    const organizationId = typeof request.body?.organizationId === "string" ? request.body.organizationId.trim() : "";
    const organization = organizationWorkspaceRecordForUser(store, identity.user.id, organizationId);
    if (!organization || organization.id !== organizationId) return forbidden(reply, "Organization membership is required");
    const previousOrganizationId = activeOrganizationIdForUser(store, identity.user.id, identity.session.activeOrganizationId);
    identity.session.activeOrganizationId = organization.id;
    identity.session.updatedAt = nowIso();
    store.state.auditLogs.push(createTimestamped("audit", { actorUserId: identity.user.id, actorType: "user" as const, action: "organization.session.switch", targetType: "organization_workspace", targetId: organization.id, after: { organizationId: organization.id } }) satisfies AuditLog);
    store.save();
    if (previousOrganizationId !== organization.id) disconnectRealtimeSession(identity.session.id);
    return { organization: publicOrganizationWorkspace(organization), session: publicSession(identity.session), organizations: organizationWorkspaceInfos(store, identity.user.id) };
