  app.post<{ Params: { campaignId: string }; Body: CampaignOwnershipTransferBody }>("/api/v1/campaigns/:campaignId/ownership-transfer", async (request, reply) => {
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const campaign = store.state.campaigns.find((item) => item.id === request.params.campaignId);
    if (!campaign) return notFound(reply, "Campaign not found");
    const activeOrganization = requireCampaignActiveOrganization(store, reply, request.headers, userId, campaign.id);
    if (activeOrganization !== true) return activeOrganization;
    if (campaign.ownerUserId !== userId) return forbidden(reply, "Only the current campaign owner can transfer ownership");

    const idempotencyKey = opaqueHeaderText(request.headers["idempotency-key"]);
    if (!idempotencyKey) return badRequest(reply, "Campaign ownership transfer requires an Idempotency-Key header");
    const expectedUpdatedAt = normalizeNonEmptyString(request.body?.expectedUpdatedAt);
    if (!expectedUpdatedAt) return badRequest(reply, "expectedUpdatedAt must be a non-empty string");
    if (!Number.isFinite(Date.parse(expectedUpdatedAt))) return badRequest(reply, "expectedUpdatedAt must be a valid date-time");
    if (expectedUpdatedAt !== campaign.updatedAt) {
      return reply.code(409).send({ error: "conflict", code: "stale_write", message: "Campaign changed after this ownership transfer was prepared. Review the latest state and retry.", resourceType: "campaign", resourceId: campaign.id, expectedUpdatedAt, currentUpdatedAt: campaign.updatedAt, current: campaign });
    }

    const targetUserId = normalizeNonEmptyString(request.body?.targetUserId);
    if (!targetUserId) return badRequest(reply, "targetUserId must be a non-empty string");
    if (targetUserId === userId) return badRequest(reply, "Campaign ownership must be transferred to a different member");
    if (!isActiveUserId(store, targetUserId)) return badRequest(reply, "The new campaign owner must be an active user");
    const ownerMembers = store.state.members.filter((member) => member.campaignId === campaign.id && member.role === "owner");
    const previousOwnerMember = ownerMembers.find((member) => member.userId === userId);
    if (!previousOwnerMember || ownerMembers.length !== 1) return conflict(reply, "Campaign owner membership is inconsistent and must be repaired before ownership can be transferred");
    const newOwnerMember = store.state.members.find((member) => member.campaignId === campaign.id && member.userId === targetUserId);
    if (!newOwnerMember) return badRequest(reply, "The new campaign owner must already be a member of this campaign");
    if (newOwnerMember.source?.type === "scim_group") return conflict(reply, "SCIM-managed campaign members cannot become campaign owners");
    const reason = request.body?.reason;
    if (reason !== undefined && typeof reason !== "string") return badRequest(reply, "reason must be a string");
    if (typeof reason === "string" && reason.length > 160) return badRequest(reply, "reason must be 160 characters or fewer");

    const previousTargetRole = newOwnerMember.role;
    const updatedAt = nextRevisionTimestamp(campaign.updatedAt);
    campaign.ownerUserId = targetUserId;
    campaign.updatedAt = updatedAt;
    previousOwnerMember.role = "gm";
    previousOwnerMember.updatedAt = updatedAt;
    newOwnerMember.role = "owner";
    newOwnerMember.updatedAt = updatedAt;
    appendServerAuditLog(store, userId, { campaignId: campaign.id, action: "campaign.owner.transfer", targetType: "campaign", targetId: campaign.id, before: { ownerUserId: userId, ownerMemberId: previousOwnerMember.id, targetMemberId: newOwnerMember.id, targetRole: previousTargetRole }, after: { ownerUserId: targetUserId, previousOwnerRole: previousOwnerMember.role, targetRole: newOwnerMember.role, reason: reason?.trim() } });
    store.save();
    broadcast(createEvent({ campaignId: campaign.id, type: "campaign.updated", actorUserId: userId, targetId: campaign.id, payload: campaign }));
    broadcast(createEvent({ campaignId: campaign.id, type: "campaign.member.updated", actorUserId: userId, targetId: previousOwnerMember.id, payload: previousOwnerMember }));
    broadcast(createEvent({ campaignId: campaign.id, type: "campaign.member.updated", actorUserId: userId, targetId: newOwnerMember.id, payload: newOwnerMember }));
    return { campaign, previousOwner: memberSessionInfo(store, previousOwnerMember), newOwner: memberSessionInfo(store, newOwnerMember) };
  });

  app.patch<{ Params: { campaignId: string; memberId: string }; Body: { role?: unknown } }>("/api/v1/campaigns/:campaignId/members/:memberId", async (request, reply) => {
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "campaign.update");
    if (allowed !== true) return allowed;
    const member = store.state.members.find((item) => item.id === request.params.memberId && item.campaignId === request.params.campaignId);
    if (!member) return notFound(reply, "Campaign member not found");
    if (member.role === "owner") return forbidden(reply, "The campaign owner role cannot be changed");
    if (member.source?.type === "scim_group") return conflict(reply, "SCIM-managed campaign members must be changed through their group mapping");
    const userId = currentUserId(store, request.headers)!;
    if (member.userId === userId) return forbidden(reply, "Campaign members cannot change their own role");
    const role = assignableInviteRole(request.body?.role);
    if (!role) return badRequest(reply, "role must be gm, assistant_gm, player, or observer");
    const before = { role: member.role };
    member.role = role;
    member.updatedAt = nowIso();
    appendServerAuditLog(store, userId, { campaignId: member.campaignId, action: "campaign.member.update", targetType: "campaign_member", targetId: member.id, before, after: { role: member.role, userId: member.userId } });
    store.save();
    broadcast(createEvent({ campaignId: member.campaignId, type: "campaign.member.updated", actorUserId: userId, targetId: member.id, payload: member }));
    return memberSessionInfo(store, member);
  });

  app.delete<{ Params: { campaignId: string; memberId: string } }>("/api/v1/campaigns/:campaignId/members/:memberId", async (request, reply) => {
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "campaign.update");
    if (allowed !== true) return allowed;
    const index = store.state.members.findIndex((item) => item.id === request.params.memberId && item.campaignId === request.params.campaignId);
    const member = store.state.members[index];
    if (!member) return notFound(reply, "Campaign member not found");
    if (member.role === "owner") return forbidden(reply, "The campaign owner cannot be removed");
    if (member.source?.type === "scim_group") return conflict(reply, "SCIM-managed campaign members must be removed through their group mapping");
    const userId = currentUserId(store, request.headers)!;
    if (member.userId === userId) return forbidden(reply, "Campaign members cannot remove their own access");
    store.state.members.splice(index, 1);
    store.state.permissionGrants = store.state.permissionGrants.filter((grant) => !(grant.campaignId === member.campaignId && grant.subjectType === "user" && grant.subjectId === member.userId));
    for (const token of store.state.tokens) {
      if (!token.ownerUserIds?.includes(member.userId)) continue;
      token.ownerUserIds = token.ownerUserIds.filter((id) => id !== member.userId);
      token.updatedAt = nowIso();
    }
    appendServerAuditLog(store, userId, { campaignId: member.campaignId, action: "campaign.member.remove", targetType: "campaign_member", targetId: member.id, before: { userId: member.userId, role: member.role }, after: { removed: true } });
    store.save();
    broadcast(createEvent({ campaignId: member.campaignId, type: "campaign.member.left", actorUserId: userId, targetId: member.id, payload: member }));
    return memberSessionInfo(store, member);
  });

