  app.post<{ Params: { campaignId: string }; Body: { name?: unknown; expectedUpdatedAt?: unknown } }>("/api/v1/campaigns/:campaignId/duplicate", async (request, reply) => {
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    if (!opaqueHeaderText(request.headers["idempotency-key"])) return badRequest(reply, "Campaign duplication requires an Idempotency-Key header");
    const allowed = requireCampaignPermissionForUser(store, reply, request.headers, userId, request.params.campaignId, "campaign.update");
    if (allowed !== true) return allowed;
    const source = store.state.campaigns.find((campaign) => campaign.id === request.params.campaignId);
    if (!source) return notFound(reply, "Campaign not found");
    const revision = requireExpectedRevision(reply, { resourceType: "campaign", resourceId: source.id, currentUpdatedAt: source.updatedAt, expectedUpdatedAt: request.body?.expectedUpdatedAt, current: source, label: "Campaign" });
    if (revision !== true) return revision;
    const requestedName = request.body?.name === undefined ? undefined : normalizeBoundedText(request.body.name, 160);
    if (request.body?.name !== undefined && !requestedName) return badRequest(reply, "Campaign copy name must be 1-160 characters");
    const workspace = organizationWorkspaceRecordForRequest(store, userId, request.headers);
    let archive: CampaignArchive;
    try {
      archive = await withArchivedAssetFiles(makeArchive(store.state, source.id), assetStorage);
    } catch (error) {
      if (error instanceof CampaignArchiveExportSizeError) return reply.code(413).send({ error: "campaign_archive_too_large", message: error.message });
      throw error;
    }
    const regenerated = archiveWithRegeneratedIds(archive, { userId, organizationId: workspace.id });
    const portable = secureArchiveIdentityForImport(store.state, regenerated, { userId, organizationId: workspace.id });
    const copiedCampaign = portable.data.campaigns[0];
    if (!copiedCampaign) return badRequest(reply, "Campaign archive did not contain a campaign record");
    copiedCampaign.name = requestedName ?? `${source.name} Copy`;
    portable.manifest.name = copiedCampaign.name;
    const references = archiveReferenceProtection(store.state, portable, { requireResolvedReferences: true, hasSystemRuntimeCapability, normalizedEncounterThreatSelections });
    if (!references.ok) return badRequest(reply, references.error);
    const abortController = new AbortController();
    Reflect.set(request, archiveImportAbortControllerSymbol, abortController);
    let assetRestore: ArchiveAssetRestoreTransaction;
    try {
      assetRestore = await restoreArchivedAssetFiles(assetStorage, portable, { signal: abortController.signal, onTransaction: (transaction) => Reflect.set(request, archiveImportAssetRestoreSymbol, transaction) });
    } catch (error) {
      if (error instanceof ArchiveAssetRestoreError) return badRequest(reply, `Campaign copy asset restore failed: ${errorMessage(error)}`);
      throw error;
    }
    Reflect.set(request, archiveImportAssetRestoreSymbol, assetRestore);
    // Build the duplicate off to the side; keep the current state object as the
    // compensation root instead of cloning the entire repository twice.
    const before = store.state;
    Reflect.set(request, archiveImportStateSnapshotSymbol, before);
    try {
      const nextState = stateForArchiveMerge(store.state, portable);
      const counts = mergeArchive(nextState, portable);
      migrateDnd5eSrdStoredArmorClassIntent(nextState, { initiatedByUserId: userId });
      nextState.auditLogs.push(createTimestamped("audit", { campaignId: copiedCampaign.id, actorUserId: userId, actorType: "user" as const, action: "campaign.duplicate", targetType: "campaign", targetId: copiedCampaign.id, after: { sourceCampaignId: source.id, assetFiles: assetRestore.restoredFiles, recordCount: Object.values(counts).reduce((total, count) => total + count, 0) } }) satisfies AuditLog);
      store.replace(nextState);
      // Idempotency onSend persists the state and replay record atomically.
      // The durable finalizer commits staged asset objects only after that save.
      return reply.code(201).send({ campaign: copiedCampaign, counts, assetFiles: assetRestore.restoredFiles });
    } catch (error) {
      return rollbackCampaignArchiveImport(store, before, assetRestore, error);
    }
  });

