    if (sizeBytes === undefined) return badRequest(reply, "Asset sizeBytes must be a non-negative finite number");
    const quotaExceeded = assetQuotaExceeded(store, request.params.campaignId, sizeBytes);
    if (quotaExceeded) return reply.code(413).send(quotaExceeded);
    const asset = createTimestamped("asset", { campaignId: request.params.campaignId, name: body.name ?? "Map Asset", url: body.url ?? "", mimeType: body.mimeType ?? "image/png", sizeBytes, checksum: body.checksum, folder: normalizeAssetFolder(body.folder), tags: normalizeAssetTags(body.tags), lifecycle: defaultAssetLifecycle() }) satisfies MapAsset;
    store.state.assets.push(asset);
    appendServerAuditLog(store, userId, { campaignId: asset.campaignId, action: "asset.create", targetType: "asset", targetId: asset.id, after: assetAuditSummary(asset) });
