  app.post<{ Params: { assetId: string }; Body: { expiresInSeconds?: number; disposition?: "inline" | "attachment" } }>("/api/v1/assets/:assetId/delivery-url", async (request, reply) => {
    const body = request.body ?? {};
    const asset = store.state.assets.find((item) => item.id === request.params.assetId);
    if (!asset) return notFound(reply, "Asset not found");
    if (!isAssetDeliverable(asset)) return assetUnavailable(reply, asset);
    const allowed = requireCampaignPermission(store, reply, request.headers, asset.campaignId, "scene.read");
    if (allowed !== true) return allowed;
    const userId = currentUserId(store, request.headers)!;
    if (!canReadAssetRecord(store, userId, asset)) return notFound(reply, "Asset not found");
    try {
      return signedAssetDelivery(asset, request.headers, body.expiresInSeconds, body.disposition);
    } catch (error) {
      appendAssetDeliveryAuditLog(store, asset, { status: "signing_failed", accessMode: "signed", reason: errorMessage(error) });
      store.save();
      return reply.code(500).send({ error: "asset_signing_unavailable", message: errorMessage(error) });
    }
  });

  app.patch<{ Params: { assetId: string }; Body: { status?: "active" | "archived" | "deleted"; expiresAt?: string | null; reason?: string; expectedUpdatedAt?: string } }>("/api/v1/assets/:assetId/lifecycle", async (request, reply) => {
    const body = request.body ?? {};
    const asset = store.state.assets.find((item) => item.id === request.params.assetId);
    if (!asset) return notFound(reply, "Asset not found");
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const allowed = requireCampaignPermissionForUser(store, reply, request.headers, userId, asset.campaignId, "scene.update");
    if (allowed !== true) return allowed;
    const status = normalizeAssetLifecycleStatus(body.status);
    if (!status) return badRequest(reply, "Asset lifecycle status must be active, archived, or deleted");
    const expiresAt = normalizeOptionalIsoDate(body.expiresAt);
    if (body.expiresAt !== undefined && body.expiresAt !== null && !expiresAt) return badRequest(reply, "expiresAt must be an ISO date");
    const before = assetAuditSummary(asset);
    asset.lifecycle = { status, expiresAt, updatedAt: nowIso(), updatedByUserId: userId, reason: body.reason?.trim().slice(0, 160) };
    asset.updatedAt = nextRevisionTimestamp(asset.updatedAt);
    appendServerAuditLog(store, userId, { campaignId: asset.campaignId, action: status === "deleted" ? "asset.delete" : "asset.lifecycle.update", targetType: "asset", targetId: asset.id, before, after: assetAuditSummary(asset) });
    store.save();
    broadcast(createEvent({ campaignId: asset.campaignId, type: status === "deleted" ? "asset.deleted" : "asset.updated", actorUserId: userId, targetId: asset.id, payload: asset }));
    return asset;
  });

  app.get<{ Params: { assetId: string }; Querystring: { userId?: string; sessionToken?: string; expiresAt?: string; signature?: string; disposition?: "inline" | "attachment"; variant?: "thumbnail" | "optimized" } }>("/api/v1/assets/:assetId/blob", async (request, reply) => {
    const asset = store.state.assets.find((item) => item.id === request.params.assetId);
    if (!asset) return notFound(reply, "Asset not found");
    const accessMode = request.query.signature ? "signed" : "session";
    if (!isAssetDeliverable(asset)) {
      appendAssetDeliveryAuditLog(store, asset, { status: "unavailable", accessMode, reason: asset.lifecycle?.status === "deleted" ? "deleted" : "expired_or_deleted", lifecycleStatus: asset.lifecycle?.status ?? "active" });
      return assetUnavailable(reply, asset);
    }
    const signedAccess = isValidAssetSignature(asset.id, request.query.expiresAt, request.query.signature, request.query.disposition);
    if (!signedAccess) {
      const userId = userIdFromRequest(store, request.url, request.headers);
      if (!userId) {
        appendAssetDeliveryAuditLog(store, asset, { status: "denied", accessMode, reason: "missing_session" });
        return unauthorized(reply, "Missing asset session");
      }
      const allowed = requireCampaignPermissionForUser(store, reply, headersWithRequestSessionToken(request.url, request.headers), userId, asset.campaignId, "scene.read");
      if (allowed !== true) {
        appendAssetDeliveryAuditLog(store, asset, { status: "denied", accessMode, reason: "missing_permission_or_active_organization" });
        return allowed;
      }
      if (!canReadAssetRecord(store, userId, asset)) {
        appendAssetDeliveryAuditLog(store, asset, { status: "denied", accessMode, reason: "asset_not_visible" });
        return notFound(reply, "Asset not found");
      }
    }
    const cacheControl = signedAccess ? signedAssetCacheControl(request.query.expiresAt) : "private, max-age=60";
    const contentDisposition = request.query.disposition === "attachment" ? `attachment; filename="${safeDownloadFileName(asset.name)}"` : undefined;
    const requestedRendition = request.query.variant ? asset.renditions?.find((rendition) => rendition.kind === request.query.variant) : undefined;
    let deliveryAsset = requestedRendition ? assetRecordForRendition(asset, requestedRendition) : asset;
    if (request.query.variant && !requestedRendition) reply.header("x-otte-rendition-fallback", "original");
    if (!deliveryAsset.storage && requestedRendition) {
      deliveryAsset = asset;
      reply.header("x-otte-rendition-fallback", "original");
    }
    if (!deliveryAsset.storage) {
      appendAssetDeliveryAuditLog(store, asset, { status: "missing_bytes", accessMode: signedAccess ? "signed" : "session", reason: "asset_storage_reference_missing" });
      return notFound(reply, "Asset file not found");
    }
    let deliveryStorage = sourceStorageForAsset(deliveryAsset, assetStorage, uploadDir);
    const stream = await deliveryStorage.stream?.(deliveryAsset);
    if (contentDisposition) reply.header("content-disposition", contentDisposition);
    if (stream) {
      appendAssetDeliveryAuditLog(store, asset, { status: "served", accessMode: signedAccess ? "signed" : "session", bytes: deliveryAsset.sizeBytes, cacheControl, variant: requestedRendition?.kind });
      return reply.header("content-type", deliveryAsset.mimeType).header("cache-control", cacheControl).send(stream);
    }
    let body = await deliveryStorage.read(deliveryAsset);
    if (!body && requestedRendition && deliveryAsset !== asset && asset.storage) {
      deliveryAsset = asset;
      deliveryStorage = sourceStorageForAsset(asset, assetStorage, uploadDir);
      body = await deliveryStorage.read(asset);
      reply.header("x-otte-rendition-fallback", "original");
    }
    if (!body) {
      appendAssetDeliveryAuditLog(store, asset, { status: "missing_bytes", accessMode: signedAccess ? "signed" : "session", reason: "asset_file_not_found" });
      return notFound(reply, "Asset file not found");
    }
    appendAssetDeliveryAuditLog(store, asset, { status: "served", accessMode: signedAccess ? "signed" : "session", bytes: body.length, cacheControl, variant: requestedRendition?.kind });
    return reply.header("content-type", deliveryAsset.mimeType).header("cache-control", cacheControl).send(body);
  });

