  app.delete<{ Params: { sceneId: string } }>("/api/v1/scenes/:sceneId", async (request, reply) => {
    const campaignId = campaignIdForScene(store, request.params.sceneId);
    if (!campaignId) return notFound(reply, "Scene not found");
    const allowed = requireCampaignPermission(store, reply, request.headers, campaignId, "scene.delete");
    if (allowed !== true) return allowed;
    const userId = currentUserId(store, request.headers)!;
    const index = store.state.scenes.findIndex((item) => item.id === request.params.sceneId);
    if (index < 0) return notFound(reply, "Scene not found");
    const deleted = store.state.scenes[index]!;
    const auditSummary = sceneDeletionAuditSummary(store, deleted);
    const replacementScene = deleted.active ? store.state.scenes.filter((scene) => scene.campaignId === deleted.campaignId && scene.id !== deleted.id).sort((left, right) => left.sortOrder - right.sortOrder || left.createdAt.localeCompare(right.createdAt))[0] : undefined;
    if (replacementScene) activateSceneForCampaignSession(store, replacementScene, userId, nowIso());
    removeSceneRecords(store, deleted.id);
    appendServerAuditLog(store, userId, { campaignId: deleted.campaignId, action: "scene.delete", targetType: "scene", targetId: deleted.id, before: auditSummary, after: replacementScene ? { deleted: true, activatedSceneId: replacementScene.id } : { deleted: true } });
    store.save();
    broadcast(createEvent({ campaignId: deleted.campaignId, type: "scene.deleted", targetId: deleted.id, payload: deleted }));
    if (replacementScene) {
      broadcast(createEvent({ campaignId: replacementScene.campaignId, type: "scene.activated", actorUserId: userId, targetId: replacementScene.id, payload: replacementScene }));
    }
    return deleted;
  });

