  app.patch<{ Params: { actorId: string }; Body: ActorPatchBody }>("/api/v1/actors/:actorId", async (request, reply) => {
    const actor = store.state.actors.find((item) => item.id === request.params.actorId);
    if (!actor) return notFound(reply, "Actor not found");
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const activeOrganization = requireCampaignActiveOrganization(store, reply, request.headers, userId, actor.campaignId);
    if (activeOrganization !== true) return activeOrganization;
    const canUpdate = canCampaign(store, userId, actor.campaignId, "actor.update");
    const canUpdateOwned = actor.ownerUserId === userId && canCampaign(store, userId, actor.campaignId, "actor.updateOwned");
    if (!canUpdate && !canUpdateOwned) return forbidden(reply, "Missing permission: actor.update");
    const actorRevision = requireExpectedRevision(reply, { resourceType: "actor", resourceId: actor.id, currentUpdatedAt: actor.updatedAt, expectedUpdatedAt: request.body.expectedUpdatedAt, current: actorPayloadForUser(store, userId, actor), label: "Actor" });
    if (actorRevision !== true) return actorRevision;
    const manualOverrideReason = rawPatchManualOverrideReason(request.body.manualOverrideReason);
    if (!manualOverrideReason.ok) return badRequest(reply, manualOverrideReason.error);
    const updatesAccessControl = request.body.ownerUserId !== undefined || request.body.permissions !== undefined;
    if (updatesAccessControl && !canUpdate) return forbidden(reply, "Only a campaign actor manager can change actor access control");
    if (updatesAccessControl && !canReadActorPrivateData(store, userId, actor.campaignId, actor)) {
      return forbidden(reply, "Missing permission: actor.readPrivate");
    }
    const requestedWorldId = request.body.worldId === null ? undefined : request.body.worldId;
    if (requestedWorldId && !store.state.worlds.some((world) => world.id === requestedWorldId && world.campaignId === actor.campaignId)) {
      return badRequest(reply, "Actor worldId must reference a world in the same campaign");
    }
    if (request.body.data !== undefined && !isRecord(request.body.data)) return badRequest(reply, "Actor data must be an object");
    const changedDataRoots = request.body.data === undefined ? [] : changedRecordRoots(actor.data, request.body.data);
    const armorClassRoots = changedDataRoots.filter((root) => root === "armorClass" || root === "armorClassIntent" || root === "armorClassReview");
    const resultingActorType = request.body.type ?? actor.type;
    if ((actor.systemId === DND_5E_SRD_SYSTEM_ID || request.body.systemId === DND_5E_SRD_SYSTEM_ID) && resultingActorType !== "monster" && armorClassRoots.length > 0) {
      return reply.code(409).send({ error: "conflict", code: "calculation_override_route_required", message: "Character Armor Class is derived. Create or clear a reasoned armor-class calculation override instead of patching stored Armor Class data.", resourceType: "actor", resourceId: actor.id, managedRoots: armorClassRoots });
    }
    if (changedDataRoots.includes(DND_CHARACTER_REVIEW_DATA_KEY)) {
      return reply.code(409).send({ error: "conflict", code: "character_review_route_required", message: "D&D character review state can only be changed through the character review routes", resourceType: "actor", resourceId: actor.id, managedRoots: [DND_CHARACTER_REVIEW_DATA_KEY] });
    }
    const combatVitalsRoots = (actor.systemId === DND_5E_SRD_SYSTEM_ID || request.body.systemId === DND_5E_SRD_SYSTEM_ID) && request.body.data !== undefined
      ? dndRawActorCombatVitalsRoots(actor.data, request.body.data)
      : [];
    if (combatVitalsRoots.length > 0) {
      return reply.code(409).send({
        error: "conflict",
        code: "combat_vitals_route_required",
        message: "D&D Hit Points, death saves, and lifecycle state can only be changed through an authoritative rules mutation route",
        resourceType: "actor",
        resourceId: actor.id,
        managedRoots: combatVitalsRoots,
      });
    }
    const dndManagedRoots = actor.systemId === DND_5E_SRD_SYSTEM_ID || request.body.systemId === DND_5E_SRD_SYSTEM_ID ? [...(request.body.systemId !== undefined && request.body.systemId !== actor.systemId ? ["systemId"] : []), ...(request.body.type !== undefined && request.body.type !== actor.type ? ["type"] : []), ...changedDataRoots.filter((root) => DND_RAW_ACTOR_MANAGED_DATA_ROOTS.has(root))] : [];
    const uniqueDndManagedRoots = [...new Set(dndManagedRoots)].sort();
    if (uniqueDndManagedRoots.length > 0) {
      if (!manualOverrideReason.value) {
        return reply.code(409).send({ error: "conflict", code: "rules_managed_patch_requires_review", message: `Rules-managed D&D actor fields require a reviewed mutation route or a campaign-manager manual override: ${uniqueDndManagedRoots.join(", ")}`, resourceType: "actor", resourceId: actor.id, managedRoots: uniqueDndManagedRoots });
      }
      if (!canUpdate) return forbidden(reply, "Only a campaign actor manager can manually override rules-managed D&D actor fields");
    }
    const patch = actorPatchFromBody(request.body);
    if (request.body.ownerUserId !== undefined) {
      const ownerUserId = campaignActorOwnerUserId(store, actor.campaignId, request.body.ownerUserId);
      if (!ownerUserId.ok) return badRequest(reply, ownerUserId.error);
      patch.ownerUserId = ownerUserId.value;
    }
    const candidateActor = { ...actor, ...patch } as Actor;
    if ((request.body.data !== undefined || request.body.systemId === DND_5E_SRD_SYSTEM_ID) && candidateActor.systemId === DND_5E_SRD_SYSTEM_ID) {
      const validationError = dndManagedDataBoundaryError(parseDnd5eSrdActorManagedData(candidateActor), Boolean(manualOverrideReason.value));
      if (validationError) return badRequest(reply, validationError);
    }
    const previousUpdatedAt = actor.updatedAt;
    const updatedAt = nextRevisionTimestamp(actor.updatedAt);
    Object.assign(actor, patch, { updatedAt });
    if (uniqueDndManagedRoots.length > 0) {
      appendServerAuditLog(store, userId, { campaignId: actor.campaignId, action: "actor.dndManualOverride", targetType: "actor", targetId: actor.id, before: { updatedAt: previousUpdatedAt, managedRoots: uniqueDndManagedRoots }, after: { updatedAt, managedRoots: uniqueDndManagedRoots, reason: manualOverrideReason.value } });
    }
    store.save();
    broadcast(createEvent({ campaignId: actor.campaignId, type: "actor.updated", targetId: actor.id, payload: actor }));
    return actorPayloadForUser(store, userId, actor);
  });

  app.post<{ Params: { actorId: string }; Body: Dnd5eSrdConcentrationEndBody }>("/api/v1/actors/:actorId/concentration/end", async (request, reply) => {
    const actor = store.state.actors.find((item) => item.id === request.params.actorId);
    if (!actor) return notFound(reply, "Actor not found");
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const activeOrganization = requireCampaignActiveOrganization(store, reply, request.headers, userId, actor.campaignId);
    if (activeOrganization !== true) return activeOrganization;
    if (!canUpdateActorForUser(store, userId, actor)) return forbidden(reply, "Missing permission: actor.update");
    if (!canReadActorPrivateData(store, userId, actor.campaignId, actor)) return forbidden(reply, "Missing permission: actor.readPrivate");
    if (actor.systemId !== DND_5E_SRD_SYSTEM_ID) return badRequest(reply, "Concentration lifecycle is only available for D&D 5e SRD actors");
    const body = request.body ?? {};
    if (body.prepare !== undefined && typeof body.prepare !== "boolean") return badRequest(reply, "prepare must be true or false");
    if (body.reason !== undefined && (typeof body.reason !== "string" || body.reason.trim().length > 500)) return badRequest(reply, "reason must be a string of 500 characters or fewer");
    const idempotencyKey = opaqueHeaderText(request.headers["idempotency-key"]);
    if (!idempotencyKey) return badRequest(reply, `${body.prepare === true ? "Preparing" : "Ending"} concentration requires an Idempotency-Key header`);

    const linkedControlledCreatures = dndControlledCreatureEntries(store.state, actor.campaignId).filter(({ record }) => record.status === "active" && record.concentration?.sourceActorId === actor.id);
    if (linkedControlledCreatures.length > 0) {
      return conflict(reply, "End this concentration through the controlled-creature concentration workflow so every linked actor and token is cleaned up atomically");
    }

    const campaignActors = store.state.actors.filter((candidate) => candidate.campaignId === actor.campaignId && candidate.systemId === DND_5E_SRD_SYSTEM_ID);
    const lifecycle = endDnd5eSrdConcentration(campaignActors, actor.id);
    if (!lifecycle.ended) return conflict(reply, "Actor is not concentrating");

    const affectedActors = lifecycle.actorUpdates.flatMap((update) => {
      const affected = store.state.actors.find((candidate) => candidate.id === update.actorId && candidate.campaignId === actor.campaignId);
      return affected ? [affected] : [];
    });
    if (affectedActors.length !== lifecycle.actorUpdates.length) return conflict(reply, "A concentration-linked actor no longer exists");
    for (const affected of affectedActors) {
      if (!canUpdateActorForUser(store, userId, affected)) return forbidden(reply, `Missing actor.update permission for ${affected.name}`);
      if (!canReadActorPrivateData(store, userId, affected.campaignId, affected)) return forbidden(reply, `Missing actor.readPrivate permission for ${affected.name}`);
    }
    const affectedCombats = store.state.combats
      .filter((combat) => combat.campaignId === actor.campaignId && combat.active)
      .flatMap((combat) => {
        const after = structuredClone(combat);
        return syncDnd5eSrdEffectLifecycleToCombat(after, lifecycle) ? [{ combat, after }] : [];
      });
    if (affectedCombats.length > 1) return conflict(reply, "Concentration cleanup found multiple active combats; end the extra combat before reviewing this change");
    if (affectedCombats.length > 0 && !canCampaign(store, userId, actor.campaignId, "combat.manage")) return forbidden(reply, "Missing permission: combat.manage");

    const reason = body.reason?.trim() || "voluntary";
    const actorUpdatedAt = Object.fromEntries(affectedActors.map((affected) => [affected.id, affected.updatedAt]));
    const combatUpdatedAt = Object.fromEntries(affectedCombats.map(({ combat }) => [combat.id, combat.updatedAt]));
    const resolutionHash = hashStableJson({ actorUpdates: lifecycle.actorUpdates, combats: affectedCombats.map(({ after }) => after) });
    if (body.prepare === true) {
      return { status: "ready", actor: actorPayloadForUser(store, userId, actor), concentrationEnded: true, review: { reason, actorUpdates: lifecycle.actorUpdates, combatUpdates: affectedCombats.map(({ combat, after }) => ({ combatId: combat.id, before: combatPayloadForUser(store, userId, combat), after: combatPayloadForUser(store, userId, after) })), changes: lifecycle.changes }, preparation: { preparedPreviewKey: idempotencyKey, actorId: actor.id, request: { reason }, revisions: { actorUpdatedAt, combatUpdatedAt }, resolutionHash } };
    }

    const preparedPreviewKey = normalizeNonEmptyString(body.preparedPreviewKey);
    if (!preparedPreviewKey) return badRequest(reply, "Concentration cleanup must commit a preparedPreviewKey from a reviewed preview");
    if (!isStringRecord(body.expectedActorUpdatedAt) || !isStringRecord(body.expectedCombatUpdatedAt)) return badRequest(reply, "Exact actor and combat revisions are required");
    const previewPath = `/api/v1/actors/${actor.id}/concentration/end`;
    const record = store.state.idempotencyRecords.find((candidate) => candidate.key === preparedPreviewKey && candidate.method === "POST" && candidate.userId === userId && candidate.path === previewPath);
    const currentAuthorizationHash = idempotencyAuthorizationHash(store, request.headers, userId);
    if (!record || !currentAuthorizationHash || record.authorizationHash !== currentAuthorizationHash) return conflict(reply, "Prepared concentration cleanup is unavailable or expired; review it again");
    let storedPreview: unknown;
    try {
      storedPreview = JSON.parse(record.responseBody);
    } catch {
      return conflict(reply, "Prepared concentration cleanup is invalid; review it again");
    }
    if (!isRecord(storedPreview) || storedPreview.status !== "ready" || !isRecord(storedPreview.preparation)) return conflict(reply, "Prepared concentration cleanup is not ready to apply");
    const preparation = storedPreview.preparation;
    if (preparation.preparedPreviewKey !== preparedPreviewKey || preparation.actorId !== actor.id || !isRecord(preparation.request) || !isRecord(preparation.revisions) || !isStringRecord(preparation.revisions.actorUpdatedAt) || !isStringRecord(preparation.revisions.combatUpdatedAt) || typeof preparation.resolutionHash !== "string") return conflict(reply, "Prepared concentration cleanup is invalid; review it again");
    if (hashStableJson(body.expectedActorUpdatedAt) !== hashStableJson(preparation.revisions.actorUpdatedAt) || hashStableJson(body.expectedCombatUpdatedAt) !== hashStableJson(preparation.revisions.combatUpdatedAt)) return conflict(reply, "Concentration cleanup revisions do not match the reviewed preview");
    if (reason !== normalizeNonEmptyString(preparation.request.reason)) return conflict(reply, "Concentration cleanup reason changed after review; review it again");
    if (hashStableJson(actorUpdatedAt) !== hashStableJson(preparation.revisions.actorUpdatedAt) || hashStableJson(combatUpdatedAt) !== hashStableJson(preparation.revisions.combatUpdatedAt)) {
      return conflict(reply, "Concentration state changed after review; review it again");
    }
    if (resolutionHash !== preparation.resolutionHash) return conflict(reply, "Concentration consequences changed after review; review them again");

    const actorRoots = affectedActors.map((affected) => ({ actorId: affected.id, before: { data: structuredClone(affected.data), revision: affected.updatedAt }, afterRevision: "" }));
    const combatRoot = affectedCombats[0] ? { combatId: affectedCombats[0].combat.id, before: structuredClone(affectedCombats[0].combat), afterRevision: "" } : undefined;
    const updatedActors: Actor[] = [];
    for (const update of lifecycle.actorUpdates) {
      const updatedActor = store.state.actors.find((candidate) => candidate.id === update.actorId && candidate.campaignId === actor.campaignId)!;
      updatedActor.data = update.after;
      updatedActor.updatedAt = nextRevisionTimestamp(updatedActor.updatedAt);
      updatedActors.push(updatedActor);
    }
    const updatedCombats = affectedCombats.map(({ combat, after }) => {
      const priorRevision = combat.updatedAt;
      Object.assign(combat, after);
      combat.updatedAt = nextRevisionTimestamp(priorRevision);
      return combat;
    });
    for (const root of actorRoots) root.afterRevision = store.state.actors.find((candidate) => candidate.id === root.actorId)!.updatedAt;
    if (combatRoot) combatRoot.afterRevision = affectedCombats[0]!.combat.updatedAt;
    const mutationCreatedAt = nowIso();
    const mutation: DndRulesMutation = { id: createId("drmut"), campaignId: actor.campaignId, kind: "concentration", preparedPreviewKey, committedByUserId: userId, status: "applied", roots: { actors: actorRoots, items: [], ...(combatRoot ? { combat: combatRoot } : {}) }, createdAt: mutationCreatedAt, updatedAt: mutationCreatedAt };
    store.state.dndRulesMutations = [...store.state.dndRulesMutations, mutation].sort(sortTimestampsDesc).slice(0, 1000);
    appendServerAuditLog(store, userId, { campaignId: actor.campaignId, action: "actor.concentrationEnded", targetType: "actor", targetId: actor.id, before: { actorUpdatedAt, combatUpdatedAt }, after: { reason, updatedActorCount: lifecycle.actorUpdates.length, removedEffectCount: lifecycle.changes.reduce((total, change) => total + change.removedEffectIds.length, 0), removedConditionCount: lifecycle.changes.reduce((total, change) => total + change.removedConditionIds.length, 0), preparedPreviewKey, rulesMutationId: mutation.id } });
    appendServerAuditLog(store, userId, { campaignId: actor.campaignId, action: "dnd.rulesMutationCommitted", targetType: "actor", targetId: actor.id, after: { rulesMutationId: mutation.id, preparedPreviewKey, kind: mutation.kind } });
    store.save();
    deferRequestSideEffectUntilDurableSave(request, () => {
      for (const updatedActor of updatedActors) broadcastActorUpdated(broadcast, updatedActor);
      for (const combat of updatedCombats) {
        broadcast(createEvent({ campaignId: combat.campaignId, type: "combat.turnChanged", actorUserId: userId, targetId: combat.id, payload: combat }));
      }
    });
    return { actor: actorPayloadForUser(store, userId, actor), concentrationEnded: true, updatedActors: updatedActors.map((updatedActor) => actorPayloadForUser(store, userId, updatedActor)), updatedCombats: updatedCombats.map((combat) => combatPayloadForUser(store, userId, combat)), rulesMutationId: mutation.id, undo: dndRulesMutationUndoDescriptor(mutation) };
  });

  app.delete<{ Params: { actorId: string } }>("/api/v1/actors/:actorId", async (request, reply) => {
    const index = store.state.actors.findIndex((item) => item.id === request.params.actorId);
    const actor = store.state.actors[index];
    if (!actor) return notFound(reply, "Actor not found");
    const allowed = requireCampaignPermission(store, reply, request.headers, actor.campaignId, "actor.delete");
    if (allowed !== true) return allowed;
    const userId = currentUserId(store, request.headers)!;
    const controlledCreatureDependency = dndControlledCreatureEntries(store.state, actor.campaignId).find(({ actor: dependentActor, record }) => dependentActor.id !== actor.id && record.status === "active" && (
      record.source.actorId === actor.id
      || record.controllerActorId === actor.id
      || record.linkedActorId === actor.id
      || record.concentration?.sourceActorId === actor.id
      || (record.initiative.mode === "shared" && record.initiative.sourceActorId === actor.id)
    ));
    if (controlledCreatureDependency) {
      return conflict(reply, `Actor is required by active controlled creature ${controlledCreatureDependency.actor.name}; end that lifecycle before deleting this actor`);
    }
    const effectDependency = store.state.actors.find((candidate) => candidate.id !== actor.id && candidate.campaignId === actor.campaignId && activeDndLifecycleReferencesActor(candidate, actor.id));
    if (effectDependency) {
      return conflict(reply, `Actor is required by an active effect or concentration on ${effectDependency.name}; end that lifecycle before deleting this actor`);
    }
    const changedAt = nowIso();
    store.state.actors.splice(index, 1);
    let tokenCount = 0;
    let itemCount = 0;
    let combatantCount = 0;
    let combatActionCount = 0;
    let releasedLootClaimCount = 0;
    const detachedItemIds = new Set<string>();
    const changedCombatIds = new Set<string>();
    for (const token of store.state.tokens) {
      if (token.actorId !== actor.id) continue;
      token.actorId = undefined;
      token.updatedAt = changedAt;
      tokenCount += 1;
    }
    for (const item of store.state.items) {
      let itemChanged = false;
      if (item.actorId === actor.id) {
        item.actorId = undefined;
        detachedItemIds.add(item.id);
        itemCount += 1;
        itemChanged = true;
      }
      const loot = dnd5eLootData(item);
      if (loot?.status === "claimed" && loot.claimedForActorId === actor.id) {
        item.data = { ...item.data, [DND5E_LOOT_DATA_KEY]: { version: 1, combatId: loot.combatId, rewardId: loot.rewardId, status: "available" } satisfies Dnd5eLootData };
        releasedLootClaimCount += 1;
        itemChanged = true;
      }
      if (itemChanged) item.updatedAt = changedAt;
    }
    const removedCharacterTransfers = store.state.characterTransfers.filter((transfer) => transfer.actorId === actor.id).length;
    store.state.characterTransfers = store.state.characterTransfers.filter((transfer) => transfer.actorId !== actor.id);
    const removedCalculationOverrides = store.state.calculationOverrides.filter((override) => override.actorId === actor.id).length;
    store.state.calculationOverrides = store.state.calculationOverrides.filter((override) => override.actorId !== actor.id);
    const removedPendingAdvancements = store.state.pendingAdvancements.filter((advancement) => advancement.actorId === actor.id).length;
    store.state.pendingAdvancements = store.state.pendingAdvancements.filter((advancement) => advancement.actorId !== actor.id);
    for (const combat of store.state.combats) {
      let combatChanged = false;
      for (const combatant of combat.combatants) {
        if (combatant.actorId !== actor.id) continue;
        combatant.actorId = undefined;
        combatantCount += 1;
        combatChanged = true;
      }
      if (combat.actions) {
        const retainedActions = combat.actions.filter((action) => !combatActionReferencesActor(action, actor.id));
        const removedActions = combat.actions.length - retainedActions.length;
        if (removedActions > 0) {
          combat.actions = retainedActions;
          combatActionCount += removedActions;
          combatChanged = true;
        }
      }
      if (combatChanged) {
        combat.updatedAt = changedAt;
        changedCombatIds.add(combat.id);
      }
    }
    const removedDndRulesMutations = store.state.dndRulesMutations.filter((mutation) => mutation.status === "applied" && (
      mutation.roots.actors.some((root) => root.actorId === actor.id)
      || mutation.roots.items.some((root) => detachedItemIds.has(root.itemId))
      || Boolean(mutation.roots.combat && changedCombatIds.has(mutation.roots.combat.combatId))
    )).length;
    store.state.dndRulesMutations = store.state.dndRulesMutations.filter((mutation) => mutation.status !== "applied" || (
      !mutation.roots.actors.some((root) => root.actorId === actor.id)
      && !mutation.roots.items.some((root) => detachedItemIds.has(root.itemId))
      && !(mutation.roots.combat && changedCombatIds.has(mutation.roots.combat.combatId))
    ));
    const updatedJournals = store.state.journals.filter((journal) => {
      if (journal.campaignId !== actor.campaignId) return false;
      const visibleToActorIds = journal.visibleToActorIds.filter((id) => id !== actor.id);
      const links = (journal.links ?? []).filter((link) => link.targetType !== "actor" || link.targetId !== actor.id);
      if (visibleToActorIds.length === journal.visibleToActorIds.length && links.length === (journal.links ?? []).length) return false;
      journal.visibleToActorIds = visibleToActorIds;
      journal.links = links;
      journal.updatedBy = userId;
      journal.updatedAt = changedAt;
      return true;
    });
    const updatedHandouts = store.state.handouts.filter((handout) => {
      if (handout.campaignId !== actor.campaignId) return false;
      const visibleToActorIds = (handout.visibleToActorIds ?? []).filter((id) => id !== actor.id);
      if (visibleToActorIds.length === (handout.visibleToActorIds ?? []).length) return false;
      handout.visibleToActorIds = visibleToActorIds;
      handout.updatedBy = userId;
      handout.updatedAt = changedAt;
      return true;
    });
    const updatedEncounters = store.state.encounters.filter((encounter) => encounter.campaignId === actor.campaignId && encounter.partyActorIds?.includes(actor.id));
    for (const encounter of updatedEncounters) {
      encounter.partyActorIds = encounter.partyActorIds?.filter((id) => id !== actor.id);
      encounter.updatedAt = changedAt;
    }
    appendServerAuditLog(store, userId, { campaignId: actor.campaignId, action: "actor.delete", targetType: "actor", targetId: actor.id, before: actor, after: { deleted: true, detachedTokens: tokenCount, detachedItems: itemCount, detachedCombatants: combatantCount, removedCombatActions: combatActionCount, releasedLootClaims: releasedLootClaimCount, removedCharacterTransfers, removedCalculationOverrides, removedPendingAdvancements, removedDndRulesMutations, updatedJournals: updatedJournals.length, updatedHandouts: updatedHandouts.length, updatedEncounters: updatedEncounters.length } });
    store.save();
    broadcast(createEvent({ campaignId: actor.campaignId, type: "actor.deleted", actorUserId: userId, targetId: actor.id, payload: actor }));
    for (const encounter of updatedEncounters) {
      broadcast(createEvent({ campaignId: encounter.campaignId, type: "encounter.updated", actorUserId: userId, targetId: encounter.id, payload: encounter }));
    }
    for (const journal of updatedJournals) {
      broadcast(createEvent({ campaignId: journal.campaignId, type: "journal.updated", actorUserId: userId, targetId: journal.id, payload: journal }));
    }
    for (const handout of updatedHandouts) {
      broadcast(createEvent({ campaignId: handout.campaignId, type: "handout.updated", actorUserId: userId, targetId: handout.id, payload: handout }));
    }
    return actor;
  });

  app.get<{ Params: { campaignId: string } }>("/api/v1/campaigns/:campaignId/items", async (request, reply) => {
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "actor.read");
    if (allowed !== true) return allowed;
    const userId = currentUserId(store, request.headers)!;
    return visibleItemsForUser(store, userId, request.params.campaignId);
  });

  app.post<{ Params: { campaignId: string }; Body: Record<string, unknown> }>("/api/v1/campaigns/:campaignId/items", async (request, reply) => {
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "actor.update");
    if (allowed !== true) return allowed;
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const actorId = request.body.actorId === undefined || request.body.actorId === null ? undefined : String(request.body.actorId);
    if (actorId !== undefined && !store.state.actors.some((actor) => actor.id === actorId && actor.campaignId === request.params.campaignId)) {
      return badRequest(reply, "Item actorId must reference an actor in the same campaign");
    }
    const worldId = request.body.worldId === undefined || request.body.worldId === null ? undefined : String(request.body.worldId);
    if (worldId && !store.state.worlds.some((world) => world.id === worldId && world.campaignId === request.params.campaignId)) {
      return badRequest(reply, "Item worldId must reference a world in the same campaign");
    }
    if (request.body.data !== undefined && !isRecord(request.body.data)) return badRequest(reply, "Item data must be an object");
    const item = createTimestamped("itm", { campaignId: request.params.campaignId, worldId, systemId: String(request.body.systemId ?? DEFAULT_SYSTEM_ID), actorId, type: String(request.body.type ?? "gear"), name: String(request.body.name ?? "New Item"), data: request.body.data ?? {} }) satisfies Item;
    if (item.systemId === DND_5E_SRD_SYSTEM_ID) {
      const validationError = dndManagedDataBoundaryError(parseDnd5eSrdItemManagedData(item));
      if (validationError) return badRequest(reply, validationError);
    }
    store.state.items.push(item);
    const campaign = advanceCampaignAggregateRevision(store, item.campaignId);
    store.save();
    broadcast(createEvent({ campaignId: item.campaignId, type: "item.created", actorUserId: userId, targetId: item.id, payload: item }));
    if (campaign) broadcast(createEvent({ campaignId: campaign.id, type: "campaign.updated", actorUserId: userId, targetId: campaign.id, payload: campaign }));
    return itemPayloadForUser(store, userId, item);
  });

  app.get<{ Params: { itemId: string } }>("/api/v1/items/:itemId", async (request, reply) => {
    const item = store.state.items.find((candidate) => candidate.id === request.params.itemId);
    if (!item) return notFound(reply, "Item not found");
    const allowed = requireCampaignPermission(store, reply, request.headers, item.campaignId, "actor.read");
    if (allowed !== true) return allowed;
    const userId = currentUserId(store, request.headers)!;
    if (!visibleItemsForUser(store, userId, item.campaignId).some((candidate) => candidate.id === item.id)) return notFound(reply, "Item not found");
    return itemPayloadForUser(store, userId, item);
  });

  app.patch<{ Params: { itemId: string }; Body: ItemPatchBody }>("/api/v1/items/:itemId", async (request, reply) => {
    const item = store.state.items.find((candidate) => candidate.id === request.params.itemId);
    if (!item) return notFound(reply, "Item not found");
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const activeOrganization = requireCampaignActiveOrganization(store, reply, request.headers, userId, item.campaignId);
    if (activeOrganization !== true) return activeOrganization;
    const actor = item.actorId ? store.state.actors.find((candidate) => candidate.id === item.actorId) : undefined;
    const nextActorId = request.body.actorId === null ? undefined : request.body.actorId !== undefined ? String(request.body.actorId) : item.actorId;
    const nextActor = nextActorId ? store.state.actors.find((candidate) => candidate.id === nextActorId && candidate.campaignId === item.campaignId) : undefined;
    if (nextActorId && !nextActor) return badRequest(reply, "Item actorId must reference an actor in the same campaign");
    const nextWorldId = request.body.worldId === null ? undefined : request.body.worldId !== undefined ? String(request.body.worldId) : item.worldId;
    if (nextWorldId && !store.state.worlds.some((world) => world.id === nextWorldId && world.campaignId === item.campaignId)) {
      return badRequest(reply, "Item worldId must reference a world in the same campaign");
    }
    const canUpdateCampaign = canCampaign(store, userId, item.campaignId, "actor.update");
    const canUpdateOwned = actor?.ownerUserId === userId && canCampaign(store, userId, item.campaignId, "actor.updateOwned");
    const canUpdateNextOwned = nextActor?.ownerUserId === userId && canCampaign(store, userId, item.campaignId, "actor.updateOwned");
    if (!canUpdateCampaign && !canUpdateOwned && !canUpdateNextOwned) return forbidden(reply, "Missing permission: actor.update");
    const itemRevision = requireExpectedRevision(reply, { resourceType: "item", resourceId: item.id, currentUpdatedAt: item.updatedAt, expectedUpdatedAt: request.body.expectedUpdatedAt, current: itemPayloadForUser(store, userId, item), label: "Item" });
    if (itemRevision !== true) return itemRevision;
    const manualOverrideReason = rawPatchManualOverrideReason(request.body.manualOverrideReason);
    if (!manualOverrideReason.ok) return badRequest(reply, manualOverrideReason.error);
    const reassignsItem = request.body.actorId !== undefined && nextActorId !== item.actorId;
    if (reassignsItem && !canReadItemPrivateData(store, userId, item.campaignId, item)) {
      return forbidden(reply, "Missing permission: actor.readPrivate");
    }
    if (request.body.data !== undefined && !isRecord(request.body.data)) return badRequest(reply, "Item data must be an object");
    const nextItemType = request.body.type ?? item.type;
    const nextItemData = request.body.data ?? item.data;
    const changedDataRoots = request.body.data === undefined ? [] : changedRecordRoots(item.data, request.body.data);
    const dndManagedRoots = item.systemId === DND_5E_SRD_SYSTEM_ID ? [...(reassignsItem ? ["actorId"] : []), ...(request.body.type !== undefined && request.body.type !== item.type ? ["type"] : []), ...changedDataRoots.filter((root) => DND_RAW_ITEM_MANAGED_DATA_ROOTS.has(root))] : [];
    const uniqueDndManagedRoots = [...new Set(dndManagedRoots)].sort();
    if (uniqueDndManagedRoots.length > 0) {
      if (!manualOverrideReason.value) {
        return reply.code(409).send({ error: "conflict", code: "rules_managed_patch_requires_review", message: `Rules-managed D&D item fields require a reviewed mutation route or a campaign-manager manual override: ${uniqueDndManagedRoots.join(", ")}`, resourceType: "item", resourceId: item.id, managedRoots: uniqueDndManagedRoots });
      }
      if (!canUpdateCampaign) return forbidden(reply, "Only a campaign actor manager can manually override rules-managed D&D item fields");
    }
    if ((request.body.data !== undefined || request.body.type !== undefined) && item.systemId === DND_5E_SRD_SYSTEM_ID) {
      const candidateItem = { ...item, actorId: nextActorId, worldId: nextWorldId, type: nextItemType, data: nextItemData };
      const validationError = dndManagedDataBoundaryError(parseDnd5eSrdItemManagedData(candidateItem), Boolean(manualOverrideReason.value));
      if (validationError) return badRequest(reply, validationError);
    }
    if (!canUpdateCampaign && item.systemId === DND_5E_SRD_SYSTEM_ID && isRecord(nextItemData) && (["costGp", "compendiumId", "compendiumEntryId", "merchantId", "merchantCatalogEntryId", "purchasedForGp"] as const).some((key) => !Object.is(nextItemData[key], item.data[key]))) {
      return badRequest(reply, "D&D commerce valuation and provenance fields can only be changed by a campaign manager");
    }
    if (item.systemId === DND_5E_SRD_SYSTEM_ID && nextItemType === "spell" && isRecord(nextItemData) && nextItemData.alwaysPrepared === true && nextItemData.prepared === false) {
      return badRequest(reply, "An always-prepared spell cannot be unprepared");
    }
    if (item.systemId === DND_5E_SRD_SYSTEM_ID && nextItemType === "spell" && isRecord(nextItemData) && (item.data.classSpell === true || nextItemData.classSpell === true) && nextItemData.prepared !== item.data.prepared) {
      return badRequest(reply, "Rules-managed D&D class spell preparation requires a reviewed preview and apply");
    }
    if (request.body.name !== undefined) item.name = request.body.name;
    if (request.body.type !== undefined) item.type = request.body.type;
    if (request.body.actorId !== undefined) item.actorId = nextActorId;
    if (request.body.worldId !== undefined) item.worldId = nextWorldId;
    if (request.body.data !== undefined) item.data = request.body.data;
    const previousUpdatedAt = item.updatedAt;
    item.updatedAt = nextRevisionTimestamp(item.updatedAt);
    if (uniqueDndManagedRoots.length > 0) {
      appendServerAuditLog(store, userId, { campaignId: item.campaignId, action: "item.dndManualOverride", targetType: "item", targetId: item.id, before: { updatedAt: previousUpdatedAt, managedRoots: uniqueDndManagedRoots }, after: { updatedAt: item.updatedAt, managedRoots: uniqueDndManagedRoots, reason: manualOverrideReason.value } });
    }
    store.save();
    if (actor) {
      broadcast(createEvent({ campaignId: actor.campaignId, type: "actor.updated", targetId: actor.id, payload: actor }));
    }
    if (nextActor && nextActor.id !== actor?.id) {
      broadcast(createEvent({ campaignId: nextActor.campaignId, type: "actor.updated", targetId: nextActor.id, payload: nextActor }));
    }
    broadcast(createEvent({ campaignId: item.campaignId, type: "item.updated", actorUserId: userId, targetId: item.id, payload: item }));
    return itemPayloadForUser(store, userId, item, [actor?.id, nextActor?.id]);
  });

  app.delete<{ Params: { itemId: string } }>("/api/v1/items/:itemId", async (request, reply) => {
    const index = store.state.items.findIndex((candidate) => candidate.id === request.params.itemId);
    const item = store.state.items[index];
    if (!item) return notFound(reply, "Item not found");
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const activeOrganization = requireCampaignActiveOrganization(store, reply, request.headers, userId, item.campaignId);
    if (activeOrganization !== true) return activeOrganization;
    const actor = item.actorId ? store.state.actors.find((candidate) => candidate.id === item.actorId && candidate.campaignId === item.campaignId) : undefined;
    const canDelete = canCampaign(store, userId, item.campaignId, "actor.delete");
    const canDeleteOwned = actor?.ownerUserId === userId && canCampaign(store, userId, item.campaignId, "actor.updateOwned");
    if (!canDelete && !canDeleteOwned) return forbidden(reply, "Missing permission: actor.delete");
    store.state.items.splice(index, 1);
    appendServerAuditLog(store, userId, { campaignId: item.campaignId, action: "item.delete", targetType: "item", targetId: item.id, before: item, after: { deleted: true } });
    store.save();
    broadcast(createEvent({ campaignId: item.campaignId, type: "item.deleted", actorUserId: userId, targetId: item.id, payload: item }));
    return item;
  });

