    if (!normalized.ok) return badRequest(reply, normalized.error);
    const value = normalized.value;
    const entry = createTimestamped("jnl", { campaignId: request.params.campaignId, worldId: value.worldId ?? undefined, parentId: value.parentId ?? undefined, kind: value.kind ?? "entry", title: value.title ?? "New Journal Entry", body: value.body ?? "", visibility: value.visibility ?? "gm_only", visibleToUserIds: value.visibleToUserIds ?? [], visibleToActorIds: value.visibleToActorIds ?? [], tags: value.tags ?? [], links: value.links ?? [], revision: 1, revisions: [], canonStatus: value.kind === "folder" ? "draft" : "in_review", createdBy: userId, updatedBy: userId }) satisfies JournalEntry;
    store.state.journals.push(entry);
    appendServerAuditLog(store, userId, { campaignId: entry.campaignId, action: "journal.create", targetType: "journal", targetId: entry.id, after: journalAuditSnapshot(entry) });
