  app.post<{ Body: { campaignId: string; formula: string; visibility?: "public" | "gm_only" | "whisper"; label?: string; clientSeed?: string } }>("/api/v1/dice/roll", async (request, reply) => {
    const allowed = requireCampaignPermission(store, reply, request.headers, request.body.campaignId, "dice.roll");
    if (allowed !== true) return allowed;
    if (!opaqueHeaderText(request.headers["idempotency-key"])) return badRequest(reply, "Dice rolls require an Idempotency-Key header");
    const userId = currentUserId(store, request.headers)!;
    let rolled: ReturnType<typeof rollFormula>;
    let fairness: DiceRollFairness;
    try {
      const fairRoll = rollFormulaWithFairness(request.body.formula, { clientSeed: request.body.clientSeed });
      rolled = fairRoll.rolled;
      fairness = fairRoll.fairness;
    } catch (error) {
      return badRequest(reply, error instanceof Error ? error.message : "Invalid dice formula");
    }
    const roll = createTimestamped("roll", { campaignId: request.body.campaignId, userId, formula: request.body.formula, label: request.body.label, visibility: request.body.visibility ?? "public", terms: rolled.terms, total: rolled.total, fairness });
    store.state.rolls.push(roll);
    const message = createTimestamped("msg", { campaignId: request.body.campaignId, userId, type: "roll" as const, body: `${request.body.label ? `${request.body.label}: ` : ""}${request.body.formula} = ${roll.total}`, visibility: roll.visibility, recipientUserIds: [], rollId: roll.id });
    store.state.chat.push(message);
    store.save();
    broadcast(createEvent({ campaignId: roll.campaignId, type: "dice.roll.created", actorUserId: userId, targetId: roll.id, payload: roll }));
    broadcast(createEvent({ campaignId: roll.campaignId, type: "chat.message.created", actorUserId: userId, targetId: message.id, payload: message }));
    return roll;
  });

  app.get<{ Params: { campaignId: string; rollId: string } }>("/api/v1/campaigns/:campaignId/rolls/:rollId/verify", async (request, reply) => {
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "chat.read");
    if (allowed !== true) return allowed;
    const roll = store.state.rolls.find((item) => item.id === request.params.rollId && item.campaignId === request.params.campaignId);
    if (!roll) return notFound(reply, "Dice roll not found");
    const linkedMessage = store.state.chat.find((message) => message.rollId === roll.id && message.campaignId === roll.campaignId);
    if (!canReadDiceRoll(store, userId, roll, linkedMessage)) return notFound(reply, "Dice roll not found");
    const sourceRollId = roll.heroicInspiration?.kind === "reroll" ? roll.heroicInspiration.originalRollId : undefined;
    const sourceRoll = sourceRollId
      ? store.state.rolls.find((candidate) => candidate.id === sourceRollId && candidate.campaignId === roll.campaignId)
      : undefined;
    const visibleSource = sourceRoll && canReadDiceRoll(store, userId, sourceRoll, store.state.chat.find((message) => message.rollId === sourceRoll.id && message.campaignId === sourceRoll.campaignId)) ? sourceRoll : undefined;
    return verifyFairDiceRollRecord(roll, visibleSource);
  });

  app.get<{ Params: { campaignId: string }; Querystring: ListPaginationQuery }>("/api/v1/campaigns/:campaignId/rolls", async (request, reply) => {
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "chat.read");
    if (allowed !== true) return allowed;
    const pagination = normalizeListPagination(request.query);
    if ("error" in pagination) return badRequest(reply, pagination.error);
    const linkedMessagesByRollId = new Map<string, ChatMessage>();
    for (const message of store.state.chat) {
      if (message.campaignId !== request.params.campaignId || !message.rollId || linkedMessagesByRollId.has(message.rollId)) continue;
      linkedMessagesByRollId.set(message.rollId, message);
    }
    const rolls = store.state.rolls.filter((roll) => {
      if (roll.campaignId !== request.params.campaignId) return false;
      const linkedMessage = linkedMessagesByRollId.get(roll.id);
      return canReadDiceRoll(store, userId, roll, linkedMessage);
    });
    return pagination.requested ? paginateList(rolls, pagination) : rolls;
  });

  app.get<{ Params: { campaignId: string } }>("/api/v1/campaigns/:campaignId/dice-macros", async (request, reply) => {
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "dice.roll");
    if (allowed !== true) return allowed;
    const canManage = canCampaign(store, userId, request.params.campaignId, "campaign.update");
    return store.state.diceMacros.filter((macro) => macro.campaignId === request.params.campaignId && (macro.visibility === "public" || canManage));
  });

  app.post<{ Params: { campaignId: string }; Body: Partial<DiceMacro> }>("/api/v1/campaigns/:campaignId/dice-macros", async (request, reply) => {
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "campaign.update");
    if (allowed !== true) return allowed;
    if (!opaqueHeaderText(request.headers["idempotency-key"])) return badRequest(reply, "Dice macro creation requires an Idempotency-Key header");
    const userId = currentUserId(store, request.headers)!;
    const name = typeof request.body.name === "string" ? request.body.name.trim() : "";
    const formula = typeof request.body.formula === "string" ? request.body.formula.trim() : "";
    if (!name) return badRequest(reply, "Dice macro name is required");
    if (!formula) return badRequest(reply, "Dice macro formula is required");
    try {
      rollFormula(formula);
    } catch (error) {
      return badRequest(reply, error instanceof Error ? error.message : "Invalid dice macro formula");
    }
    const macro = createTimestamped("mac", { campaignId: request.params.campaignId, createdBy: userId, name, formula, visibility: request.body.visibility === "gm_only" ? ("gm_only" as const) : ("public" as const) }) satisfies DiceMacro;
    store.state.diceMacros.push(macro);
    appendServerAuditLog(store, userId, { campaignId: macro.campaignId, action: "diceMacro.create", targetType: "dice_macro", targetId: macro.id, after: diceMacroAuditSummary(macro) });
    store.save();
    broadcast(createEvent({ campaignId: macro.campaignId, type: "dice.macro.created", actorUserId: userId, targetId: macro.id, payload: macro }));
    return macro;
  });

  app.patch<{ Params: { macroId: string }; Body: Partial<DiceMacro> }>("/api/v1/dice-macros/:macroId", async (request, reply) => {
    const macro = store.state.diceMacros.find((item) => item.id === request.params.macroId);
    if (!macro) return notFound(reply, "Dice macro not found");
    const allowed = requireCampaignPermission(store, reply, request.headers, macro.campaignId, "campaign.update");
    if (allowed !== true) return allowed;
    const userId = currentUserId(store, request.headers)!;
    const normalized = normalizeDiceMacroPatch(request.body);
    if (!normalized.ok) return badRequest(reply, normalized.error);
    const before = diceMacroAuditSummary(macro);
    const previousVisibility = macro.visibility;
    Object.assign(macro, normalized.value);
    macro.updatedAt = nextRevisionTimestamp(macro.updatedAt);
    appendServerAuditLog(store, userId, { campaignId: macro.campaignId, action: "diceMacro.update", targetType: "dice_macro", targetId: macro.id, before, after: diceMacroAuditSummary(macro) });
    store.save();
    broadcast(createEvent({ campaignId: macro.campaignId, type: "dice.macro.updated", actorUserId: userId, targetId: macro.id, payload: { ...macro, previousVisibility } }));
    return macro;
  });

