  app.post<{ Params: { campaignId: string }; Body: Partial<AudioTrack> }>("/api/v1/campaigns/:campaignId/audio", async (request, reply) => {
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "scene.update");
    if (allowed !== true) return allowed;
    if (!opaqueHeaderText(request.headers["idempotency-key"])) return badRequest(reply, "Audio track creation requires an Idempotency-Key header");
    const userId = currentUserId(store, request.headers)!;
    const name = typeof request.body.name === "string" ? request.body.name.trim() : "";
    if (!name) return badRequest(reply, "Audio track name is required");
    const url = normalizeAudioTrackUrl(request.body.url);
    if (!url) return badRequest(reply, "Audio track url must be a valid http(s) or relative URL");
    const track = createTimestamped("aud", { campaignId: request.params.campaignId, createdBy: userId, name: name.slice(0, 120), url, kind: normalizeAudioTrackKind(request.body.kind), loop: request.body.loop ?? true, playing: false, volume: normalizeAudioVolume(request.body.volume) }) satisfies AudioTrack;
    store.state.audioTracks.push(track);
    store.save();
    broadcast(createEvent({ campaignId: track.campaignId, type: "audio.updated", actorUserId: userId, targetId: track.id, payload: track }));
    return track;
  });

  app.patch<{ Params: { trackId: string }; Body: Partial<AudioTrack> }>("/api/v1/audio/:trackId", async (request, reply) => {
    const track = store.state.audioTracks.find((item) => item.id === request.params.trackId);
    if (!track) return notFound(reply, "Audio track not found");
    const allowed = requireCampaignPermission(store, reply, request.headers, track.campaignId, "scene.update");
    if (allowed !== true) return allowed;
    const userId = currentUserId(store, request.headers)!;
    if (request.body.name !== undefined) {
      const name = typeof request.body.name === "string" ? request.body.name.trim() : "";
      if (!name) return badRequest(reply, "Audio track name is required");
      track.name = name.slice(0, 120);
    }
    if (request.body.url !== undefined) {
      const url = normalizeAudioTrackUrl(request.body.url);
      if (!url) return badRequest(reply, "Audio track url must be a valid http(s) or relative URL");
      track.url = url;
    }
    if (request.body.kind !== undefined) track.kind = normalizeAudioTrackKind(request.body.kind);
    if (typeof request.body.loop === "boolean") track.loop = request.body.loop;
    if (request.body.volume !== undefined) track.volume = normalizeAudioVolume(request.body.volume);
    if (typeof request.body.playing === "boolean") {
      const wasPlaying = track.playing;
      track.playing = request.body.playing;
      if (track.playing && !wasPlaying) track.startedAt = nowIso();
      if (!track.playing) track.startedAt = undefined;
      if (track.playing && track.kind !== "sfx") {
        for (const other of store.state.audioTracks) {
          if (other.id !== track.id && other.campaignId === track.campaignId && other.kind === track.kind && other.playing) {
            other.playing = false;
            other.startedAt = undefined;
            other.updatedAt = nowIso();
            broadcast(createEvent({ campaignId: other.campaignId, type: "audio.updated", actorUserId: userId, targetId: other.id, payload: other }));
          }
        }
      }
    }
    track.updatedAt = nextRevisionTimestamp(track.updatedAt);
    store.save();
    broadcast(createEvent({ campaignId: track.campaignId, type: "audio.updated", actorUserId: userId, targetId: track.id, payload: track }));
    return track;
  });

  app.delete<{ Params: { trackId: string } }>("/api/v1/audio/:trackId", async (request, reply) => {
    const track = store.state.audioTracks.find((item) => item.id === request.params.trackId);
    if (!track) return notFound(reply, "Audio track not found");
    const allowed = requireCampaignPermission(store, reply, request.headers, track.campaignId, "scene.update");
    if (allowed !== true) return allowed;
    const userId = currentUserId(store, request.headers)!;
    store.state.audioTracks = store.state.audioTracks.filter((item) => item.id !== track.id);
    store.save();
    broadcast(createEvent({ campaignId: track.campaignId, type: "audio.deleted", actorUserId: userId, targetId: track.id, payload: track }));
    return track;
  });

  app.get<{ Querystring: { campaignId?: string } & ListPaginationQuery }>("/api/v1/chat/messages", async (request, reply) => {
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const pagination = normalizeListPagination(request.query);
    if ("error" in pagination) return badRequest(reply, pagination.error);
    if (!request.query.campaignId) {
      const workspace = organizationWorkspaceRecordForRequest(store, userId, request.headers);
      const activeCampaignIds = new Set(store.state.campaigns.filter((campaign) => campaign.organizationId === workspace.id).map((campaign) => campaign.id));
      const messages = store.state.chat.filter((item) => activeCampaignIds.has(item.campaignId) && canCampaign(store, userId, item.campaignId, "chat.read") && canReadChatMessage(store, userId, item));
      return pagination.requested ? paginateList(messages, pagination) : messages;
    }
    const allowed = requireCampaignPermission(store, reply, request.headers, request.query.campaignId, "chat.read");
    if (allowed !== true) return allowed;
    const messages = store.state.chat.filter((item) => item.campaignId === request.query.campaignId && canReadChatMessage(store, userId, item));
    return pagination.requested ? paginateList(messages, pagination) : messages;
  });

  app.get<{ Params: { campaignId: string }; Querystring: { format?: "json" | "ndjson" } }>("/api/v1/campaigns/:campaignId/chat/export", async (request, reply) => {
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "chat.read");
    if (allowed !== true) return allowed;
    const messages = store.state.chat.filter((item) => item.campaignId === request.params.campaignId && canReadChatMessage(store, userId, item));
    const format = request.query.format === "ndjson" ? "ndjson" : "json";
    appendSerializedReadAudit(userId, { campaignId: request.params.campaignId, action: "chat.export", targetType: "chat", after: { format, count: messages.length, visibilityCounts: countBy(messages, (message) => message.visibility), typeCounts: countBy(messages, (message) => message.type) } });
    if (format === "ndjson") {
      reply.header("content-type", "application/x-ndjson; charset=utf-8");
      return messages.map((message) => JSON.stringify(message)).join("\n") + (messages.length > 0 ? "\n" : "");
    }
    return { campaignId: request.params.campaignId, exportedAt: nowIso(), count: messages.length, visibilityCounts: countBy(messages, (message) => message.visibility), typeCounts: countBy(messages, (message) => message.type), messages };
  });

  app.post<{ Body: unknown }>("/api/v1/chat/messages", async (request, reply) => {
    const parsedBody = parseChatMessageCreateBody(request.body, reply);
    if (!parsedBody.ok) return parsedBody.reply;
    const body = parsedBody.body;
    const allowed = requireCampaignPermission(store, reply, request.headers, body.campaignId, "chat.write");
    if (allowed !== true) return allowed;
    if (!opaqueHeaderText(request.headers["idempotency-key"])) return badRequest(reply, "Chat message creation requires an Idempotency-Key header");
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const visibility = body.type === "whisper" ? "whisper" : (body.visibility ?? "public");
    const recipientUserIds = normalizeChatRecipients(store, body.campaignId, userId, visibility, body.recipientUserIds, reply);
    if (!Array.isArray(recipientUserIds)) return recipientUserIds;
    const rollLink = normalizeChatRollLink(store, body.campaignId, userId, body.rollId, visibility, recipientUserIds, reply);
    if (!rollLink.ok) return rollLink.reply;
    const replyToMessageId = normalizeChatReplyToMessageId(store, body.campaignId, userId, body.replyToMessageId, reply);
    if (replyToMessageId && typeof replyToMessageId !== "string") return replyToMessageId;
    const message = createTimestamped("msg", { campaignId: body.campaignId, sceneId: body.sceneId, userId, type: body.type ?? (visibility === "whisper" ? "whisper" : "plain"), body: body.body, visibility, recipientUserIds, rollId: rollLink.rollId, replyToMessageId }) satisfies ChatMessage;
    store.state.chat.push(message);
    store.save();
    broadcast(createEvent({ campaignId: message.campaignId, type: "chat.message.created", actorUserId: message.userId, targetId: message.id, payload: message }));
    return message;
  });

  app.patch<{ Params: { messageId: string }; Body: ChatMessageEditBody }>("/api/v1/chat/messages/:messageId", async (request, reply) => {
    const message = store.state.chat.find((item) => item.id === request.params.messageId);
    if (!message) return notFound(reply, "Chat message not found");
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const canModerate = canCampaign(store, userId, message.campaignId, "chat.moderate");
    const canEditOwn = message.userId === userId && canCampaign(store, userId, message.campaignId, "chat.write");
    if (!canModerate && !canEditOwn) return forbidden(reply, "Missing permission: chat.write or chat.moderate");
    const parsedBody = parseChatMessageEditBody(request.body, reply);
    if (!parsedBody.ok) return parsedBody.reply;
    const previousBody = message.body;
    message.body = parsedBody.body;
    message.editedByUserId = userId;
    message.editedAt = nowIso();
    message.updatedAt = nextRevisionTimestamp(message.updatedAt);
    message.editedAt = message.updatedAt;
    appendServerAuditLog(store, userId, { campaignId: message.campaignId, action: "chat.message.edit", targetType: "chat", targetId: message.id, before: { bodyLength: previousBody.length, visibility: message.visibility, type: message.type }, after: { bodyLength: message.body.length, visibility: message.visibility, type: message.type } });
    store.save();
    broadcast(createEvent({ campaignId: message.campaignId, type: "chat.message.updated", actorUserId: userId, targetId: message.id, payload: message }));
    return message;
  });

  app.patch<{ Params: { messageId: string }; Body: { moderationStatus?: ChatMessage["moderationStatus"] } }>("/api/v1/chat/messages/:messageId/moderation", async (request, reply) => {
    const message = store.state.chat.find((item) => item.id === request.params.messageId);
    if (!message) return notFound(reply, "Chat message not found");
    const allowed = requireCampaignPermission(store, reply, request.headers, message.campaignId, "chat.moderate");
    if (allowed !== true) return allowed;
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const moderationStatus = normalizeChatModerationStatus(request.body.moderationStatus);
    if (!moderationStatus) return badRequest(reply, "moderationStatus must be open, follow_up, or reviewed");
    message.moderationStatus = moderationStatus;
    message.moderatedByUserId = userId;
    message.moderatedAt = nowIso();
    message.updatedAt = nextRevisionTimestamp(message.updatedAt);
    message.moderatedAt = message.updatedAt;
    appendServerAuditLog(store, userId, { campaignId: message.campaignId, action: "chat.message.moderate", targetType: "chat", targetId: message.id, after: { moderationStatus, visibility: message.visibility, type: message.type } });
    store.save();
    broadcast(createEvent({ campaignId: message.campaignId, type: "chat.message.updated", actorUserId: userId, targetId: message.id, payload: message }));
    return message;
  });

