  app.post<{ Params: { campaignId: string; systemId: string }; Body: unknown }>("/api/v1/campaigns/:campaignId/systems/:systemId/encounter-plan", async (request, reply) => {
    const rawBody = request.body ?? {};
    const createEncounter = isRecord(rawBody) && rawBody.createEncounter === true;
    const permission: PermissionName = createEncounter ? "combat.manage" : "campaign.read";
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, permission);
    if (allowed !== true) return allowed;
    if (createEncounter) {
      if (!opaqueHeaderText(request.headers["idempotency-key"])) return badRequest(reply, "Encounter creation requires an Idempotency-Key header");
      const campaign = store.state.campaigns.find((candidate) => candidate.id === request.params.campaignId);
      if (!campaign) return notFound(reply, "Campaign not found");
      const revision = requireExpectedRevision(reply, { resourceType: "campaign", resourceId: campaign.id, currentUpdatedAt: campaign.updatedAt, expectedUpdatedAt: isRecord(rawBody) ? rawBody.expectedUpdatedAt : undefined, current: campaign, label: "Campaign" });
      if (revision !== true) return revision;
    }
    const system = findRegisteredSystem(store.state, request.params.systemId);
    if (!system) return notFound(reply, "System not found");
    const normalizedBody = normalizeSystemEncounterPlanBody(store, request.params.campaignId, system, rawBody);
    if (!normalizedBody.ok) return badRequest(reply, normalizedBody.error);
    const body = normalizedBody.value;
    const party = partyActorsForSystem(store, request.params.campaignId, system.id, body.partyActorIds);
    const plan = encounterPlanForSystem(system.id, party, body.threats);
    if (!body.createEncounter) return { plan };
    const normalized = normalizeEncounterPatch(store, request.params.campaignId, { name: body.name?.trim() || `${system.name} ${titleCase(plan.difficulty)} Encounter`, summary: plan.summary, tokenIds: [], difficulty: plan.difficulty, systemId: system.id, partyActorIds: party.map((actor) => actor.id), threats: plan.threats.map((threat) => ({ id: threat.id, count: threat.count })) }, true);
    if (!normalized.ok) return badRequest(reply, normalized.error);
    const userId = currentUserId(store, request.headers)!;
    const encounter = createTimestamped("enc", { campaignId: request.params.campaignId, systemId: normalized.value.systemId, name: normalized.value.name!, summary: normalized.value.summary!, tokenIds: normalized.value.tokenIds ?? [], difficulty: normalized.value.difficulty, partyActorIds: normalized.value.partyActorIds, threats: normalized.value.threats }) satisfies Encounter;
    store.state.encounters.push(encounter);
    const campaign = advanceCampaignAggregateRevision(store, encounter.campaignId);
    appendServerAuditLog(store, userId, { campaignId: encounter.campaignId, action: "encounter.create", targetType: "encounter", targetId: encounter.id, after: encounter });
    store.save();
    broadcast(createEvent({ campaignId: encounter.campaignId, type: "encounter.created", actorUserId: userId, targetId: encounter.id, payload: encounter }));
    if (campaign) broadcast(createEvent({ campaignId: campaign.id, type: "campaign.updated", actorUserId: userId, targetId: campaign.id, payload: campaign }));
    return { plan, encounter };
  });

