    if (typeof request.query.expectedUpdatedAt !== "string" || !request.query.expectedUpdatedAt.trim()) {
      return badRequest(reply, "Condition expectedUpdatedAt is required");
    }
    if (request.query.expectedUpdatedAt !== actor.updatedAt) {
      return staleWriteConflict(reply, { resourceType: "actor", resourceId: actor.id, expectedUpdatedAt: request.query.expectedUpdatedAt, currentUpdatedAt: actor.updatedAt, current: actorPayloadForUser(store, userId, actor) });
    }
    const reviewedUpdatedAt = actor.updatedAt;
