    actor.updatedAt = nextRevisionTimestamp(actor.updatedAt);
    appendServerAuditLog(store, userId, { campaignId: actor.campaignId, action: "actor.conditionRemoved", targetType: "actor", targetId: actor.id, before: { updatedAt: reviewedUpdatedAt, conditionId: request.params.conditionId }, after: { updatedAt: actor.updatedAt } });
    store.save();
    broadcastActorUpdated(broadcast, actor);
    const privateDataVisible = canReadActorPrivateData(store, userId, actor.campaignId, actor);
