function systemActivityOperationsSummary(store: StateStore, systems: Array<{ id: string; name: string; readiness: ReturnType<typeof systemProductionReadiness> }>) {
  const systemById = new Map(systems.map((system) => [system.id, system]));
  const activityLogs = store.state.auditLogs.filter((log) => log.action === "system.actor.roll" || log.action === "system.actor.rest" || log.action === "system.actor.advance").sort(sortTimestampsDesc);
  const rows = activityLogs
    .map((log) => {
      const after = isRecord(log.after) ? log.after : {};
      const systemId = typeof after.systemId === "string" ? after.systemId : undefined;
      const system = systemId ? systemById.get(systemId) : undefined;
      return { auditLogId: log.id, action: log.action, campaignId: log.campaignId, actorUserId: log.actorUserId, systemId, systemName: system?.name, productionReady: system?.readiness.productionReady ?? false, actorId: typeof after.actorId === "string" ? after.actorId : log.targetId, actorType: typeof after.actorType === "string" ? after.actorType : undefined, rollId: typeof after.rollId === "string" ? after.rollId : undefined, label: typeof after.label === "string" ? after.label : undefined, restType: typeof after.restType === "string" ? after.restType : undefined, optionId: typeof after.optionId === "string" ? after.optionId : undefined, consumeResources: after.consumeResources === true, applyEffect: after.applyEffect === true, hasUsage: after.hasUsage === true, hasEffect: after.hasEffect === true, createdAt: log.createdAt };
    })
    .filter((row) => row.systemId);
  const nonPrimaryRows = rows.filter((row) => !row.productionReady);
  const systemsWithRecentActivity = [...new Set(nonPrimaryRows.map((row) => row.systemId).filter((systemId): systemId is string => Boolean(systemId)))];
  return { activityCount: rows.length, nonPrimaryActivityCount: nonPrimaryRows.length, systemsWithRecentActivity, actionCounts: countBy(rows, (row) => row.action), nonPrimaryActionCounts: countBy(nonPrimaryRows, (row) => row.action), systemCounts: countBy(rows, (row) => row.systemId ?? "unknown"), nonPrimarySystemCounts: countBy(nonPrimaryRows, (row) => row.systemId ?? "unknown"), recentActivity: rows.slice(0, 12), recentNonPrimaryActivity: nonPrimaryRows.slice(0, 12) };
}

function systemCapabilityEvidence(systemId: string, compendium: ReadonlyArray<{ id: string; name: string; data?: Record<string, unknown> }>, threats: ReadonlyArray<{ id: string; name: string }>) {
  if (systemId !== DND_5E_SRD_SYSTEM_ID) {
    return { origins: { count: 0, samples: [] as string[] }, monsterCreation: { count: 0, samples: [] as string[] }, equipmentPurchase: { count: 0, samples: [] as string[] } };
  }
  const origins = dnd5eSrdCharacterOrigins();
  const monsterCreationThreats = threats.filter((threat) => Boolean(dnd5eSrdMonsterActorData(threat.id)));
  const purchasableEntries = compendium.filter((entry) => {
    const data = entry.data ?? {};
    return Number.isFinite(Number(data.costGp)) && Number(data.costGp) >= 0 && typeof data.equipmentCategory === "string";
  });
  return { origins: { count: origins.backgrounds.length + origins.species.length, samples: [...origins.backgrounds.slice(0, 2).map((origin) => `background:${origin.id}`), ...origins.species.slice(0, 2).map((origin) => `species:${origin.id}`)] }, monsterCreation: { count: monsterCreationThreats.length, samples: monsterCreationThreats.slice(0, 4).map((threat) => threat.id) }, equipmentPurchase: { count: purchasableEntries.length, samples: purchasableEntries.slice(0, 4).map((entry) => entry.id ?? entry.name ?? "unknown") } };
}

function systemProductionGaps(readiness: ReturnType<typeof systemProductionReadiness>, coverage: { supportsOrigins: boolean; supportsMonsterCreation: boolean; supportsEquipmentPurchase: boolean; supportsEncounterPlanning: boolean; supportsCompendium: boolean }, issues: string[]) {
  if (readiness.productionReady) return [];
  return [...readiness.reasons, ...issues, coverage.supportsOrigins ? undefined : "missing_origin_builder", coverage.supportsMonsterCreation ? undefined : "missing_monster_creation", coverage.supportsEquipmentPurchase ? undefined : "missing_equipment_purchase", coverage.supportsEncounterPlanning ? undefined : "missing_encounter_planning", coverage.supportsCompendium ? undefined : "missing_compendium_support"].filter((gap): gap is string => Boolean(gap));
}

function systemProductionReadiness(systemId: string, activeCampaignCount: number, actorCount: number, itemCount: number) {
  const productionReady = systemId === DND_5E_SRD_SYSTEM_ID;
  const used = activeCampaignCount > 0 || actorCount > 0 || itemCount > 0;
  return { tier: productionReady ? "primary" : "demo", productionReady, actionRequired: !productionReady && used, reasons: productionReady || !used ? [] : ["non_primary_runtime_in_use"] };
}

function systemProductionReadinessSummary(systems: Array<{ id: string; readiness: ReturnType<typeof systemProductionReadiness>; usage: { activeCampaignCount: number; actorCount: number; itemCount: number } }>) {
  const nonPrimaryInUse = systems.filter((system) => system.readiness.actionRequired);
  return { primarySystemId: DND_5E_SRD_SYSTEM_ID, productionReadySystemCount: systems.filter((system) => system.readiness.productionReady).length, demoSystemCount: systems.filter((system) => !system.readiness.productionReady).length, nonPrimaryActiveCampaignCount: nonPrimaryInUse.reduce((total, system) => total + system.usage.activeCampaignCount, 0), nonPrimaryActorCount: nonPrimaryInUse.reduce((total, system) => total + system.usage.actorCount, 0), nonPrimaryItemCount: nonPrimaryInUse.reduce((total, system) => total + system.usage.itemCount, 0), systemsNeedingProductionDepth: nonPrimaryInUse.map((system) => system.id), actionRequired: nonPrimaryInUse.length > 0 };
}

function systemProductionGapCounts(systems: Array<{ id: string; name: string; productionGaps: string[]; usage: { activeCampaignCount: number; actorCount: number; itemCount: number } }>) {
  const gapCounts = new Map<string, { code: string; count: number; systems: Array<{ id: string; name: string; activeCampaignCount: number; actorCount: number; itemCount: number }> }>();
  for (const system of systems) {
    for (const gap of system.productionGaps) {
      const entry = gapCounts.get(gap) ?? { code: gap, count: 0, systems: [] };
      entry.count += 1;
      entry.systems.push({ id: system.id, name: system.name, activeCampaignCount: system.usage.activeCampaignCount, actorCount: system.usage.actorCount, itemCount: system.usage.itemCount });
      gapCounts.set(gap, entry);
    }
  }
  return [...gapCounts.values()]
    .sort((left, right) => right.count - left.count || left.code.localeCompare(right.code))
    .slice(0, 8)
    .map((entry) => {
      const detail = systemProductionGapDetail(entry.code);
      return { ...entry, ...detail, systems: entry.systems.sort((left, right) => right.activeCampaignCount + right.actorCount + right.itemCount - (left.activeCampaignCount + left.actorCount + left.itemCount) || left.name.localeCompare(right.name)).slice(0, 4) };
    });
}

function systemProductionGapDetail(code: string): { severity: "warning" | "critical"; message: string; remediation: string } {
  switch (code) {
    case "non_primary_runtime_in_use":
      return { severity: "critical", message: "A demo rules runtime is being used by live campaign data.", remediation: "Migrate the campaign or harden that runtime to primary-system depth before treating the deployment as Roll20-class." };
    case "missing_origin_builder":
      return { severity: "warning", message: "The runtime does not expose guided character origin choices.", remediation: "Add background/species or equivalent origin catalogs and creation-time validation." };
    case "missing_monster_creation":
      return { severity: "warning", message: "The runtime cannot create adversary actors from threat or bestiary entries.", remediation: "Add threat stat blocks plus actor creation and action quick-roll wiring." };
    case "missing_equipment_purchase":
      return { severity: "warning", message: "The runtime lacks a first-class equipment purchase flow.", remediation: "Add priced compendium entries, currency mutation, inventory creation, and insufficient-funds checks." };
    case "missing_encounter_planning":
      return { severity: "warning", message: "The runtime has no encounter-planning threat budget support.", remediation: "Add threat catalogs, party budget math, and optional encounter persistence." };
    case "missing_compendium_support":
      return { severity: "warning", message: "The runtime lacks compendium-backed content.", remediation: "Add bounded compendium entries for actions, gear, conditions, and runtime-specific resources." };
    default:
      return { severity: "warning", message: "The runtime has an unresolved manifest or content issue.", remediation: "Inspect the system manifest, schemas, templates, compendium entries, and encounter threats for this gap code." };
  }
}

function systemPromotionBlockers(systems: Array<{ id: string; name: string; readiness: ReturnType<typeof systemProductionReadiness>; usage: { activeCampaignCount: number; actorCount: number; itemCount: number }; productionGaps: string[] }>) {
  return systems
    .filter((system) => !system.readiness.productionReady && system.productionGaps.length > 0)
    .map((system) => {
      const blockers = system.productionGaps.map((gap) => ({ code: gap, ...systemProductionGapDetail(gap) }));
      return { systemId: system.id, name: system.name, activeCampaignCount: system.usage.activeCampaignCount, actorCount: system.usage.actorCount, itemCount: system.usage.itemCount, blockerCount: blockers.length, criticalBlockerCount: blockers.filter((blocker) => blocker.severity === "critical").length, blockers };
    })
    .sort((left, right) => right.criticalBlockerCount - left.criticalBlockerCount || right.activeCampaignCount + right.actorCount + right.itemCount - (left.activeCampaignCount + left.actorCount + left.itemCount) || right.blockerCount - left.blockerCount || left.name.localeCompare(right.name))
    .slice(0, 8);
}

function systemOperationsRemediationQueue(gapCounts: ReturnType<typeof systemProductionGapCounts>, activityOperations?: ReturnType<typeof systemActivityOperationsSummary>) {
  const remediations = gapCounts.map((gap) => ({ code: gap.code, severity: gap.severity, action: gap.remediation, affectedCount: gap.count, message: gap.message, samples: gap.systems.map((system) => ({ systemId: system.id, name: system.name, activeCampaignCount: system.activeCampaignCount, actorCount: system.actorCount, itemCount: system.itemCount })) }));
  if (activityOperations && activityOperations.nonPrimaryActivityCount > 0) {
    remediations.push({ code: "non_primary_runtime_recent_activity", severity: "critical", action: "Review recent demo-runtime rolls, rests, and advancement before promoting or migrating those campaigns.", affectedCount: activityOperations.nonPrimaryActivityCount, message: "A demo rules runtime is actively handling recent table operations.", samples: activityOperations.recentNonPrimaryActivity.slice(0, 4).map((activity) => ({ systemId: activity.systemId ?? "unknown", name: activity.systemName ?? activity.systemId ?? "Unknown system", activeCampaignCount: activity.campaignId ? 1 : 0, actorCount: activity.actorId ? 1 : 0, itemCount: 0, action: activity.action, actorId: activity.actorId, createdAt: activity.createdAt })) });
  }
  return remediations.sort((left, right) => (right.severity === "critical" ? 2 : 1) - (left.severity === "critical" ? 2 : 1) || right.affectedCount - left.affectedCount || left.code.localeCompare(right.code)).slice(0, 8);
}

function systemOperationsIssues(system: SystemManifest, templateCount: number, compendiumCount: number, threatCount: number): string[] {
  return [system.entrypoints.client ? undefined : "missing_client_entrypoint", system.entrypoints.server ? undefined : "missing_server_entrypoint", system.schemas.actor ? undefined : "missing_actor_schema", system.schemas.item ? undefined : "missing_item_schema", templateCount > 0 ? undefined : "missing_character_templates", compendiumCount > 0 ? undefined : "missing_compendium_entries", threatCount > 0 ? undefined : "missing_encounter_threats"].filter((issue): issue is string => Boolean(issue));
}

async function syncPluginRegistriesForRequest(pluginRegistry: PluginRuntimeRegistry, registryUrl: string | undefined, reply: FastifyReply) {
  const configuredRegistries = configuredPluginRegistryUrls();
  if (!configuredRegistries.length) return badRequest(reply, "No plugin registries are configured");
  const requestedRegistry = registryUrl ? normalizeConfiguredPluginRegistryUrl(registryUrl) : undefined;
  if (registryUrl && !requestedRegistry) return badRequest(reply, "Plugin registryUrl must be a valid http or https URL");
  if (requestedRegistry && !configuredRegistries.includes(requestedRegistry)) return forbidden(reply, "Plugin registryUrl is not configured for this server");
  const registryUrls = requestedRegistry ? [requestedRegistry] : configuredRegistries;
  const registries = [];
  for (const url of registryUrls) registries.push(await pluginRegistry.syncRemoteRegistry(url));
  const imported = registries.flatMap((registry) => registry.imported);
  return { syncedAt: nowIso(), registries, plugins: imported };
}

function pluginOperationalInstall(store: StateStore, pluginRegistry: PluginRuntimeRegistry, grant: PermissionGrant) {
  const installedVersion = pluginVersionFromGrant(grant);
  const plugin = pluginRegistry.find(grant.subjectId, installedVersion);
  const storageEntryCount = store.state.pluginStorage.filter((entry) => entry.campaignId === grant.campaignId && entry.pluginId === grant.subjectId).length;
  if (!plugin) {
    return { campaignId: grant.campaignId, pluginId: grant.subjectId, installedVersion, status: "missing_package" as const, grantedPermissions: [...grant.permissions], missingManifestPermissions: [], storageEntryCount, issues: ["installed_plugin_package_missing"] };
  }
  const compatibleCore = pluginCoreCompatibilityInfo(plugin);
  const reviewBlock = pluginReviewInstallBlock(store, plugin);
  const trustBlock = plugin.trust.installable ? undefined : pluginTrustErrorMessage(plugin);
  const identityBlock = pluginGrantIdentityBlock(grant, plugin);
  const missingManifestPermissions = plugin.permissions.filter((permission) => !grant.permissions.includes(permission));
  const compatibilityBlock = pluginCoreCompatibilityBlock(plugin);
  const issues = [trustBlock ? "trust_policy_blocked" : undefined, reviewBlock ? "marketplace_review_blocked" : undefined, identityBlock ? "package_identity_drift" : undefined, missingManifestPermissions.length > 0 ? "manifest_permission_not_granted" : undefined, compatibilityBlock ? "core_compatibility_drift" : undefined].filter((issue): issue is string => Boolean(issue));
  return { campaignId: grant.campaignId, pluginId: plugin.id, name: plugin.name, installedVersion: plugin.version, latestVersion: plugin.distribution.latestVersion, updateAvailable: plugin.version !== plugin.distribution.latestVersion, status: trustBlock || reviewBlock || identityBlock || compatibilityBlock ? ("blocked" as const) : ("healthy" as const), grantedPermissions: [...grant.permissions], requestedPermissions: [...plugin.permissions], missingManifestPermissions, compatibleCore, source: { ...plugin.source }, trust: { ...plugin.trust, errors: [...plugin.trust.errors], signature: plugin.trust.signature ? { ...plugin.trust.signature } : undefined }, marketplaceReview: publicPluginReviewInfo(plugin, pluginReviewForDisplay(store, plugin)), storageEntryCount, issues, blocks: [trustBlock, reviewBlock, identityBlock, compatibilityBlock].filter((block): block is string => Boolean(block)) };
}

function pluginCoreCompatibilityInfo(plugin: LoadedPlugin): { range: string; coreVersion: string; satisfied: boolean } {
  return { range: plugin.compatibleCore, coreVersion: CORE_COMPATIBILITY_VERSION, satisfied: pluginCoreRangeSatisfied(plugin.compatibleCore) };
}

function pluginCoreCompatibilityBlock(plugin: LoadedPlugin): string | undefined {
  const compatibleCore = pluginCoreCompatibilityInfo(plugin);
  return compatibleCore.satisfied ? undefined : `Plugin requires core ${compatibleCore.range}; server core is ${compatibleCore.coreVersion}`;
}

function pluginCoreRangeSatisfied(range: string): boolean {
  return pluginCoreCompatibility(range, CORE_COMPATIBILITY_VERSION).satisfied;
}

function publicPluginReviewInfo(plugin: LoadedPlugin, review: PluginReview): AdminPluginReviewInfo {
  const installBlock = pluginReviewInstallBlockForReview(plugin, review);
  return { review: { ...review }, plugin: { id: plugin.id, name: plugin.name, version: plugin.version, permissions: [...plugin.permissions], chatCommands: plugin.chatCommands }, source: { ...plugin.source }, distribution: { availableVersions: [...plugin.distribution.availableVersions], latestVersion: plugin.distribution.latestVersion }, trust: { ...plugin.trust, errors: [...plugin.trust.errors], signature: plugin.trust.signature ? { ...plugin.trust.signature } : undefined }, installable: !installBlock, ...(installBlock ? { installBlock } : {}) };
}

function publicPluginCatalogInfo(plugin: LoadedPlugin): PublicPluginCatalogInfo {
  return {
    id: plugin.id,
    name: plugin.name,
    version: plugin.version,
    compatibleCore: plugin.compatibleCore,
    ...(plugin.package ? { package: { publisher: plugin.package.publisher, license: plugin.package.license } } : {}),
    ...(plugin.runtime ? { runtime: { apiVersion: plugin.runtime.apiVersion, sandbox: plugin.runtime.sandbox } } : {}),
    permissions: [...plugin.permissions],
    ...(plugin.ui ? { ui: { panels: plugin.ui.panels?.map((panel) => ({ ...panel })) } } : {}),
    ...(plugin.chatCommands ? { chatCommands: plugin.chatCommands.map((command) => ({ ...command })) } : {}),
    ...(plugin.eventSubscriptions ? { eventSubscriptions: plugin.eventSubscriptions.map((subscription) => ({ ...subscription })) } : {}),
    source: { type: plugin.source.type, packageId: plugin.source.packageId, manifestChecksum: plugin.source.manifestChecksum, sandbox: plugin.source.sandbox, checksum: plugin.source.checksum, packageChecksum: plugin.source.packageChecksum, syncedAt: plugin.source.syncedAt },
    distribution: { availableVersions: [...plugin.distribution.availableVersions], latestVersion: plugin.distribution.latestVersion },
    permissionReview: { requestedPermissions: [...plugin.permissionReview.requestedPermissions], grantRequired: plugin.permissionReview.grantRequired },
    trust: publicPluginTrustInfo(plugin),
  };
}

function publicPluginTrustInfo(plugin: LoadedPlugin): PublicPluginCatalogInfo["trust"] {
  return { status: plugin.trust.status, policy: plugin.trust.policy, required: plugin.trust.required, installable: plugin.trust.installable, errors: [...plugin.trust.errors], ...(plugin.trust.signature ? { signature: { keyId: plugin.trust.signature.keyId, algorithm: plugin.trust.signature.algorithm, verified: plugin.trust.signature.verified } } : {}) };
}

function marketplacePluginReviewInfo(plugin: LoadedPlugin, review: PluginReview): MarketplacePluginReviewInfo {
  const installBlock = pluginReviewInstallBlockForReview(plugin, review);
  return { review: { id: review.id, reviewKey: review.reviewKey, pluginId: review.pluginId, packageId: review.packageId, version: review.version, checksum: review.checksum, sourceType: review.sourceType, status: review.status, reviewedAt: review.reviewedAt, createdAt: review.createdAt, updatedAt: review.updatedAt }, installable: !installBlock, ...(installBlock ? { installBlock } : {}) };
}

function ensurePluginReview(store: StateStore, plugin: LoadedPlugin): PluginReview {
  const reviewKey = pluginReviewKey(plugin);
  const existing = store.state.pluginReviews.find((review) => review.reviewKey === reviewKey);
  if (existing) return syncPluginReviewMetadata(existing, plugin);
  const review = createPluginReview(plugin);
  store.state.pluginReviews.push(review);
  return review;
}

function pluginReviewForDisplay(store: StateStore, plugin: LoadedPlugin): PluginReview {
  const existing = store.state.pluginReviews.find((review) => review.reviewKey === pluginReviewKey(plugin));
  return existing ? syncPluginReviewMetadata(existing, plugin) : createPluginReview(plugin);
}

function syncPluginReviewMetadata(review: PluginReview, plugin: LoadedPlugin): PluginReview {
  review.pluginId = plugin.id;
  review.packageId = plugin.source.packageId;
  review.version = plugin.version;
  review.checksum = pluginReviewChecksum(plugin);
  review.sourceType = plugin.source.type;
  review.registryUrl = plugin.source.registryUrl;
  review.packageUrl = plugin.source.packageUrl;
  return review;
}

function createPluginReview(plugin: LoadedPlugin): PluginReview {
  return createTimestamped("plugrev", { reviewKey: pluginReviewKey(plugin), pluginId: plugin.id, packageId: plugin.source.packageId, version: plugin.version, checksum: pluginReviewChecksum(plugin), sourceType: plugin.source.type, registryUrl: plugin.source.registryUrl, packageUrl: plugin.source.packageUrl, status: "pending" as const }) satisfies PluginReview;
}

function updatePluginReview(review: PluginReview, status: PluginReviewStatus, notes: string | undefined, adminUserId: string): void {
  review.status = status;
  review.notes = notes;
  if (status === "pending") {
    review.reviewedAt = undefined;
    review.reviewedByUserId = undefined;
  } else {
    review.reviewedAt = nowIso();
    review.reviewedByUserId = adminUserId;
  }
  review.updatedAt = nowIso();
}

function pluginReviewInstallBlock(store: StateStore, plugin: LoadedPlugin): string | undefined {
  return pluginReviewInstallBlockForReview(plugin, ensurePluginReview(store, plugin));
}

function pluginReviewInstallBlockForReview(plugin: LoadedPlugin, review: PluginReview): string | undefined {
  if (review.status === "rejected") {
    return `Plugin ${plugin.id}@${plugin.version} was rejected by marketplace review`;
  }
  if (pluginRequiresReviewApproval(plugin) && review.status !== "approved") {
    return `Plugin ${plugin.id}@${plugin.version} requires marketplace approval before install or execution; current review status is ${review.status}`;
  }
  return undefined;
}

function pluginRequiresReviewApproval(plugin: LoadedPlugin): boolean {
  return pluginReviewPolicyMode() === "require_approved" || (process.env.NODE_ENV === "production" && plugin.source.type === "registry");
}

function pluginReviewKey(plugin: LoadedPlugin): string {
  return createHash("sha256")
    .update([plugin.id, plugin.version, plugin.source.packageId, pluginReviewChecksum(plugin)].join("\n"))
    .digest("hex");
}

function pluginReviewChecksum(plugin: LoadedPlugin): string {
  return pluginPackageIdentityChecksum(plugin);
}

function pluginReviewPolicyMode(): PluginReviewPolicyMode {
  return process.env.NODE_ENV === "production" || process.env.OTTE_PLUGIN_REVIEW_POLICY === "require_approved" ? "require_approved" : "allow_unreviewed";
}

function normalizePluginReviewStatus(value: unknown): PluginReviewStatus | undefined {
  return value === "pending" || value === "approved" || value === "rejected" ? value : undefined;
}

function normalizePluginReviewNotes(value: unknown): string | undefined | false {
  if (value === undefined || value === null) return undefined;
  if (typeof value !== "string") return false;
  const notes = value.trim();
  if (notes.length > 500) return false;
  return notes || undefined;
}

function pluginCampaignAuditSummary(store: StateStore, campaignId: string, pluginId: string): { installCount: number; lastInstallAt?: string; versions: string[] } {
  const installLogs = store.state.auditLogs.filter((log) => log.campaignId === campaignId && log.action === "plugin.install" && log.targetType === "plugin" && log.targetId === pluginId).sort((left, right) => right.createdAt.localeCompare(left.createdAt));
  const versions = [...new Set(installLogs.map((log) => (isRecord(log.after) && typeof log.after.version === "string" ? log.after.version : undefined)).filter((version): version is string => Boolean(version)))];
  return { installCount: installLogs.length, lastInstallAt: installLogs[0]?.createdAt, versions };
}

function pluginCampaignInfo(store: StateStore, pluginRegistry: PluginRuntimeRegistry, campaignId: string, plugin: LoadedPlugin): CampaignPluginCatalogInfo {
  const grant = findPluginGrant(store, campaignId, plugin.id);
  const installedVersion = pluginVersionFromGrant(grant);
  const installedPlugin = installedVersion ? pluginRegistry.find(plugin.id, installedVersion) : undefined;
  const displayPlugin = installedPlugin ?? plugin;
  const latestVersion = plugin.distribution.latestVersion;
  const availableVersions = plugin.distribution.availableVersions;
  const versionCompatibility = availableVersions.flatMap((version) => {
    const versionPlugin = pluginRegistry.find(plugin.id, version);
    if (!versionPlugin) return [];
    const compatibilityBlock = pluginCoreCompatibilityBlock(versionPlugin);
    const publicVersion = publicPluginCatalogInfo(versionPlugin);
    const versionReview = marketplacePluginReviewInfo(versionPlugin, pluginReviewForDisplay(store, versionPlugin));
    return [{ version, compatibleCore: pluginCoreCompatibilityInfo(versionPlugin), permissions: [...versionPlugin.permissions], permissionReview: publicVersion.permissionReview, trust: publicVersion.trust, source: publicVersion.source, marketplaceReview: { installable: versionReview.installable, status: versionReview.review.status, ...(versionReview.installBlock ? { installBlock: versionReview.installBlock } : {}) }, ...(compatibilityBlock ? { compatibilityBlock } : {}) }];
  });
  return { ...publicPluginCatalogInfo(displayPlugin), distribution: { availableVersions: [...plugin.distribution.availableVersions], latestVersion: plugin.distribution.latestVersion }, installed: Boolean(grant), grantedPermissions: grant?.permissions ?? [], missingPermissions: displayPlugin.permissions.filter((permission) => !grant?.permissions.includes(permission)), installedVersion, updateAvailable: Boolean(grant && installedVersion && installedVersion !== latestVersion), rollbackVersions: grant ? availableVersions.filter((version) => version !== installedVersion) : [], marketplaceReview: marketplacePluginReviewInfo(displayPlugin, pluginReviewForDisplay(store, displayPlugin)), compatibleCore: pluginCoreCompatibilityInfo(displayPlugin), ...(pluginCoreCompatibilityBlock(displayPlugin) ? { compatibilityBlock: pluginCoreCompatibilityBlock(displayPlugin) } : {}), versionCompatibility, audit: pluginCampaignAuditSummary(store, campaignId, plugin.id) };
}

function reviewedPluginPermissions(plugin: LoadedPlugin, requestedPermissions?: PermissionName[]): PermissionName[] | undefined {
  if (!requestedPermissions) return [...plugin.permissions];
  const uniquePermissions = [...new Set(requestedPermissions)];
  if (uniquePermissions.some((permission) => !plugin.permissions.includes(permission))) return undefined;
  return uniquePermissions;
}

function pluginInstallMetadata(plugin: LoadedPlugin): Record<string, unknown> {
  return { packageId: plugin.source.packageId, version: plugin.version, checksum: pluginPackageIdentityChecksum(plugin), manifestChecksum: plugin.source.manifestChecksum, runtimeChecksum: plugin.source.checksum, trust: publicPluginTrustInfo(plugin), installedAt: nowIso() };
}

function configuredPluginRegistryUrls(): string[] {
  const urls = (process.env.OTTE_PLUGIN_REGISTRY_URLS ?? "")
    .split(",")
    .map((entry) => normalizeConfiguredPluginRegistryUrl(entry))
    .filter((entry): entry is string => Boolean(entry));
  return [...new Set(urls)];
}

function normalizeConfiguredPluginRegistryUrl(value: string): string | undefined {
  const trimmed = value.trim();
  if (!trimmed) return undefined;
  try {
    const url = new URL(trimmed);
    if (url.protocol !== "http:" && url.protocol !== "https:") return undefined;
    return url.toString();
  } catch {
    return undefined;
  }
}

function pluginVersionFromGrant(grant: PermissionGrant | undefined): string | undefined {
  const metadata = grant?.metadata;
  if (!isRecord(metadata)) return undefined;
  return typeof metadata.version === "string" ? metadata.version : undefined;
}

function pluginGrantIdentityBlock(grant: PermissionGrant | undefined, plugin: LoadedPlugin): string | undefined {
  if (!grant) return undefined;
  const metadata = grant.metadata;
  const installedPackageId = isRecord(metadata) && typeof metadata.packageId === "string" ? metadata.packageId : undefined;
  const installedVersion = isRecord(metadata) && typeof metadata.version === "string" ? metadata.version : undefined;
  const installedChecksum = isRecord(metadata) && typeof metadata.checksum === "string" ? metadata.checksum : undefined;
  if (installedPackageId === plugin.source.packageId && installedVersion === plugin.version && installedChecksum !== undefined && installedChecksum === pluginPackageIdentityChecksum(plugin)) {
    return undefined;
  }
  return `Installed plugin ${plugin.id} package identity no longer matches the reviewed grant; reinstall the intended package before execution`;
}

function pluginTrustErrorMessage(plugin: LoadedPlugin): string {
  const reason = plugin.trust.errors.length ? plugin.trust.errors.join("; ") : `Plugin trust status is ${plugin.trust.status}`;
  return `Plugin ${plugin.id} is not installable under the current trust policy: ${reason}`;
}

function findSystemActor(store: StateStore, campaignId: string, systemId: string, actorId: string): Actor | undefined {
  return store.state.actors.find((actor) => actor.id === actorId && actor.campaignId === campaignId && actor.systemId === systemId);
}

function hasSystemRuntimeCapability(systemId: string, capability: SystemCapability): boolean {
  return systemRuntimeCapabilities(systemId).includes(capability);
}

function assertSystemRuntimeCapability(systemId: string, capability: SystemCapability): void {
  if (!hasSystemRuntimeCapability(systemId, capability)) throw new UnsupportedSystemCapabilityError(systemId, capability);
}

function systemRuntimeInfo(store: { state: Pick<EngineState, "systemInstallations"> }, system: SystemManifest, active = false) {
  const installation = systemInstallationByManifestId(store.state, system.id);
  const runtimeCapabilities = systemRuntimeCapabilities(system.id);
  return { ...system, active, source: isBundledSystem(system.id) ? ("bundled" as const) : ("api" as const), dataDriven: !isBundledSystem(system.id), runtimeCapabilities, unsupportedCapabilities: system.capabilities.filter((capability) => !runtimeCapabilities.includes(capability)), installedAt: installation?.createdAt };
}

function buildCampaignCompatibilityReport(store: StateStore, campaign: Campaign): CampaignCompatibilityReport {
  const actors = store.state.actors.filter((actor) => actor.campaignId === campaign.id).sort((left, right) => left.id.localeCompare(right.id));
  const items = store.state.items.filter((item) => item.campaignId === campaign.id).sort((left, right) => left.id.localeCompare(right.id));
  const actorById = new Map(actors.map((actor) => [actor.id, actor]));
  const manifests = registeredSystems(store.state);
  const manifestById = new Map(manifests.map((manifest) => [manifest.id, manifest]));
  const referencedSystemIds = new Set<string>([campaign.defaultSystemId, ...actors.map((actor) => actor.systemId), ...items.map((item) => item.systemId)].filter(Boolean));
  const issues: CampaignCompatibilityIssue[] = [];
  const pushIssue = (issue: Omit<CampaignCompatibilityIssue, "id">) => {
    const digest = createHash("sha256")
      .update(`${issue.group}:${issue.code}:${issue.entityType ?? ""}:${issue.entityId ?? ""}:${issue.detail}`)
      .digest("hex")
      .slice(0, 12);
    issues.push({ id: `compat-${issue.group}-${digest}`, ...issue });
  };
  const countValues = (values: string[]): Record<string, number> =>
    values
      .sort((left, right) => left.localeCompare(right))
      .reduce<Record<string, number>>((counts, value) => {
        counts[value] = (counts[value] ?? 0) + 1;
        return counts;
      }, {});
  const objectValue = (value: unknown): Record<string, unknown> => (isRecord(value) ? value : {});

  const systems = [...referencedSystemIds]
    .sort((left, right) => left.localeCompare(right))
    .map((systemId) => {
      const manifest = manifestById.get(systemId);
      const compatibility = manifest ? systemCoreCompatibility(manifest.compatibleCore, OPEN_TABLETOP_CORE_VERSION) : { valid: false, satisfied: false };
      const systemActors = actors.filter((actor) => actor.systemId === systemId);
      const systemItems = items.filter((item) => item.systemId === systemId);
      if (!manifest) {
        pushIssue({ group: "system", severity: "blocking", code: "system.missing", title: "Referenced rules system is missing", detail: `Campaign records reference ${systemId}, but no registered system manifest is available.`, action: "Install a compatible data-model system package or restore the expected bundled system before using those records.", entityType: "system", entityId: systemId });
      } else if (!compatibility.valid || !compatibility.satisfied) {
        pushIssue({ group: "system", severity: "blocking", code: compatibility.valid ? "system.core_incompatible" : "system.core_range_invalid", title: "Rules system is incompatible with this core", detail: `${manifest.name} ${manifest.version} requires core ${manifest.compatibleCore}; this server is ${OPEN_TABLETOP_CORE_VERSION}.`, action: "Install a compatible system version. This report will not migrate or discard system data.", entityType: "system", entityId: systemId });
      }
      return { systemId, ...(manifest ? { name: manifest.name, installedVersion: manifest.version, compatibleCore: manifest.compatibleCore } : {}), coreCompatible: compatibility.valid && compatibility.satisfied, bundled: isBundledSystem(systemId), default: campaign.defaultSystemId === systemId, actorCount: systemActors.length, itemCount: systemItems.length, actorRulesVersions: countValues(systemActors.map((actor) => stringValue(actor.data.ruleset) ?? "unversioned")), itemContentVersions: countValues(systemItems.map((item) => stringValue(objectValue(item.data.compendiumProvenance).contentVersion) ?? "unversioned")) };
    });

  for (const item of items) {
    if (!item.actorId) continue;
    const actor = actorById.get(item.actorId);
    if (!actor) {
      pushIssue({ group: "reference", severity: "blocking", code: "reference.actor_missing", title: "Item references a missing actor", detail: `Item ${item.id} references actor ${item.actorId}, which is not present in this campaign.`, action: "Restore the referenced actor or explicitly reassign the item after review.", entityType: "item", entityId: item.id });
    } else if (actor.systemId !== item.systemId) {
      pushIssue({ group: "reference", severity: "blocking", code: "reference.system_mismatch", title: "Actor and item systems differ", detail: `Item ${item.id} uses ${item.systemId}, while its actor uses ${actor.systemId}.`, action: "Review the original source and correct the reference without dropping unknown fields.", entityType: "item", entityId: item.id });
    }
  }

  const dndActors = actors.filter((actor) => actor.systemId === DND_5E_SRD_SYSTEM_ID);
  const dndItems = items.filter((item) => item.systemId === DND_5E_SRD_SYSTEM_ID);
  const validationReports = [...dndActors.map((actor) => validateDnd5eSrdActor(actor)), ...dndItems.map((item) => validateDnd5eSrdItem(item))];
  const repairPreviews = [...dndActors.map((actor) => previewDnd5eSrdActorRepairs(actor)), ...dndItems.map((item) => previewDnd5eSrdItemRepairs(item))];
  const repairCandidates = repairPreviews.flatMap((preview) => preview.candidates.map((candidate) => ({ id: candidate.id, entityKind: candidate.entityKind, entityId: candidate.entityId, path: candidate.path, operation: candidate.operation, ...(candidate.before === undefined ? {} : { before: candidate.before }), after: candidate.after, issue: { severity: candidate.issue.severity, code: candidate.issue.code, message: candidate.issue.message }, rationale: candidate.rationale, inverse: { operation: candidate.inverse.operation, path: candidate.inverse.path, ...(candidate.inverse.before === undefined ? {} : { before: candidate.inverse.before }), ...(candidate.inverse.after === undefined ? {} : { after: candidate.inverse.after }) } })));
  let validationErrors = 0;
  let validationWarnings = 0;
  for (const report of validationReports) {
    for (const validationIssue of report.issues) {
      if (validationIssue.severity === "error") validationErrors += 1;
      else validationWarnings += 1;
      pushIssue({ group: "validation", severity: validationIssue.severity === "error" ? "blocking" : "warning", code: validationIssue.code, title: `D&D ${report.entityKind} validation ${validationIssue.severity}`, detail: `${validationIssue.path || "/"}: ${validationIssue.message}`, action: validationIssue.severity === "error" ? "Review this field before relying on automated D&D actions or previews." : "Review the preserved value; the report does not rewrite homebrew or legacy data.", entityType: report.entityKind, entityId: report.entityId });
    }
  }

  const calculationFlags = { manualFields: 0, overrideFields: 0, unsupportedFields: 0, ambiguousFields: 0 };
  for (const actor of dndActors) {
    try {
      const explanation = dnd5eSrdCalculationExplanation(
        actor,
        items.filter((item) => item.actorId === actor.id),
      );
      for (const field of explanation.fields) {
        if (field.flags.manual) calculationFlags.manualFields += 1;
        if (field.flags.override) calculationFlags.overrideFields += 1;
        if (field.flags.unsupported) calculationFlags.unsupportedFields += 1;
        if (field.flags.ambiguous) calculationFlags.ambiguousFields += 1;
        if (!field.flags.manual && !field.flags.override && !field.flags.unsupported && !field.flags.ambiguous) continue;
        const code = field.flags.unsupported ? "calculation.unsupported" : field.flags.manual ? "calculation.manual" : field.flags.override ? "calculation.override" : "calculation.ambiguous";
        pushIssue({ group: "manual", severity: "warning", code, title: `${field.label} needs review`, detail: field.flags.reasons.join(" ") || "The calculation carries a manual, override, unsupported, or ambiguous flag.", action: "Open the actor calculation explanation and review the ordered source terms. No value is changed by this report.", entityType: "actor", entityId: actor.id });
      }
    } catch {
      calculationFlags.unsupportedFields += 1;
      pushIssue({ group: "manual", severity: "warning", code: "calculation.unavailable", title: "Calculation explanation is unavailable", detail: `Actor ${actor.id} could not be explained using the current D&D helper.`, action: "Review the actor validation issues and preserved legacy fields before using automated calculations.", entityType: "actor", entityId: actor.id });
    }
  }

  const compendium = { trackedEntries: 0, currentEntries: 0, driftedEntries: 0, missingProvenance: 0, unknownEntries: 0 };
  const inspectCompendiumReference = (entityType: "item" | "condition", entityId: string, systemId: string, entryId: string, rawProvenance: unknown) => {
    compendium.trackedEntries += 1;
    const provenance = compendiumProvenanceFromValue(rawProvenance, systemId);
    if (!provenance) {
      compendium.missingProvenance += 1;
      pushIssue({ group: "compendium", severity: "warning", code: "compendium.provenance_missing", title: "Compendium provenance is missing", detail: `${entityType} ${entityId} references ${entryId} without complete source/version/license provenance.`, action: "Review the source manually. Do not infer or overwrite provenance without evidence.", entityType, entityId });
      return;
    }
    if (provenance.sourceKind === "user") {
      compendium.currentEntries += 1;
      return;
    }
    const current = isBundledSystem(systemId) ? compendiumEntryForSystem(systemId, entryId) : undefined;
    if (!current) {
      compendium.unknownEntries += 1;
      pushIssue({ group: "compendium", severity: "warning", code: "compendium.entry_unknown", title: "Compendium source entry is unavailable", detail: `${entryId} from ${provenance.sourceName} ${provenance.contentVersion} is not present in the installed ${systemId} catalog.`, action: "Install the matching open-content system version or keep the preserved campaign copy for manual review.", entityType, entityId });
      return;
    }
    if (current.provenance.contentVersion !== provenance.contentVersion) {
      compendium.driftedEntries += 1;
      pushIssue({ group: "compendium", severity: "warning", code: "compendium.version_drift", title: "Compendium content version differs", detail: `${entryId} stores ${provenance.contentVersion}; the installed catalog provides ${current.provenance.contentVersion}.`, action: "Use the explicit compendium keep or replace flow after reviewing the versioned source.", entityType, entityId });
      return;
    }
    compendium.currentEntries += 1;
  };
  for (const item of items) {
    const entryId = stringValue(item.data.compendiumId);
    if (entryId) inspectCompendiumReference("item", item.id, item.systemId, entryId, item.data.compendiumProvenance);
  }
  for (const actor of dndActors) {
    const conditionProvenance = objectValue(actor.data.compendiumConditionProvenance);
    const conditionIds = Array.isArray(actor.data.conditions) ? actor.data.conditions.flatMap((condition) => (typeof condition === "string" ? [condition] : isRecord(condition) && typeof condition.id === "string" ? [condition.id] : [])) : [];
    for (const conditionId of [...new Set(conditionIds)].sort((left, right) => left.localeCompare(right))) {
      if (dnd5eSrdCompendiumEntry(conditionId)?.type === "condition") {
        inspectCompendiumReference("condition", `${actor.id}:${conditionId}`, actor.systemId, conditionId, conditionProvenance[conditionId]);
      }
    }
  }

  const orderedIssues = orderCampaignCompatibilityIssues(issues);
  const compatibleChecks = 3 + systems.filter((system) => system.coreCompatible).length + validationReports.filter((report) => report.valid).length + compendium.currentEntries;
  const { status, ...summary } = summarizeCampaignCompatibility(orderedIssues, compatibleChecks);
  return {
    campaignId: campaign.id,
    readOnly: true,
    status,
    summary,
    platform: { coreVersion: OPEN_TABLETOP_CORE_VERSION, currentArchiveVersion: CURRENT_CAMPAIGN_ARCHIVE_VERSION, supportedArchiveVersions: [...SUPPORTED_CAMPAIGN_ARCHIVE_VERSIONS], dndRulesVersion: DND_5E_SRD_VERSION, dndActorSchemaVersion: DND_5E_SRD_ACTOR_SCHEMA_VERSION, dndItemSchemaVersion: DND_5E_SRD_ITEM_SCHEMA_VERSION },
    systems,
    validation: { actorReports: dndActors.length, itemReports: dndItems.length, errors: validationErrors, warnings: validationWarnings, repairPreview: { automaticChanges: repairCandidates.length, manualIssues: repairPreviews.reduce((total, preview) => total + preview.manualIssues.length, 0) + calculationFlags.manualFields + calculationFlags.unsupportedFields + calculationFlags.ambiguousFields, note: "Read-only repair candidates require explicit confirmation and include exact inverse patches. Intent-sensitive and unknown/homebrew data is never rewritten.", candidates: repairCandidates } },
    compendium,
    calculationFlags,
    issues: orderedIssues,
  };
}

function systemRequirementsForCampaign(store: StateStore, campaignId: string) {
  const campaign = store.state.campaigns.find((item) => item.id === campaignId);
  const ids = new Set<string>();
  if (campaign?.defaultSystemId) ids.add(campaign.defaultSystemId);
  for (const actor of store.state.actors) if (actor.campaignId === campaignId) ids.add(actor.systemId);
  for (const item of store.state.items) if (item.campaignId === campaignId) ids.add(item.systemId);
  return registeredSystems(store.state)
    .filter((system) => ids.has(system.id))
    .map(({ id, name, version, compatibleCore, capabilities }) => ({ id, name, version, compatibleCore, capabilities }))
    .sort((left, right) => left.id.localeCompare(right.id));
}

function compendiumEntriesForSystem(systemId: string) {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdCompendium();
  if (systemId === "generic-fantasy") return genericFantasyCompendium();
  if (systemId === "stellar-frontiers") return stellarFrontiersCompendium();
  if (systemId === "mystic-noir") return mysticNoirCompendium();
  assertSystemRuntimeCapability(systemId, "compendium");
  return [];
}

function compendiumEntryForSystem(systemId: string, entryId: string) {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdCompendiumEntry(entryId);
  if (systemId === "generic-fantasy") return genericFantasyCompendiumEntry(entryId);
  if (systemId === "stellar-frontiers") return stellarFrontiersCompendiumEntry(entryId);
  if (systemId === "mystic-noir") return mysticNoirCompendiumEntry(entryId);
  assertSystemRuntimeCapability(systemId, "compendium");
  return undefined;
}

function compendiumProvenanceFromValue(value: unknown, systemId: string): CompendiumProvenance | undefined {
  if (!isRecord(value)) return undefined;
  const sourceKind = value.sourceKind;
  if (sourceKind !== "srd" && sourceKind !== "bundled" && sourceKind !== "user") return undefined;
  const sourceName = normalizeNonEmptyString(value.sourceName);
  const sourceVersion = normalizeNonEmptyString(value.sourceVersion);
  const contentVersion = normalizeNonEmptyString(value.contentVersion);
  const provenanceSystemId = normalizeNonEmptyString(value.systemId);
  const systemVersion = normalizeNonEmptyString(value.systemVersion);
  const rulesVersion = normalizeNonEmptyString(value.rulesVersion);
  if (!sourceName || !sourceVersion || !contentVersion || provenanceSystemId !== systemId || !systemVersion || !rulesVersion) return undefined;
  if (!isRecord(value.license)) return undefined;
  const licenseName = normalizeNonEmptyString(value.license.name);
  const usage = value.license.usage;
  if (!licenseName || (usage !== "srd" && usage !== "open" && usage !== "user_provided" && usage !== "private_home_game")) return undefined;
  const licenseUrl = value.license.url === undefined ? undefined : normalizeNonEmptyString(value.license.url);
  const attribution = value.license.attribution === undefined ? undefined : normalizeNonEmptyString(value.license.attribution);
  if ((value.license.url !== undefined && !licenseUrl) || (value.license.attribution !== undefined && !attribution)) return undefined;
  return { sourceKind, sourceName, sourceVersion, contentVersion, systemId, systemVersion, rulesVersion, license: { name: licenseName, usage, ...(licenseUrl ? { url: licenseUrl } : {}), ...(attribution ? { attribution } : {}) } };
}

function cloneCompendiumProvenance(provenance: CompendiumProvenance): CompendiumProvenance {
  return { ...provenance, license: { ...provenance.license } };
}

function campaignHomebrewCompendiumEntries(store: StateStore, campaignId: string, systemId: string): CompendiumCatalogEntry[] {
  return store.state.items.flatMap((item) => {
    if (item.campaignId !== campaignId || item.systemId !== systemId || item.actorId !== undefined) return [];
    const provenance = compendiumProvenanceFromValue(item.data.compendiumProvenance, systemId);
    if (!provenance || provenance.sourceKind !== "user") return [];
    const data = cloneRecord(item.data);
    delete data.compendiumProvenance;
    const summary = normalizeNonEmptyString(data.summary) ?? `Campaign-owned ${item.type} with user-supplied provenance.`;
    return [{ id: `campaign-item:${item.id}`, type: item.type, name: item.name, summary, data, provenance: cloneCompendiumProvenance(provenance) }];
  });
}

function isDndCustomContentItem(item: Item, campaignId: string): boolean {
  if (item.campaignId !== campaignId || item.systemId !== DND_5E_SRD_SYSTEM_ID || item.actorId !== undefined) return false;
  if (!DND_CUSTOM_CONTENT_KINDS.includes(item.type as (typeof DND_CUSTOM_CONTENT_KINDS)[number])) return false;
  if (item.data.customContentKind !== item.type || item.data.builderSchemaVersion !== "1.0.0") return false;
  const provenance = compendiumProvenanceFromValue(item.data.compendiumProvenance, item.systemId);
  return provenance?.sourceKind === "user";
}

function dndCustomContentPayload(item: Item) {
  const provenance = compendiumProvenanceFromValue(item.data.compendiumProvenance, item.systemId)!;
  const data = cloneRecord(item.data);
  delete data.compendiumProvenance;
  const summary = normalizeNonEmptyString(data.summary) ?? `Campaign-owned ${item.type}.`;
  const draftData = cloneRecord(data);
  delete draftData.summary;
  delete draftData.customContentKind;
  delete draftData.builderSchemaVersion;
  delete draftData.monsterVariant;
  return { item: { ...item, data: cloneRecord(item.data) }, entry: { id: `campaign-item:${item.id}`, type: item.type, name: item.name, summary, data, provenance: cloneCompendiumProvenance(provenance) } satisfies CompendiumCatalogEntry, draft: { kind: item.type, name: item.name, summary, sourceName: provenance.sourceName, sourceVersion: provenance.sourceVersion, contentVersion: provenance.contentVersion, license: { ...provenance.license }, data: draftData } };
}

function dndCustomContentAuditSummary(item: Item): Record<string, unknown> {
  const provenance = compendiumProvenanceFromValue(item.data.compendiumProvenance, item.systemId);
  return { kind: item.type, name: item.name, updatedAt: item.updatedAt, contentVersion: provenance?.contentVersion, sourceName: provenance?.sourceName, licenseUsage: provenance?.license.usage };
}

function campaignCompendiumEntries(store: StateStore, campaignId: string, systemId: string, includeCampaignHomebrew = false): CompendiumCatalogEntry[] {
  const bundled = hasSystemRuntimeCapability(systemId, "compendium") ? compendiumEntriesForSystem(systemId) : [];
  const homebrew = includeCampaignHomebrew ? campaignHomebrewCompendiumEntries(store, campaignId, systemId) : [];
  return [...bundled, ...homebrew].map((entry) => ({ ...entry, data: cloneRecord(entry.data), provenance: cloneCompendiumProvenance(entry.provenance) })).sort((left, right) => left.name.localeCompare(right.name) || left.id.localeCompare(right.id));
}

function filteredCampaignCompendiumEntries(entries: CompendiumCatalogEntry[], query: { q?: string; type?: string; types?: string }): CompendiumCatalogEntry[] {
  const search = query.q?.trim().toLocaleLowerCase().slice(0, 160) ?? "";
  const requestedTypes = new Set(
    [query.type, query.types]
      .flatMap((value) => value?.split(",") ?? [])
      .map((value) => value.trim().toLocaleLowerCase())
      .filter(Boolean),
  );
  return entries.filter((entry) => {
    if (requestedTypes.size > 0 && !requestedTypes.has(entry.type.toLocaleLowerCase())) return false;
    if (!search) return true;
    return `${entry.name} ${entry.summary} ${entry.type} ${entry.provenance.sourceName}`.toLocaleLowerCase().includes(search);
  });
}

function compendiumProvenanceSummary(allEntries: CompendiumCatalogEntry[], filteredEntries: CompendiumCatalogEntry[]): CompendiumProvenanceSummary {
  const types: Record<string, number> = {};
  for (const entry of allEntries) types[entry.type] = (types[entry.type] ?? 0) + 1;
  const sources = new Map<string, CompendiumProvenanceSummary["sources"][number]>();
  for (const entry of filteredEntries) {
    const provenance = entry.provenance;
    const key = stableJson([provenance.sourceKind, provenance.sourceName, provenance.sourceVersion, provenance.contentVersion, provenance.license]);
    const existing = sources.get(key);
    if (existing) existing.entryCount += 1;
    else {
      sources.set(key, { sourceKind: provenance.sourceKind, sourceName: provenance.sourceName, sourceVersion: provenance.sourceVersion, contentVersion: provenance.contentVersion, license: { ...provenance.license }, entryCount: 1 });
    }
  }
  return { totalEntries: allEntries.length, filteredEntries: filteredEntries.length, types: Object.fromEntries(Object.entries(types).sort(([left], [right]) => left.localeCompare(right))), sources: [...sources.values()].sort((left, right) => left.sourceName.localeCompare(right.sourceName) || left.contentVersion.localeCompare(right.contentVersion)) };
}

function campaignCompendiumEntry(store: StateStore, campaignId: string, systemId: string, entryId: string, includeCampaignHomebrew = false): CompendiumCatalogEntry | undefined {
  return campaignCompendiumEntries(store, campaignId, systemId, includeCampaignHomebrew).find((entry) => entry.id === entryId);
}

function isGenericFantasyCompendiumCatalogEntry(entry: CompendiumCatalogEntry): entry is GenericFantasyCompendiumEntry {
  return entry.type === "item" || entry.type === "spell" || entry.type === "condition";
}

function compendiumConflictChoice(value: unknown): CompendiumConflictChoice | undefined {
  return value === "keep_existing" || value === "replace_existing" || value === "merge_existing" ? value : undefined;
}

function actorCompendiumItem(store: StateStore, actor: Actor, entryId: string): Item | undefined {
  return actorItems(store, actor).find((item) => item.data.compendiumId === entryId);
}

function compendiumItemConflict(item: Item, entry: CompendiumCatalogEntry, choices: CompendiumConflictChoice[]): CompendiumConflict {
  const existingProvenance = compendiumProvenanceFromValue(item.data.compendiumProvenance, item.systemId);
  const existingVersion = existingProvenance?.contentVersion;
  return { kind: existingVersion === entry.provenance.contentVersion ? "exact_duplicate" : "version_conflict", entryId: entry.id, requestedVersion: entry.provenance.contentVersion, ...(existingVersion ? { existingVersion } : {}), existingItemId: item.id, choices };
}

function actorHasCompendiumCondition(actor: Actor, conditionId: string): boolean {
  if (!Array.isArray(actor.data.conditions)) return false;
  return actor.data.conditions.some((condition) => condition === conditionId || (isRecord(condition) && condition.id === conditionId));
}

function actorConditionProvenance(actor: Actor, conditionId: string): CompendiumProvenance | undefined {
  const records = isRecord(actor.data.compendiumConditionProvenance) ? actor.data.compendiumConditionProvenance : {};
  return compendiumProvenanceFromValue(records[conditionId], actor.systemId);
}

function withActorConditionProvenance(data: Record<string, unknown>, entry: CompendiumCatalogEntry): Record<string, unknown> {
  const records = isRecord(data.compendiumConditionProvenance) ? cloneRecord(data.compendiumConditionProvenance) : {};
  records[entry.id] = cloneCompendiumProvenance(entry.provenance);
  return { ...data, compendiumConditionProvenance: records };
}

function compendiumItemData(entry: CompendiumCatalogEntry, existing?: Item, overrides: Record<string, unknown> = {}): Record<string, unknown> {
  const preservedKeys = ["quantity", "equipped", "attuned", "prepared", "uses", "charges", "purchasedForGp"] as const;
  const preserved = existing ? Object.fromEntries(preservedKeys.flatMap((key) => (existing.data[key] === undefined ? [] : [[key, existing.data[key]]]))) : {};
  return { ...cloneRecord(entry.data), ...preserved, ...overrides, compendiumId: entry.id, compendiumProvenance: cloneCompendiumProvenance(entry.provenance) };
}

function characterTemplatesForSystem(systemId: string): CharacterTemplate[] {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdCharacterTemplates();
  if (systemId === "generic-fantasy") return genericFantasyCharacterTemplates();
  if (systemId === "stellar-frontiers") return stellarFrontiersCharacterTemplates();
  if (systemId === "mystic-noir") return mysticNoirCharacterTemplates();
  assertSystemRuntimeCapability(systemId, "character-templates");
  return [];
}

function createTemplateItems(campaignId: string, actor: Actor, template: CharacterTemplate): Item[] {
  return template.items.flatMap((templateItem) => {
    const entry = compendiumEntryForSystem(template.systemId, templateItem.entryId);
    if (!entry || entry.type === "condition") return [];
    return [createTimestamped("itm", { campaignId, systemId: template.systemId, actorId: actor.id, type: entry.type, name: entry.name, data: { ...cloneRecord(entry.data), ...(templateItem.data ? cloneRecord(templateItem.data) : {}), compendiumId: entry.id, quantity: templateItem.quantity ?? 1 } }) satisfies Item];
  });
}

function characterImportForSystem(systemId: string, input: CharacterImportInput): CharacterImportResult {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdCharacterImport(input);
  if (systemId === "generic-fantasy") return genericFantasyCharacterImport(input);
  if (systemId === "stellar-frontiers") return stellarFrontiersCharacterImport(input);
  if (systemId === "mystic-noir") return mysticNoirCharacterImport(input);
  assertSystemRuntimeCapability(systemId, "character-import");
  throw new UnsupportedSystemCapabilityError(systemId, "character-import");
}

function createImportedItems(campaignId: string, actor: Actor, imported: CharacterImportResult): Item[] {
  return imported.items.flatMap((importedItem) => {
    const entry = compendiumEntryForSystem(imported.systemId, importedItem.entryId);
    if (!entry || entry.type === "condition") return [];
    return [createTimestamped("itm", { campaignId, systemId: imported.systemId, actorId: actor.id, type: entry.type, name: entry.name, data: { ...cloneRecord(entry.data), ...(importedItem.data ? cloneRecord(importedItem.data) : {}), compendiumId: entry.id, quantity: importedItem.quantity ?? 1 } }) satisfies Item];
  });
}

function calculationOverrideContextForActor(store: StateStore, actor: Actor, items: Item[]): Dnd5eSrdCalculationOverrideContext | undefined {
  if (actor.systemId !== DND_5E_SRD_SYSTEM_ID) return undefined;
  const explanation = dnd5eSrdCalculationExplanation(actor, items);
  return buildDnd5eSrdCalculationOverrideContext(explanation, store.state.calculationOverrides.filter((entry) => entry.actorId === actor.id && entry.campaignId === actor.campaignId));
}

function systemSheet(actor: Actor, items: Item[], calculationContext?: Dnd5eSrdCalculationOverrideContext) {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) {
    const sheet = dnd5eSrdSheet(actor, items);
    return calculationContext ? applyDnd5eSrdCalculationOverridesToSheet(sheet, calculationContext) : sheet;
  }
  if (actor.systemId === "generic-fantasy") return genericFantasySheet(actor, items);
  if (actor.systemId === "stellar-frontiers") return stellarFrontiersSheet(actor, items);
  if (actor.systemId === "mystic-noir") return mysticNoirSheet(actor, items);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "actor-sheet");
}

function systemSheetForStore(store: StateStore, actor: Actor, items: Item[]) {
  return systemSheet(actor, items, calculationOverrideContextForActor(store, actor, items));
}

function systemQuickRolls(actor: Actor, items: Item[] = [], calculationContext?: Dnd5eSrdCalculationOverrideContext) {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) {
    const rolls = dnd5eSrdQuickRolls(actor, items);
    return calculationContext ? applyDnd5eSrdCalculationOverridesToRolls(rolls, calculationContext) : rolls;
  }
  if (actor.systemId === "generic-fantasy") return genericFantasyQuickRolls(actor, items);
  if (actor.systemId === "stellar-frontiers") return stellarFrontiersQuickRolls(actor, items);
  if (actor.systemId === "mystic-noir") return mysticNoirQuickRolls(actor, items);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "quick-rolls");
}

function systemActionOptions(spellSlotLevel: number | undefined, resourceAmount?: number, useFreeResource?: boolean): SystemActionUseOptions {
  return { spellSlotLevel, resourceAmount, useFreeResource };
}

function systemActionFormula(actor: Actor, items: Item[], rollId: string, options: SystemActionUseOptions, calculationContext?: Dnd5eSrdCalculationOverrideContext): string | undefined {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) {
    const override = dnd5eSrdFormulaOverride(calculationContext, rollId);
    return override ? dnd5eSrdSafeOverrideFormula(override.effectiveValue) : dnd5eSrdActionFormula(actor, items, rollId, options);
  }
  if (actor.systemId === "generic-fantasy") return genericFantasyActionFormula(actor, items, rollId, options);
  if (actor.systemId === "stellar-frontiers" || actor.systemId === "mystic-noir") return undefined;
  assertSystemRuntimeCapability(actor.systemId, "actions");
  return undefined;
}

function useSystemAction(actor: Actor, items: Item[], rollId: string, options: SystemActionUseOptions = {}): SystemActionUseResult {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return useDnd5eSrdAction(actor, items, rollId, options);
  if (actor.systemId === "generic-fantasy") return useGenericFantasyAction(actor, items, rollId, options);
  if (actor.systemId === "stellar-frontiers") return useStellarFrontiersAction(actor, items, rollId);
  if (actor.systemId === "mystic-noir") return useMysticNoirAction(actor, items, rollId);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "actions");
}

function applySystemCondition(actor: Actor, conditionId: string, appliedAt?: string, options: { level?: unknown; items?: Item[]; overrideReason?: string } = {}): Record<string, unknown> {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return applyDnd5eSrdCondition(actor, conditionId, appliedAt, options);
  if (actor.systemId === "generic-fantasy") return applyGenericFantasyCondition(actor, conditionId, appliedAt);
  if (actor.systemId === "stellar-frontiers") return applyStellarFrontiersCondition(actor, conditionId, appliedAt);
  if (actor.systemId === "mystic-noir") return applyMysticNoirCondition(actor, conditionId, appliedAt);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "conditions");
}

function removeSystemCondition(actor: Actor, conditionId: string): Record<string, unknown> {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return removeDnd5eSrdCondition(actor, conditionId);
  if (actor.systemId === "generic-fantasy") return removeGenericFantasyCondition(actor, conditionId);
  if (actor.systemId === "stellar-frontiers") return removeStellarFrontiersCondition(actor, conditionId);
  if (actor.systemId === "mystic-noir") return removeMysticNoirCondition(actor, conditionId);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "conditions");
}

function advancementOptionsForActor(actor: Actor) {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdAdvancementOptions(actor);
  if (actor.systemId === "generic-fantasy") return genericFantasyAdvancementOptions(actor);
  if (actor.systemId === "stellar-frontiers") return stellarFrontiersAdvancementOptions(actor);
  if (actor.systemId === "mystic-noir") return mysticNoirAdvancementOptions(actor);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "advancement");
}

function dnd5eSrdActorClassLevel(actor: Actor, className: string): number {
  if (Array.isArray(actor.data.classes)) {
    for (const value of actor.data.classes) {
      const entry = isRecord(value) ? value : {};
      const entryClassName = stringValue(entry.className) ?? stringValue(entry.class);
      if (entryClassName?.toLowerCase() !== className.toLowerCase()) continue;
      return Math.max(0, Math.floor(dnd5eSrdNumber(entry.level, 0)));
    }
  }
  return stringValue(actor.data.class)?.toLowerCase() === className.toLowerCase() ? Math.max(1, Math.floor(dnd5eSrdNumber(actor.data.level, 1))) : 0;
}

function dnd5eSrdAdvancementPath(actor: Actor, requestedClassName?: string): { className: string; nextClassLevel: number; grantsFeat: boolean } {
  const className = requestedClassName ?? dnd5eSrdAdvancementClassName(actor);
  const nextClassLevel = dnd5eSrdActorClassLevel(actor, className) + 1;
  return { className, nextClassLevel, grantsFeat: dnd5eSrdAdvancementFeatGrant(className, nextClassLevel, actor) !== undefined };
}

function dnd5eSrdStoredWeaponMasteryIds(actor: Actor, className: string): string[] {
  const ids = new Set<string>();
  const storedByClass = isRecord(actor.data.weaponMasteriesByClass) ? actor.data.weaponMasteriesByClass : {};
  const storedClassKey = Object.keys(storedByClass).find((candidate) => candidate.toLowerCase() === className.toLowerCase());
  const byClass = storedClassKey ? storedByClass[storedClassKey] : undefined;
  if (Array.isArray(byClass)) {
    for (const raw of byClass) {
      const weaponId = stringValue(isRecord(raw) ? raw.weaponId : undefined);
      if (weaponId) ids.add(weaponId);
    }
  }
  const primaryClass = stringValue(actor.data.class);
  if (Array.isArray(actor.data.weaponMasteries)) {
    for (const raw of actor.data.weaponMasteries) {
      const entry = isRecord(raw) ? raw : {};
      const entryClassName = stringValue(entry.className) ?? primaryClass;
      const weaponId = stringValue(entry.weaponId);
      if (weaponId && entryClassName?.toLowerCase() === className.toLowerCase()) ids.add(weaponId);
    }
  }
  return [...ids];
}

function dnd5eSrdAdvancementWeaponMasteryInfo(actor: Actor, className: string, nextClassLevel: number) {
  const requiredCount = dnd5eSrdWeaponMasteryChoiceCount(className, nextClassLevel);
  const priorCount = dnd5eSrdWeaponMasteryChoiceCount(className, nextClassLevel - 1);
  const selectedWeaponIds = dnd5eSrdStoredWeaponMasteryIds(actor, className);
  const requiresSelection = requiredCount > 0 && (requiredCount !== priorCount || new Set(selectedWeaponIds).size !== requiredCount);
  const options = dnd5eSrdWeaponMasteryEligibleWeaponIds(className).flatMap((id) => {
    const entry = dnd5eSrdCompendiumEntry(id);
    if (!entry) return [];
    return [{ id, name: entry.name, mastery: stringValue(entry.data.mastery) ?? "mastery" }];
  });
  return { className, nextClassLevel, requiredCount, requiresSelection, selectedWeaponIds, options };
}

function dnd5eSrdAdvancementFeatInfo(feat: ReturnType<typeof dnd5eSrdGeneralFeats>[number]) {
  const abilityPoints = Math.max(0, Math.floor(dnd5eSrdNumber(feat.data.abilityPoints, dnd5eSrdNumber(feat.data.abilityIncrease, 0))));
  const configuredChoices = stringArrayValue(feat.data.abilityChoices);
  return { id: feat.id, name: feat.name, category: feat.category, summary: feat.summary, abilityPoints, abilityChoices: abilityPoints > 0 && configuredChoices.length === 0 ? ["strength", "dexterity", "constitution", "intelligence", "wisdom", "charisma"] : configuredChoices, maximumScore: Math.max(1, Math.floor(dnd5eSrdNumber(feat.data.maximumScore, 20))) };
}

function dnd5eSrdNumber(value: unknown, fallback: number): number {
  return typeof value === "number" && Number.isFinite(value) ? value : fallback;
}

function applySystemAdvancement(actor: Actor, optionId: string): Record<string, unknown> {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return applyDnd5eSrdAdvancement(actor, optionId);
  if (actor.systemId === "generic-fantasy") return applyGenericFantasyAdvancement(actor, optionId);
  if (actor.systemId === "stellar-frontiers") return applyStellarFrontiersAdvancement(actor, optionId);
  if (actor.systemId === "mystic-noir") return applyMysticNoirAdvancement(actor, optionId);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "advancement");
}

function applySystemRest(actor: Actor, restType: SystemRestType, options: SystemRestOptions = {}): SystemRestResult {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return applyDnd5eSrdRest(actor, restType, options);
  if (actor.systemId === "generic-fantasy") return applyGenericFantasyRest(actor, restType);
  if (actor.systemId === "stellar-frontiers") return applyStellarFrontiersRest(actor, restType);
  if (actor.systemId === "mystic-noir") return applyMysticNoirRest(actor, restType);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "rest");
}

function dnd5eSrdServerRestHitDice(actor: Actor, selections: Array<{ className?: string }>): NonNullable<SystemRestOptions["hitDice"]> {
  if (!Array.isArray(selections) || selections.length > 20) throw new Error("A Short Rest can spend at most 20 Hit Dice at once");
  const storedPools = dnd5eSrdHitDicePools(actor);
  const primaryClassName = dnd5eSrdAdvancementClassName(actor);
  const aggregate = isRecord(actor.data.hitDice) ? actor.data.hitDice : {};
  const pools = storedPools.length > 0 ? storedPools : [{ className: primaryClassName, size: stringValue(aggregate.size) ?? dnd5eSrdClassHitDieSize(primaryClassName), current: Math.max(0, Math.floor(dnd5eSrdNumber(aggregate.current, dnd5eSrdNumber(aggregate.max, 0)))), max: Math.max(0, Math.floor(dnd5eSrdNumber(aggregate.max, 0))) }];
  const selectedCountByClass = new Map<string, number>();
  return selections.map((selection) => {
    if (!isRecord(selection)) throw new Error("Each Hit Die selection must be an object");
    const requestedClassName = typeof selection.className === "string" ? selection.className.trim() : "";
    if (pools.length > 1 && !requestedClassName) throw new Error("A className is required when spending a multiclass Hit Point Die");
    const pool = requestedClassName ? pools.find((candidate) => candidate.className.toLowerCase() === requestedClassName.toLowerCase()) : pools[0];
    if (!pool) throw new Error(`No Hit Point Dice pool exists for ${requestedClassName}`);
    const selectedCount = (selectedCountByClass.get(pool.className) ?? 0) + 1;
    if (selectedCount > pool.current) throw new Error(`${pool.className} has only ${pool.current} Hit Point Dice remaining`);
    selectedCountByClass.set(pool.className, selectedCount);
    return { className: pool.className, roll: rollFormula(`1${pool.size}`).total };
  });
}

function encounterThreatsForSystem(systemId: string) {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdEncounterThreats();
  if (systemId === "stellar-frontiers") return stellarFrontiersEncounterThreats();
  if (systemId === "mystic-noir") return mysticNoirEncounterThreats();
  if (systemId === "generic-fantasy") return genericFantasyEncounterThreats();
  assertSystemRuntimeCapability(systemId, "encounter-builder");
  return [];
}

function encounterPlanForSystem(systemId: string, party: Actor[], threats: EncounterThreatSelection[]): EncounterPlan {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdEncounterPlan(party, threats);
  if (systemId === "generic-fantasy") return genericFantasyEncounterPlan(party, threats);
  if (systemId === "stellar-frontiers") return stellarFrontiersEncounterPlan(party, threats);
  if (systemId === "mystic-noir") return mysticNoirEncounterPlan(party, threats);
  throw new UnsupportedSystemCapabilityError(systemId, "encounter-builder");
}

function partyActorsForSystem(store: StateStore, campaignId: string, systemId: string, actorIds?: string[]): Actor[] {
  const selectedIds = actorIds === undefined ? undefined : new Set(actorIds);
  return store.state.actors.filter((actor) => actor.campaignId === campaignId && actor.systemId === systemId && actor.type === "character" && (!selectedIds || selectedIds.has(actor.id)));
}

// JSON round-trip, not structuredClone: also canonicalizes (drops undefined members)
// so stored state stays byte-comparable with HTTP JSON bodies in stableJson diffs.
function cloneRecord(value: Record<string, unknown>): Record<string, unknown> {
  return JSON.parse(JSON.stringify(value)) as Record<string, unknown>;
}

function titleCase(value: string): string {
  return value.charAt(0).toUpperCase() + value.slice(1);
}

function actorItems(store: StateStore, actor: Actor): Item[] {
  return store.state.items.filter((item) => item.actorId === actor.id && item.campaignId === actor.campaignId);
}

function boundedDeathSaveCount(value: unknown): number {
  const parsed = Math.floor(Number(value ?? 0));
  if (!Number.isFinite(parsed)) return 0;
  return Math.max(0, Math.min(3, parsed));
}

function applyCombatantRulesAutomation(combatant: Combat["combatants"][number], options: { applyConcentrationLifecycle?: boolean } = {}): Combat["combatants"][number] {
  let deathSaveSuccesses = boundedDeathSaveCount(combatant.deathSaveSuccesses);
  let deathSaveFailures = boundedDeathSaveCount(combatant.deathSaveFailures);
  const reachedOutcome = deathSaveFailures >= 3 ? "dead" : deathSaveSuccesses >= 3 ? "stable" : undefined;
  const storedOutcome = combatant.deathSaveOutcome === "dead" || combatant.deathSaveOutcome === "stable" ? combatant.deathSaveOutcome : undefined;
  const deathSaveOutcome = reachedOutcome ?? (deathSaveSuccesses === 0 && deathSaveFailures === 0 ? storedOutcome : undefined);
  if (deathSaveOutcome === "stable") {
    deathSaveSuccesses = 0;
    deathSaveFailures = 0;
  }
  let conditions = normalizeCombatantConditionList(combatant.conditions).filter((condition) => condition !== "dead" && condition !== "stable");
  const hadConcentration = conditions.some(isCombatantConcentrationCondition);
  const concentrationBroken = options.applyConcentrationLifecycle !== false && hadConcentration && (deathSaveOutcome !== undefined || combatant.defeated === true || conditions.some(isCombatantConcentrationBreakingCondition));
  if (concentrationBroken) {
    conditions = conditions.filter((condition) => !isCombatantConcentrationCondition(condition));
    if (!conditions.includes("concentration lost")) conditions.push("concentration lost");
  }
  if (deathSaveOutcome === "dead") conditions.push("dead");
  if (deathSaveOutcome === "stable") conditions.push("stable");
  return { ...combatant, defeated: deathSaveOutcome === "dead" ? true : combatant.defeated, conditions, deathSaveSuccesses, deathSaveFailures, deathSaveOutcome };
}

function normalizeCombatantConditionList(conditions: string[] | undefined): string[] {
  return [...new Set((conditions ?? []).map((condition) => condition.trim().toLowerCase()).filter(Boolean))];
}

function combatantConditionBase(condition: string): string {
  return condition.split(":")[0]?.trim() ?? condition.trim();
}

function isCombatantConcentrationCondition(condition: string): boolean {
  const base = combatantConditionBase(condition);
  return base === "concentration" || base === "concentrating";
}

function isCombatantConcentrationBreakingCondition(condition: string): boolean {
  return ["incapacitated", "stunned", "unconscious", "paralyzed", "petrified", "dead"].includes(combatantConditionBase(condition));
}

function syncCombatantToActorSheet(actor: Actor, previousCombatant: Combat["combatants"][number], combatant: Combat["combatants"][number], syncedAt: string): { combatant: Combat["combatants"][number]; error?: string } {
  const data = cloneRecord(actor.data);
  const resourceResult = applyCombatantResourceUsage(data, previousCombatant, combatant);
  if (resourceResult.error) return { combatant, error: resourceResult.error };
  let synchronizedCombatant = combatant;
  let synchronizedData = data;
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) {
    const synchronization = synchronizeDnd5eSrdCombatantActorState({ ...actor, data }, combatant, syncedAt, previousCombatant);
    if (!synchronization.ok) return { combatant, error: synchronization.error };
    synchronizedCombatant = synchronization.combatant;
    synchronizedData = synchronization.actorData;
  } else {
    synchronizedData.conditions = (combatant.conditions ?? []).map((condition) => ({ id: condition, appliedAt: syncedAt }));
    synchronizedData.deathSaves = { successes: boundedDeathSaveCount(combatant.deathSaveSuccesses), failures: boundedDeathSaveCount(combatant.deathSaveFailures) };
  }
  synchronizedData.combatState = { combatantId: synchronizedCombatant.id, tokenId: synchronizedCombatant.tokenId, readiness: synchronizedCombatant.readiness ?? "normal", defeated: Boolean(synchronizedCombatant.defeated), deathSaveOutcome: synchronizedCombatant.deathSaveOutcome, resourceKey: synchronizedCombatant.resourceKey, resourceLabel: synchronizedCombatant.resourceLabel, resourceUsed: Boolean(synchronizedCombatant.resourceUsed), resourceSpent: resourceResult.spent, syncedAt };
  actor.data = synchronizedData;
  actor.updatedAt = syncedAt;
  return { combatant: synchronizedCombatant };
}

function applyCombatantResourceUsage(data: Record<string, unknown>, previousCombatant: Combat["combatants"][number], combatant: Combat["combatants"][number]): { spent: boolean; error?: string } {
  const resourceKey = typeof combatant.resourceKey === "string" ? combatant.resourceKey : undefined;
  if (!resourceKey || previousCombatant.resourceUsed === combatant.resourceUsed) return { spent: Boolean(combatant.resourceUsed) };
  const resources = isRecord(data.resources) ? { ...data.resources } : {};
  const currentResource = resources[resourceKey];
  if (combatant.resourceUsed) {
    const spent = spendActorResource(resources, resourceKey, currentResource);
    if (!spent) return { spent: false, error: `Resource unavailable: ${combatant.resourceLabel ?? resourceKey}` };
    data.resources = resources;
    combatant.resourceSpent = true;
    return { spent: true };
  }
  restoreActorResource(resources, resourceKey, currentResource);
  data.resources = resources;
  combatant.resourceSpent = false;
  return { spent: false };
}

function spendActorResource(resources: Record<string, unknown>, resourceKey: string, currentResource: unknown): boolean {
  if (typeof currentResource === "number") {
    if (currentResource <= 0) return false;
    resources[resourceKey] = currentResource - 1;
    return true;
  }
  if (!isRecord(currentResource)) return false;
  const current = Number(currentResource.current ?? 0);
  if (!Number.isFinite(current) || current <= 0) return false;
  resources[resourceKey] = { ...currentResource, current: current - 1 };
  return true;
}

function restoreActorResource(resources: Record<string, unknown>, resourceKey: string, currentResource: unknown): void {
  if (typeof currentResource === "number") {
    resources[resourceKey] = currentResource + 1;
    return;
  }
  if (!isRecord(currentResource)) return;
  const current = Number(currentResource.current ?? 0);
  const max = Number(currentResource.max ?? Number.POSITIVE_INFINITY);
  const nextCurrent = Number.isFinite(max) ? Math.min(max, current + 1) : current + 1;
  resources[resourceKey] = { ...currentResource, current: nextCurrent };
}

function canUpdateActorForUser(store: StateStore, userId: string, actor: Actor): boolean {
  return canCampaign(store, userId, actor.campaignId, "actor.update") || (actor.ownerUserId === userId && canCampaign(store, userId, actor.campaignId, "actor.updateOwned"));
}

function broadcastActorUpdated(broadcast: (event: EngineEvent) => void, actor: Actor): void {
  broadcast(createEvent({ campaignId: actor.campaignId, type: "actor.updated", targetId: actor.id, payload: actor }));
}

function truthyQuery(value: string | undefined): boolean {
  return value === "1" || value === "true" || value === "yes";
}

function normalizeAssetMimeType(value: string | string[] | undefined): string {
  const contentType = Array.isArray(value) ? value[0] : value;
  const mimeType = contentType?.split(";")[0]?.trim().toLowerCase();
  return mimeType && mimeType.length > 0 ? mimeType : "application/octet-stream";
}

function reusableUploadedAsset(store: StateStore, campaignId: string, checksum: string, sizeBytes: number, mimeType: string): MapAsset | undefined {
  return store.state.assets.find((asset) => asset.campaignId === campaignId && asset.checksum === checksum && asset.sizeBytes === sizeBytes && asset.mimeType === mimeType && asset.lifecycle?.status !== "archived" && asset.lifecycle?.status !== "deleted" && asset.security?.status === "clean" && Boolean(asset.storage) && isAssetDeliverable(asset));
}

async function storeAssetRenditions(storage: AssetStorage, asset: MapAsset, renditions: BuiltAssetRendition[]): Promise<{ renditions: NonNullable<MapAsset["renditions"]>; warnings: AssetRenditionBuildWarning[] }> {
  const stored: NonNullable<MapAsset["renditions"]> = [];
  const warnings: AssetRenditionBuildWarning[] = [];
  for (const rendition of renditions) {
    const storageAsset = assetRecordForRendition(asset, rendition);
    try {
      const storageRef = await storage.put(storageAsset, rendition.body);
      stored.push({ kind: rendition.kind, mimeType: rendition.mimeType, sizeBytes: rendition.sizeBytes, checksum: rendition.checksum, width: rendition.width, height: rendition.height, storage: storageRef, createdAt: nowIso() });
    } catch {
      warnings.push({ code: "rendition_failed", message: `${rendition.kind} storage failed. The authoritative original remains available.` });
    }
  }
  return { renditions: stored, warnings };
}

function assetRecordForRendition(asset: MapAsset, rendition: Pick<BuiltAssetRendition, "kind" | "mimeType" | "sizeBytes" | "checksum" | "width" | "height"> & { storage?: MapAsset["storage"] }): MapAsset {
  return { ...asset, id: `${asset.id}_${rendition.kind}`, name: `${asset.name} (${rendition.kind})`, url: "", mimeType: rendition.mimeType, sizeBytes: rendition.sizeBytes, checksum: rendition.checksum, storage: rendition.storage, image: { width: rendition.width, height: rendition.height }, renditions: undefined };
}

function displayNameFromHeader(value: string | string[] | undefined): string | undefined {
  const raw = Array.isArray(value) ? value[0] : value;
  if (!raw) return undefined;
  const decoded = safeDecodeURIComponent(raw);
  return basename(decoded).trim() || undefined;
}

function headerText(value: string | string[] | undefined): string | undefined {
  const raw = Array.isArray(value) ? value[0] : value;
  return raw ? safeDecodeURIComponent(raw).trim() : undefined;
}

function opaqueHeaderText(value: string | string[] | undefined): string | undefined {
  const raw = Array.isArray(value) ? value[0] : value;
  return raw && raw.length > 0 ? raw : undefined;
}

function normalizeAssetFolder(value: unknown): string | undefined {
  return typeof value === "string" && value.trim() ? value.trim().slice(0, 80) : undefined;
}

function normalizeGeneratedAssetName(value: unknown, kind: "map" | "token"): string {
  return typeof value === "string" && value.trim() ? value.trim().slice(0, 120) : kind === "map" ? "AI Generated Map" : "AI Generated Token";
}

function gridlessMapGenerationPrompt(prompt: string): string {
  return [prompt.trim(), "", "Render this as a clean gridless virtual tabletop background.", "Do not include square grids, hex grids, coordinates, labels, tokens, miniatures, UI chrome, or measurement markings; the VTT will overlay its own grid and tokens."].join("\n");
}

function normalizeAssetTags(value: unknown): string[] {
  const values = Array.isArray(value) ? value : typeof value === "string" ? value.split(",") : [];
  return [
    ...new Set(
      values
        .filter((item): item is string => typeof item === "string")
        .map((item) => item.trim())
        .filter(Boolean)
        .map((item) => item.slice(0, 40)),
    ),
  ].slice(0, 12);
}

function tokenArtReuseKeyForRequest(request: Record<string, unknown>, token: Token | undefined, actor: Actor | undefined): string | undefined {
  const explicit = normalizeTokenArtReuseKey(stringFromRecord(request, "reuseKey"));
  if (explicit) return explicit;
  if (actor?.type === "monster") return normalizeTokenArtReuseKey(actor.name.replace(/\s+\d+$/, ""));
  if (token?.disposition === "hostile") return normalizeTokenArtReuseKey(token.name.replace(/\s+\d+$/, ""));
  return actor ? normalizeTokenArtReuseKey(actor.id) : undefined;
}

function normalizeTokenArtReuseKey(value: string | undefined): string | undefined {
  const normalized = value
    ?.trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 34);
  return normalized || undefined;
}

function reusableTokenArtAsset(context: AiToolContext, reuseKey: string): MapAsset | undefined {
  const tag = `reuse:${reuseKey}`;
  return context.state.assets
    .filter((asset) => asset.campaignId === context.campaignId)
    .filter((asset) => asset.mimeType.startsWith("image/"))
    .filter((asset) => asset.lifecycle?.status !== "deleted")
    .filter((asset) => asset.tags?.includes(tag))
    .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt) || right.createdAt.localeCompare(left.createdAt))[0];
}

function tokenArtAssetTags(actor: Actor | undefined, token: Token | undefined, reuseKey: string | undefined): string[] {
  const tags = ["ai", "generated", "token", actor && actorIsAdversary(actor, token) ? "adversary" : "character"];
  if (reuseKey) tags.push(`reuse:${reuseKey}`);
  return normalizeAssetTags(tags);
}

function rosterActorArtPrompt(actor: Actor, adversary: boolean): string {
  return [`${actor.name}, ${adversary ? "adversary creature" : actor.type || "tabletop character"} token portrait.`, "Create a centered virtual tabletop token/portrait asset with a clean silhouette, no text, no UI, and no background grid."].join("\n");
}

function actorIsAdversary(actor: Actor, token: Token | undefined): boolean {
  const type = actor.type.toLowerCase();
  if (type === "monster" || type === "adversary" || type === "enemy") return true;
  const role = stringFromRecord(actor.data, "role")?.toLowerCase() ?? stringFromRecord(actor.data, "category")?.toLowerCase();
  return role === "adversary" || role === "enemy" || role === "monster" || token?.disposition === "hostile";
}

async function cleanupRejectedProposalAssets(store: StateStore, activeStorage: AssetStorage, uploadDir: string, proposals: Proposal[], actorUserId: string, reason: string): Promise<{ assetCount: number; deleted: number; missingMarked: number; skipped: number; failed: number; changed: boolean; results: Array<Record<string, unknown>> }> {
  const results: Array<Record<string, unknown>> = [];
  const seenAssetIds = new Set<string>();
  let assetCount = 0;
  let deleted = 0;
  let missingMarked = 0;
  let skipped = 0;
  let failed = 0;
  let changed = false;

  for (const proposal of proposals) {
    for (const asset of proposalCreatedAssets(proposal)) {
      if (seenAssetIds.has(asset.id)) continue;
      seenAssetIds.add(asset.id);
      assetCount++;
      const base = { proposalId: proposal.id, assetId: asset.id, name: asset.name, sizeBytes: asset.sizeBytes };
      if (!asset.storage) {
        skipped++;
        results.push({ ...base, status: "skipped", reason: "no_storage_ref" });
        continue;
      }
      if (asset.lifecycle?.storageDeletedAt) {
        skipped++;
        results.push({ ...base, status: "skipped", reason: "storage_already_deleted" });
        continue;
      }
      try {
        const objectDeleted = await deleteStoredAssetObjects(asset, activeStorage, uploadDir);
        markRejectedProposalAssetDeleted(asset, reason, actorUserId);
        changed = true;
        if (objectDeleted) {
          deleted++;
          results.push({ ...base, status: "deleted", reason: "rejected_proposal" });
        } else {
          missingMarked++;
          results.push({ ...base, status: "missing_marked", reason: "rejected_proposal" });
        }
      } catch (error) {
        failed++;
        results.push({ ...base, status: "failed", reason: errorMessage(error) });
      }
    }
  }

  if (changed) store.save();
  return { assetCount, deleted, missingMarked, skipped, failed, changed, results };
}

function proposalCreatedAssets(proposal: Proposal): MapAsset[] {
  if (proposal.status !== "rejected") return [];
  return proposal.changesJson
    .filter((change) => change.entity === "asset" && change.action === "create")
    .map((change) => mapAssetFromRecord(change.data))
    .filter((asset): asset is MapAsset => Boolean(asset));
}

function markRejectedProposalAssetDeleted(asset: MapAsset, reason: string, actorUserId: string): void {
  const updatedAt = nowIso();
  asset.lifecycle = { ...asset.lifecycle, status: "deleted", updatedAt, updatedByUserId: actorUserId, reason, storageDeletedAt: updatedAt, cleanupReason: "rejected_proposal" };
  asset.updatedAt = updatedAt;
}

function findAssetForDelivery(store: StateStore, assetId: string): MapAsset | undefined {
  return store.state.assets.find((asset) => asset.id === assetId) ?? pendingProposalAssetForDelivery(store, assetId);
}

function pendingProposalAssetForDelivery(store: StateStore, assetId: string, excludedProposalId?: string): MapAsset | undefined {
  for (const proposal of store.state.proposals) {
    if (proposal.id === excludedProposalId) continue;
    if (proposal.status !== "pending" && proposal.status !== "approved") continue;
    for (const change of proposal.changesJson) {
      if (change.entity !== "asset" || change.action !== "create") continue;
      if (mapAssetIdFromRecord(change.data) !== assetId) continue;
      const asset = mapAssetFromRecord(change.data);
      return asset ? pendingProposalAssetDeliveryRecord(asset) : undefined;
    }
  }
  return undefined;
}

function pendingProposalAssetDeliveryRecord(asset: MapAsset): MapAsset {
  return { ...asset, storage: undefined };
}

function mapAssetIdFromRecord(value: Record<string, unknown>): string | undefined {
  return typeof value.id === "string" && value.id.trim() ? value.id : undefined;
}

function mapAssetFromRecord(value: Record<string, unknown>): MapAsset | undefined {
  if (typeof value.id !== "string" || typeof value.campaignId !== "string" || typeof value.name !== "string" || typeof value.url !== "string" || typeof value.mimeType !== "string" || typeof value.sizeBytes !== "number" || typeof value.createdAt !== "string" || typeof value.updatedAt !== "string") {
    return undefined;
  }
  return value as unknown as MapAsset;
}

function assetUnavailable(reply: FastifyReply, asset: MapAsset): FastifyReply {
  const deleted = asset.lifecycle?.status === "deleted";
  return reply.code(410).send({ error: deleted ? "asset_deleted" : "asset_expired", message: deleted ? "Asset has been deleted" : "Asset has expired" });
}

function makeDogfoodReportBundle(state: EngineState, campaignId: string): Record<string, unknown> {
  const archive = makeArchive(state, campaignId);
  const data = archive.data;
  const campaign = data.campaigns[0];
  if (!campaign) throw new Error(`Campaign not found: ${campaignId}`);
  const usersById = new Map(data.users.map((user) => [user.id, user]));
  const tokensByScene = countOptionalBy(data.tokens, (token) => token.sceneId);
  const journalsByVisibility = countOptionalBy(data.journals, (journal) => journal.visibility);
  const handoutsByVisibility = countOptionalBy(data.handouts, (handout) => handout.visibility);

  return {
    format: "otte-dogfood-report-bundle",
    version: "0.3.0",
    exportedAt: nowIso(),
    privacy: { mode: "redacted", omitted: ["user emails", "password hashes", "sessions and auth identities", "OAuth and reset tokens", "invite tokens", "journal and handout bodies", "chat message bodies", "AI assistant messages", "AI memory text", "AI tool inputs and outputs", "content import raw entity data", "asset bytes and URLs"], note: "Attach this bundle to outside dogfood reports when the full campaign archive would expose table content or credentials." },
    sourceArchive: { format: archive.format, version: archive.version, schemaVersion: archive.manifest.schemaVersion, assetCount: archive.manifest.assetCount },
    campaign: { id: campaign.id, name: campaign.name, defaultSystemId: campaign.defaultSystemId, visibility: campaign.visibility, createdAt: campaign.createdAt, updatedAt: campaign.updatedAt },
    counts: { users: data.users.length, members: data.members.length, scenes: data.scenes.length, assets: data.assets.length, tokens: data.tokens.length, actors: data.actors.length, items: data.items.length, journals: data.journals.length, handouts: data.handouts.length, chat: data.chat.length, rolls: data.rolls.length, encounters: data.encounters.length, combats: data.combats.length, proposals: data.proposals.length, aiThreads: data.aiThreads.length, aiEvaluations: data.aiEvaluations.length, aiMemory: data.aiMemory.length, aiToolCalls: data.aiToolCalls.length, auditLogs: data.auditLogs.length, contentImports: data.contentImports.length, pluginStorage: data.pluginStorage.length },
    members: data.members.map((member) => ({ id: member.id, userId: member.userId, displayName: usersById.get(member.userId)?.displayName, role: member.role, permissionCount: permissionsForRole(member.role).length })),
    scenes: data.scenes.map((scene) => ({ id: scene.id, name: scene.name, active: scene.active, gridType: scene.gridType, dimensions: { width: scene.width, height: scene.height, gridSize: scene.gridSize }, tokenCount: tokensByScene.get(scene.id) ?? 0, wallCount: scene.walls.length, lightCount: scene.lights.length, fogRegionCount: scene.fog.length })),
    assets: data.assets.map((asset) => ({ id: asset.id, name: asset.name, mimeType: asset.mimeType, sizeBytes: asset.sizeBytes, lifecycleStatus: asset.lifecycle?.status, securityStatus: asset.security?.status })),
    actors: data.actors.map((actor) => {
      const hp = recordFromRecord(actor.data, "hp");
      return { id: actor.id, name: actor.name, type: actor.type, systemId: actor.systemId, ownerUserId: actor.ownerUserId, itemCount: data.items.filter((item) => item.actorId === actor.id).length, hp: hp ? { current: numberFromRecord(hp, "current", 0, 100000), max: numberFromRecord(hp, "max", 0, 100000) } : undefined, dataKeys: recordKeys(actor.data) };
    }),
    tokens: data.tokens.map((token) => ({ id: token.id, sceneId: token.sceneId, actorId: token.actorId, name: token.name, disposition: token.disposition, layer: tokenLayer(token), hidden: token.hidden, locked: token.locked, visionEnabled: token.visionEnabled, hasStatusMarkers: recordKeys(isRecord(token.metadata.statusMarkers) ? token.metadata.statusMarkers : {}).length > 0 })),
    journals: data.journals.map((journal) => ({ id: journal.id, title: journal.title, visibility: journal.visibility, bodyLength: journal.body.length, tags: journal.tags, createdBy: journal.createdBy, updatedBy: journal.updatedBy })),
    handouts: data.handouts.map((handout) => ({ id: handout.id, title: handout.title, visibility: handout.visibility, bodyLength: handout.body.length, assetCount: handout.assetIds.length })),
    visibilitySummary: { journals: Object.fromEntries(journalsByVisibility), handouts: Object.fromEntries(handoutsByVisibility) },
    recentChat: data.chat.slice(-20).map((message) => ({ id: message.id, sceneId: message.sceneId, userId: message.userId, type: message.type, visibility: message.visibility, bodyLength: message.body.length, rollId: message.rollId, createdAt: message.createdAt })),
    combats: data.combats.map((combat) => ({ id: combat.id, encounterId: combat.encounterId, active: combat.active, round: combat.round, turnIndex: combat.turnIndex, combatantCount: combat.combatants.length, defeatedCount: combat.combatants.filter((combatant) => combatant.defeated).length })),
    proposals: data.proposals.map((proposal) => ({ id: proposal.id, createdByType: proposal.createdByType, sourceId: proposal.sourceId, status: proposal.status, approvalRequired: proposal.approvalRequired, changeCount: proposal.changesJson.length, entityTypes: [...new Set(proposal.changesJson.map((change) => change.entity))], titleLength: proposal.title.length, summaryLength: proposal.summary.length })),
    ai: {
      threads: data.aiThreads.map((thread) => ({ id: thread.id, provider: thread.provider, status: thread.status, durationMs: thread.durationMs, retryAttempts: thread.retryAttempts, eventCount: thread.eventCount, toolCallCount: thread.toolCallCount, advertisedToolNames: thread.advertisedToolNames ?? thread.advertisedTools?.map((tool) => tool.name) ?? [], assistantMessageLength: thread.assistantMessage?.length ?? 0, providerErrorLength: thread.providerError?.length ?? 0 })),
      evaluations: data.aiEvaluations.map((evaluation) => ({ id: evaluation.id, name: evaluation.name, status: evaluation.status, score: evaluation.score, checkResults: evaluation.checks.map((check) => ({ name: check.name, status: check.status })) })),
      memory: data.aiMemory.map((memory) => ({ id: memory.id, visibility: memory.visibility, textLength: memory.text.length, sourceCount: memory.sourceIds.length, approved: Boolean(memory.approvedByUserId) })),
      toolCalls: data.aiToolCalls.map((toolCall) => ({ id: toolCall.id, threadId: toolCall.threadId, toolName: toolCall.toolName, status: toolCall.status, durationMs: toolCall.durationMs, retried: Boolean(toolCall.retry) })),
    },
    contentImports: data.contentImports.map((batch) => ({ id: batch.id, status: batch.status, source: { sourceType: batch.source.sourceType, adapterId: batch.source.adapterId, sourceName: batch.source.sourceName, license: batch.source.license }, selectedEntityIds: batch.selectedEntityIds, appliedRecords: batch.appliedRecords, entities: batch.entities.map((entity) => ({ id: entity.id, kind: entity.kind, name: entity.name, selectedByDefault: entity.selectedByDefault, warnings: entity.warnings, dataKeys: recordKeys(entity.data) })), createdAt: batch.createdAt, updatedAt: batch.updatedAt, appliedAt: batch.appliedAt, rolledBackAt: batch.rolledBackAt })),
    recentAudit: data.auditLogs.slice(-50).map((log) => ({ id: log.id, actorType: log.actorType, actorUserId: log.actorUserId, action: log.action, targetType: log.targetType, targetId: log.targetId, createdAt: log.createdAt })),
  };
}

function countOptionalBy<T>(items: T[], keyFor: (item: T) => string | undefined): Map<string, number> {
  const counts = new Map<string, number>();
  for (const item of items) {
    const key = keyFor(item);
    if (!key) continue;
    counts.set(key, (counts.get(key) ?? 0) + 1);
  }
  return counts;
}

function recordKeys(value: unknown): string[] {
  return isRecord(value) ? Object.keys(value).sort() : [];
}

function normalizeAdminStorageReason(value: unknown): { ok: true; value?: string } | { ok: false; error: string } {
  if (value === undefined) return { ok: true };
  if (typeof value !== "string") return { ok: false, error: "reason must be a string" };
  const reason = value.trim();
  if (reason.length > 160) return { ok: false, error: "reason must be at most 160 characters" };
  return { ok: true, ...(reason ? { value: reason } : {}) };
}

function normalizeOptionalBoolean(value: unknown): { ok: true; value: boolean } | { ok: false } {
  if (value === undefined) return { ok: true, value: false };
  return typeof value === "boolean" ? { ok: true, value } : { ok: false };
}

function normalizeOptionalBackupFileName(value: unknown): { ok: true; value?: string } | { ok: false; error: string } {
  if (value === undefined) return { ok: true };
  if (typeof value !== "string") return { ok: false, error: "backupFileName must be a string" };
  const fileName = value.trim();
  if (!fileName || fileName.length > 255 || basename(fileName) !== fileName || !fileName.endsWith(".sqlite")) {
    return { ok: false, error: "backupFileName must be a plain .sqlite filename no longer than 255 characters" };
  }
  return { ok: true, value: fileName };
}

function normalizeRestoreStateRevision(value: unknown): { ok: true; value: string } | { ok: false; error: string } {
  if (typeof value !== "string" || !/^sha256:[a-f0-9]{64}$/.test(value)) {
    return { ok: false, error: "expectedStateRevision must be the exact sha256 revision returned by storage operations" };
  }
  return { ok: true, value };
}

function normalizeAdminAssetSnapshotIdentity(value: AdminAssetSnapshotIdentityInput | undefined, activeProvider: AssetSnapshotProvider): { ok: true; value?: AssetSnapshotIdentity } | { ok: false; error: string } {
  if (value === undefined) return { ok: true };
  if (!value || typeof value !== "object" || Array.isArray(value)) return { ok: false, error: "Asset snapshot identity must be an object" };
  const keys = Object.keys(value);
  if (keys.some((key) => key !== "provider" && key !== "snapshotId" && key !== "createdAt")) {
    return { ok: false, error: "Asset snapshot identity contains unsupported fields" };
  }
  if (value.provider !== "local" && value.provider !== "s3") return { ok: false, error: "Asset snapshot provider must be local or s3" };
  if (value.provider !== activeProvider) return { ok: false, error: "Asset snapshot provider must exactly match the active asset provider" };
  if (typeof value.snapshotId !== "string" || value.snapshotId !== value.snapshotId.trim() || value.snapshotId.length < 1 || value.snapshotId.length > 200 || /[\u0000-\u001f\u007f]/.test(value.snapshotId)) {
    return { ok: false, error: "Asset snapshot ID must be 1 to 200 visible characters without surrounding whitespace" };
  }
  if (typeof value.createdAt !== "string" || value.createdAt.length > 40) return { ok: false, error: "Asset snapshot createdAt must be a canonical ISO timestamp" };
  const timestamp = Date.parse(value.createdAt);
  if (!Number.isFinite(timestamp) || new Date(timestamp).toISOString() !== value.createdAt) {
    return { ok: false, error: "Asset snapshot createdAt must be a canonical ISO timestamp" };
  }
  return { ok: true, value: { provider: value.provider, snapshotId: value.snapshotId, createdAt: value.createdAt } };
}

function asAdminStorageCapableStore(store: StateStore): AdminStorageCapableStore | undefined {
  const candidate = store as Partial<AdminStorageCapableStore>;
  if (typeof candidate.storageOperations !== "function" || typeof candidate.createBackup !== "function" || typeof candidate.runRestoreDrill !== "function" || typeof candidate.restoreBackup !== "function" || typeof candidate.backupArtifactDirectory !== "function") return undefined;
  return candidate as AdminStorageCapableStore;
}

function adminStorageRestoreStateRevision(store: AdminStorageCapableStore): string {
  const revision = store.storageOperations().restoreStateRevision;
  if (typeof revision !== "string" || !/^sha256:[a-f0-9]{64}$/.test(revision)) {
    throw new Error("SQLite storage restore-state revision is unavailable");
  }
  return revision;
}

function flushStore(store: StateStore): void {
  store.flush?.();
}

function storageOperationsForStore(store: StateStore, scheduledBackups?: StorageBackupSchedulerStatus): AdminStorageOperations {
  const storageStore = asAdminStorageCapableStore(store);
  if (storageStore) {
    return { ...storageStore.storageOperations(), ...(scheduledBackups ? { scheduledBackups } : {}) };
  }
  return { provider: "non-sqlite-state-store", supported: false, actionRequired: true, actionReasons: ["sqlite_store_required"], ...(scheduledBackups ? { scheduledBackups } : {}), remediation: "Use the SQLite-backed state store for v1 storage operations, backups, and restore drills." };
}

function notFound(reply: FastifyReply, message: string): FastifyReply {
  return reply.code(404).send({ error: "not_found", message });
}

function sendTokenMoveBatchCommandFailure(reply: FastifyReply, failure: TokenMoveBatchCommandFailure): FastifyReply {
  if (failure.kind === "bad_request") return badRequest(reply, failure.message);
  if (failure.kind === "not_found") return notFound(reply, failure.message);
  if (failure.kind === "forbidden") return forbidden(reply, failure.message);
  return staleWriteConflict(reply, failure);
}

function badRequest(reply: FastifyReply, message: string): FastifyReply {
  return reply.code(400).send({ error: "bad_request", message });
}

function dndManagedDataBoundaryError<T extends Record<string, unknown>>(
  result: Dnd5eSrdManagedDataParseResult<T>,
  allowReviewedRulesOverride = false
): string | undefined {
  if (result.ok) return undefined;
  const blocking = result.issues.find((entry) => !allowReviewedRulesOverride || !entry.code.startsWith("rules."));
  if (!blocking) return undefined;
  return `D&D ${result.source.entityKind} ${result.source.entityId || "(unknown)"} schema ${result.source.schemaVersion} validation failed at ${blocking.path || "/"} (${blocking.code}): ${blocking.message}`;
}

function unauthorized(reply: FastifyReply, message: string): FastifyReply {
  return reply.code(401).send({ error: "unauthorized", message });
}

function forbidden(reply: FastifyReply, message: string): FastifyReply {
  return reply.code(403).send({ error: "forbidden", message });
}

function conflict(reply: FastifyReply, message: string): FastifyReply {
  return reply.code(409).send({ error: "conflict", message });
}

function compendiumConflictResponse(reply: FastifyReply, conflictState: CompendiumConflict, entry: CompendiumCatalogEntry): FastifyReply {
  return reply.code(409).send({ error: "conflict", code: "compendium_conflict", message: conflictState.kind === "exact_duplicate" ? `${entry.name} at content version ${conflictState.requestedVersion} is already present. Choose how to resolve the exact duplicate.` : `${entry.name} conflicts with a different imported content version. Choose whether to keep or replace the existing entry.`, conflict: conflictState, entry });
}

function campaignDndPartyStash(store: StateStore, campaignId: string, stashId?: string): Item | undefined {
  return store.state.items.find((item) => item.campaignId === campaignId && item.systemId === DND_5E_SRD_SYSTEM_ID && item.type === DND5E_PARTY_STASH_ITEM_TYPE && (!stashId || item.id === stashId) && Boolean(dnd5ePartyStashData(item)));
}

function campaignDndMerchants(store: StateStore, campaignId: string): Item[] {
  return store.state.items.filter((item) => item.campaignId === campaignId && item.systemId === DND_5E_SRD_SYSTEM_ID && Boolean(dnd5eMerchantData(item)));
}

function dndInventoryOwnerRef(value: unknown): Dnd5eInventoryOwnerRef | undefined {
  if (!isRecord(value)) return undefined;
  if (value.kind === "actor") {
    const actorId = normalizeNonEmptyString(value.actorId);
    return actorId ? { kind: "actor", actorId } : undefined;
  }
  if (value.kind === "party_stash") {
    const stashId = normalizeNonEmptyString(value.stashId);
    return stashId ? { kind: "party_stash", stashId } : undefined;
  }
  return undefined;
}

function dndInventoryOwnerResource(store: StateStore, campaignId: string, owner: Dnd5eInventoryOwnerRef): Actor | Item | undefined {
  return owner.kind === "actor" ? store.state.actors.find((actor) => actor.id === owner.actorId && actor.campaignId === campaignId && actor.systemId === DND_5E_SRD_SYSTEM_ID) : campaignDndPartyStash(store, campaignId, owner.stashId);
}

function canUpdateDndInventoryOwner(store: StateStore, userId: string, owner: Dnd5eInventoryOwnerRef, resource: Actor | Item): boolean {
  if (owner.kind === "party_stash") return canCampaign(store, userId, resource.campaignId, "campaign.update");
  return canUpdateActorForUser(store, userId, resource as Actor);
}

function dndInventoryOwnerRevisionGuard(store: StateStore, reply: FastifyReply, userId: string, owner: Dnd5eInventoryOwnerRef, resource: Actor | Item, expectedUpdatedAt: unknown, label: string): true | FastifyReply {
  return requireExpectedRevision(reply, { resourceType: owner.kind === "actor" ? "actor" : "item", resourceId: resource.id, currentUpdatedAt: resource.updatedAt, expectedUpdatedAt, current: owner.kind === "actor" ? actorPayloadForUser(store, userId, resource as Actor) : resource, label });
}

function dndInventoryOverview(store: StateStore, userId: string, campaignId: string, actorId?: string): Record<string, unknown> {
  const campaign = store.state.campaigns.find((candidate) => candidate.id === campaignId);
  const actor = actorId ? store.state.actors.find((candidate) => candidate.id === actorId && candidate.campaignId === campaignId && candidate.systemId === DND_5E_SRD_SYSTEM_ID) : undefined;
  const canReadActor = actor ? canReadActorPrivateData(store, userId, campaignId, actor) : false;
  const stash = campaignDndPartyStash(store, campaignId);
  const stashData = stash ? dnd5ePartyStashData(stash) : undefined;
  const actorOwner = actor ? ({ kind: "actor", actorId: actor.id } as const) : undefined;
  const stashOwner = stash ? ({ kind: "party_stash", stashId: stash.id } as const) : undefined;
  const actorItems = actor && canReadActor ? dnd5eInventoryItemsForOwner(store.state.items, actorOwner!) : [];
  const stashItems = stashOwner ? dnd5eInventoryItemsForOwner(store.state.items, stashOwner) : [];
  const lootItems = stashItems.filter((item) => Boolean(dnd5eLootData(item)));
  const canManageCampaign = canCampaign(store, userId, campaignId, "campaign.update");
  const merchants = campaignDndMerchants(store, campaignId).map((merchant) => {
    const data = dnd5eMerchantData(merchant);
    if (canManageCampaign || !data?.currency) return merchant;
    return { ...merchant, data: { ...merchant.data, [DND5E_MERCHANT_DATA_KEY]: { ...data, currency: undefined } } };
  });
  return {
    campaignId,
    campaignUpdatedAt: campaign?.updatedAt ?? "",
    actorItems,
    ...(actor && canReadActor ? { actor: actorPayloadForUser(store, userId, actor), actorSummary: dnd5eInventorySummary(actorOwner!, store.state.items, { actor }) } : {}),
    ...(stash ? { partyStash: stash, partyStashItems: stashItems, partyStashSummary: dnd5eInventorySummary(stashOwner!, store.state.items, { capacityLb: stashData?.capacityLb }) } : { partyStashItems: [] }),
    merchants,
    lootItems: lootItems.map((item) => {
      const loot = dnd5eLootData(item);
      if (!loot) return item;
      if (loot.claimedByUserId === userId || canCampaign(store, userId, campaignId, "campaign.update")) return item;
      return { ...item, data: { ...item.data, [DND5E_LOOT_DATA_KEY]: { ...loot, claimedByUserId: undefined } } };
    }),
    warnings: [...(actor && !canReadActor ? ["Actor inventory is private"] : []), ...(!stash ? ["The campaign has no party stash yet"] : []), ...merchants.filter((merchant) => dnd5eMerchantData(merchant)?.currency === undefined).map((merchant) => `${merchant.name} uses manual merchant liquidity`)],
  };
}

function normalizeDndMerchantCatalog(store: StateStore, campaignId: string, value: unknown): { ok: true; value: Dnd5eMerchantCatalogEntry[] } | { ok: false; error: string } {
  if (!Array.isArray(value)) return { ok: false, error: "catalog must be an array" };
  const catalog: Dnd5eMerchantCatalogEntry[] = [];
  for (const raw of value) {
    if (!isRecord(raw)) return { ok: false, error: "catalog entries must be objects" };
    const compendiumEntryId = normalizeNonEmptyString(raw.compendiumEntryId);
    const compendium = compendiumEntryId ? campaignCompendiumEntry(store, campaignId, DND_5E_SRD_SYSTEM_ID, compendiumEntryId, true) : undefined;
    if (compendiumEntryId && (!compendium || !isGenericFantasyCompendiumCatalogEntry(compendium) || compendium.type === "condition")) {
      return { ok: false, error: `Unknown purchasable compendium entry: ${compendiumEntryId}` };
    }
    const id = normalizeNonEmptyString(raw.id) ?? compendiumEntryId;
    const name = normalizeNonEmptyString(raw.name) ?? compendium?.name;
    const type = normalizeNonEmptyString(raw.type) ?? compendium?.type;
    const defaultPrice = compendium && typeof compendium.data.costGp === "number" ? compendium.data.costGp : undefined;
    const unitPriceGp = typeof raw.unitPriceGp === "number" ? raw.unitPriceGp : defaultPrice;
    const sellPriceGp = typeof raw.sellPriceGp === "number" ? raw.sellPriceGp : undefined;
    const availableQuantity = raw.availableQuantity === undefined ? undefined : Number(raw.availableQuantity);
    if (!id || !name || !type || unitPriceGp === undefined) return { ok: false, error: "Each catalog entry needs id, name, type, and unitPriceGp" };
    catalog.push({ id, name, type, unitPriceGp, ...(sellPriceGp !== undefined ? { sellPriceGp } : {}), ...(availableQuantity !== undefined ? { availableQuantity } : {}), ...(compendiumEntryId ? { compendiumEntryId } : {}), data: compendium ? compendiumItemData(compendium) : cloneRecord(isRecord(raw.data) ? raw.data : {}) });
  }
  try {
    dnd5eAssertMerchantData({ version: 1, name: "Validation", description: "", buybackRate: 0.5, catalog });
  } catch (error) {
    return { ok: false, error: error instanceof Error ? error.message : "Invalid merchant catalog" };
  }
  return { ok: true, value: catalog };
}

function normalizeDndMerchantMutation(store: StateStore, campaignId: string, body: DndMerchantMutationBody, current?: Dnd5eMerchantData): { ok: true; value: Dnd5eMerchantData } | { ok: false; error: string } {
  const name = body.name === undefined ? (current?.name ?? "Merchant") : normalizeNonEmptyString(body.name);
  if (!name) return { ok: false, error: "name must be a non-empty string" };
  const description = body.description === undefined ? (current?.description ?? "") : typeof body.description === "string" ? body.description.trim() : undefined;
  if (description === undefined) return { ok: false, error: "description must be a string" };
  const buybackRate = body.buybackRate === undefined ? (current?.buybackRate ?? 0.5) : typeof body.buybackRate === "number" ? body.buybackRate : Number.NaN;
  const catalogResult = body.catalog === undefined ? { ok: true as const, value: current?.catalog ?? [] } : normalizeDndMerchantCatalog(store, campaignId, body.catalog);
  if (!catalogResult.ok) return catalogResult;
  const currency = body.currency === undefined ? current?.currency : body.currency === null ? undefined : isRecord(body.currency) ? dnd5eCurrencyFromCopper(dnd5eCurrencyToCopper(body.currency)) : null;
  if (currency === null) return { ok: false, error: "currency must be an object or null" };
  const data: Dnd5eMerchantData = { version: 1, name, description, buybackRate, ...(currency ? { currency } : {}), catalog: catalogResult.value };
  try {
    dnd5eAssertMerchantData(data);
  } catch (error) {
    return { ok: false, error: error instanceof Error ? error.message : "Invalid merchant" };
  }
  return { ok: true, value: data };
}

function dndMerchantCatalogItemData(merchant: Item, entry: Dnd5eMerchantCatalogEntry, quantity: number): Record<string, unknown> {
  return { ...entry.data, quantity, merchantId: merchant.id, merchantCatalogEntryId: entry.id, purchasedForGp: (Math.round(entry.unitPriceGp * 100) * quantity) / 100, [DND5E_INVENTORY_METADATA_KEY]: { version: 1, quantity, weightLb: typeof entry.data.weightLb === "number" && Number.isFinite(entry.data.weightLb) && entry.data.weightLb >= 0 ? entry.data.weightLb : 0 } satisfies Dnd5eInventoryMetadata };
}

function dndMerchantCatalogEntryForSoldItem(merchantItem: Item, merchant: Dnd5eMerchantData, item: Item): Dnd5eMerchantCatalogEntry | undefined {
  const compendiumId = normalizeNonEmptyString(item.data.compendiumId);
  const sourceMerchantId = normalizeNonEmptyString(item.data.merchantId);
  const sourceEntryId = normalizeNonEmptyString(item.data.merchantCatalogEntryId);
  return merchant.catalog.find((entry) => (sourceMerchantId === merchantItem.id && sourceEntryId && entry.id === sourceEntryId) || (compendiumId && entry.compendiumEntryId === compendiumId));
}

function dndLootItemDrafts(store: StateStore, campaignId: string, value: unknown): { ok: true; value: Array<{ name: string; type: string; quantity: number; weightLb: number; containerCapacityLb?: number; data: Record<string, unknown> }> } | { ok: false; error: string } {
  if (!Array.isArray(value) || value.length < 1 || value.length > 50) return { ok: false, error: "items must contain 1 to 50 loot entries" };
  const drafts = [];
  for (const raw of value) {
    if (!isRecord(raw)) return { ok: false, error: "Loot entries must be objects" };
    const compendiumEntryId = normalizeNonEmptyString(raw.compendiumEntryId);
    const compendium = compendiumEntryId ? campaignCompendiumEntry(store, campaignId, DND_5E_SRD_SYSTEM_ID, compendiumEntryId, true) : undefined;
    if (compendiumEntryId && (!compendium || !isGenericFantasyCompendiumCatalogEntry(compendium) || compendium.type === "condition")) return { ok: false, error: `Unknown loot compendium entry: ${compendiumEntryId}` };
    const name = normalizeNonEmptyString(raw.name) ?? compendium?.name;
    const type = normalizeNonEmptyString(raw.type) ?? compendium?.type ?? "gear";
    const quantity = raw.quantity === undefined ? 1 : Number(raw.quantity);
    const sourceData = compendium ? compendiumItemData(compendium) : cloneRecord(isRecord(raw.data) ? raw.data : {});
    const weightLb = raw.weightLb === undefined ? Number(sourceData.weightLb ?? 0) : Number(raw.weightLb);
    const containerCapacityLb = raw.containerCapacityLb === undefined ? (typeof sourceData.capacityLb === "number" ? sourceData.capacityLb : undefined) : Number(raw.containerCapacityLb);
    if (!name || name.length > 160) return { ok: false, error: "Loot names must be 1 to 160 characters" };
    if (!Number.isInteger(quantity) || quantity < 1 || quantity > 999_999) return { ok: false, error: "Loot quantity must be an integer from 1 to 999999" };
    if (!Number.isFinite(weightLb) || weightLb < 0 || weightLb > 1_000_000) return { ok: false, error: "Loot weightLb must be from 0 to 1000000" };
    if (containerCapacityLb !== undefined && (!Number.isFinite(containerCapacityLb) || containerCapacityLb <= 0 || containerCapacityLb > 1_000_000)) return { ok: false, error: "Loot containerCapacityLb must be greater than 0 and no more than 1000000" };
    drafts.push({ name, type, quantity, weightLb, ...(containerCapacityLb !== undefined ? { containerCapacityLb } : {}), data: sourceData });
  }
  return { ok: true, value: drafts };
}

function requireCombatMechanicMutationGuard(request: FastifyRequest, reply: FastifyReply, combat: Combat, expectedUpdatedAtValue: unknown, operation: string): true | FastifyReply {
  if (!opaqueHeaderText(request.headers["idempotency-key"])) return badRequest(reply, `${operation} requires an Idempotency-Key header`);
  const expectedUpdatedAt = normalizeNonEmptyString(expectedUpdatedAtValue);
  if (!expectedUpdatedAt || !Number.isFinite(Date.parse(expectedUpdatedAt))) return badRequest(reply, "expectedUpdatedAt must be a valid combat date-time");
  if (expectedUpdatedAt !== combat.updatedAt) {
    return staleWriteConflict(reply, { resourceType: "combat", resourceId: combat.id, expectedUpdatedAt, currentUpdatedAt: combat.updatedAt, current: combat });
  }
  return true;
}

function normalizeCombatEnvironmentMechanic(body: CombatEnvironmentMechanicBody | undefined, updating: boolean, current?: CombatEnvironmentMechanic): { ok: true; value: Pick<CombatEnvironmentMechanic, "kind" | "name" | "description" | "visibility" | "enabled" | "schedule" | "options"> } | { ok: false; message: string } {
  const kindValue = body?.kind ?? current?.kind;
  if (kindValue !== "lair_action" && kindValue !== "regional_effect") return { ok: false, message: "kind must be lair_action or regional_effect" };
  const name = normalizeNonEmptyString(body?.name ?? current?.name);
  if (!name || name.length > 120) return { ok: false, message: "name must be 1-120 characters" };
  const description = normalizeNonEmptyString(body?.description ?? current?.description);
  if (!description || description.length > 2000) return { ok: false, message: "description must be 1-2000 characters" };
  const visibilityValue = body?.visibility ?? current?.visibility ?? "gm_only";
  if (visibilityValue !== "public" && visibilityValue !== "gm_only") return { ok: false, message: "visibility must be public or gm_only" };
  const enabledValue = body?.enabled ?? current?.enabled ?? true;
  if (typeof enabledValue !== "boolean") return { ok: false, message: "enabled must be a boolean" };

  const scheduleValue = body?.schedule ?? current?.schedule;
  if (!isRecord(scheduleValue)) return { ok: false, message: "schedule is required" };
  const timing = scheduleValue.timing;
  if (timing !== "initiative_count" && timing !== "round_start" && timing !== "round_end" && timing !== "manual") {
    return { ok: false, message: "schedule.timing must be initiative_count, round_start, round_end, or manual" };
  }
  const startsAtRound = typeof scheduleValue.startsAtRound === "number" && Number.isInteger(scheduleValue.startsAtRound) ? scheduleValue.startsAtRound : (current?.schedule.startsAtRound ?? 1);
  const intervalRounds = typeof scheduleValue.intervalRounds === "number" && Number.isInteger(scheduleValue.intervalRounds) ? scheduleValue.intervalRounds : (current?.schedule.intervalRounds ?? 1);
  if (startsAtRound < 1 || startsAtRound > 1_000_000) return { ok: false, message: "schedule.startsAtRound must be an integer from 1 to 1000000" };
  if (intervalRounds < 1 || intervalRounds > 1_000_000) return { ok: false, message: "schedule.intervalRounds must be an integer from 1 to 1000000" };
  const initiativeCount = typeof scheduleValue.initiativeCount === "number" && Number.isFinite(scheduleValue.initiativeCount) ? scheduleValue.initiativeCount : current?.schedule.initiativeCount;
  if (timing === "initiative_count" && (initiativeCount === undefined || initiativeCount < -1000 || initiativeCount > 1000)) {
    return { ok: false, message: "initiative-count scheduling requires initiativeCount from -1000 to 1000" };
  }
  const schedule: CombatEnvironmentMechanicSchedule = { timing: timing as CombatEnvironmentMechanicTiming, ...(timing === "initiative_count" ? { initiativeCount } : {}), startsAtRound, intervalRounds };

  const rawOptions = body?.options ?? current?.options ?? [];
  if (!Array.isArray(rawOptions) || rawOptions.length > 20) return { ok: false, message: "options must contain at most 20 entries" };
  const options: CombatEnvironmentMechanic["options"] = [];
  for (const rawOption of rawOptions) {
    if (!isRecord(rawOption)) return { ok: false, message: "Each option must be an object" };
    const optionName = normalizeNonEmptyString(rawOption.name);
    const optionDescription = normalizeNonEmptyString(rawOption.description);
    if (!optionName || optionName.length > 120 || !optionDescription || optionDescription.length > 1000) {
      return { ok: false, message: "Each option requires a 1-120 character name and 1-1000 character description" };
    }
    const requestedId = normalizeNonEmptyString(rawOption.id);
    const existingId = updating && requestedId && current?.options.some((option) => option.id === requestedId) ? requestedId : undefined;
    options.push({ id: existingId ?? createId("cmechopt"), name: optionName, description: optionDescription });
  }
  return { ok: true, value: { kind: kindValue as CombatEnvironmentMechanicKind, name, description, visibility: visibilityValue, enabled: enabledValue, schedule, options } };
}

function environmentMechanicAuditSummary(mechanic: CombatEnvironmentMechanic): Record<string, unknown> {
  return { id: mechanic.id, kind: mechanic.kind, name: mechanic.name, visibility: mechanic.visibility, enabled: mechanic.enabled, schedule: mechanic.schedule, optionIds: mechanic.options.map((option) => option.id), triggerCount: mechanic.triggerCount, lastTriggeredRound: mechanic.lastTriggeredRound };
}

function normalizeCombatEffectScheduleInput(body: CombatEffectScheduleBody | undefined): { ok: true; value: { phase: RulesEffectScheduleTiming; now: string; saveOutcomes?: Record<string, "success" | "failure"> } } | { ok: false; message: string } {
  const phase = body?.phase;
  if (phase !== "start_turn" && phase !== "end_turn" && phase !== "start_round" && phase !== "end_round" && phase !== "initiative_count" && phase !== "time" && phase !== "manual") {
    return { ok: false, message: "phase must be a supported scheduled-effect timing" };
  }
  const now = body?.now === undefined ? nowIso() : normalizeNonEmptyString(body.now);
  if (!now || !Number.isFinite(Date.parse(now))) return { ok: false, message: "now must be a valid date-time" };
  const normalizedSaveOutcomes = normalizeCombatSaveOutcomes(body?.saveOutcomes);
  if (!normalizedSaveOutcomes.ok) return normalizedSaveOutcomes;
  return { ok: true, value: { phase, now: new Date(now).toISOString(), ...(normalizedSaveOutcomes.value ? { saveOutcomes: normalizedSaveOutcomes.value } : {}) } };
}

function normalizeCombatSaveOutcomes(value: unknown): { ok: true; value?: Record<string, "success" | "failure"> } | { ok: false; message: string } {
  if (value === undefined) return { ok: true };
  if (!isRecord(value)) return { ok: false, message: "saveOutcomes must be an object" };
  const saveOutcomes: Record<string, "success" | "failure"> = {};
  for (const [eventId, outcome] of Object.entries(value)) {
    if (!eventId.trim() || eventId.length > 300 || (outcome !== "success" && outcome !== "failure")) {
      return { ok: false, message: "saveOutcomes values must be success or failure" };
    }
    saveOutcomes[eventId] = outcome;
  }
  if (Object.keys(saveOutcomes).length > 100) return { ok: false, message: "saveOutcomes supports at most 100 events" };
  return { ok: true, ...(Object.keys(saveOutcomes).length > 0 ? { value: saveOutcomes } : {}) };
}

function recordFromUnknown(value: unknown): Record<string, unknown> {
  return isRecord(value) ? value : {};
}

function dndRulesMutationUndoDescriptor(mutation: DndRulesMutation): { mutationId: string; expectedActorUpdatedAt: Record<string, string>; expectedItemUpdatedAt: Record<string, string>; expectedCombatUpdatedAt?: string } {
  return { mutationId: mutation.id, expectedActorUpdatedAt: Object.fromEntries(mutation.roots.actors.map((root) => [root.actorId, root.afterRevision])), expectedItemUpdatedAt: Object.fromEntries(mutation.roots.items.map((root) => [root.itemId, root.afterRevision])), ...(mutation.roots.combat ? { expectedCombatUpdatedAt: mutation.roots.combat.afterRevision } : {}) };
}

function combatDndActors(store: StateStore, combat: Combat): Actor[] {
  const actorIds = new Set(combat.combatants.map((combatant) => combatant.actorId).filter((actorId): actorId is string => Boolean(actorId)));
  return store.state.actors.filter((actor) => actor.campaignId === combat.campaignId && actor.systemId === DND_5E_SRD_SYSTEM_ID && actorIds.has(actor.id));
}

interface DndCombatTurnProgression {
  canApply: boolean;
  combat: Combat;
  actors: Actor[];
  results: Dnd5eSrdCombatRulesProgressionResult[];
}

function campaignSurpriseInitiativeEnabled(campaign: Pick<Campaign, "rulesProfile">): boolean {
  return campaign.rulesProfile?.toggles["initiative.surprise"] !== false;
}

function validateCombatantSurpriseInputs(campaign: Pick<Campaign, "rulesProfile">, combatants: readonly unknown[]): string | undefined {
  for (const rawCombatant of combatants) {
    if (!isRecord(rawCombatant)) return "Each combatant must be an object";
    if (rawCombatant.surprised !== undefined && typeof rawCombatant.surprised !== "boolean") return "combatant surprised must be a boolean";
    if (rawCombatant.surprised === true && !campaignSurpriseInitiativeEnabled(campaign)) {
      return "Surprise initiative is disabled by this campaign's rules profile";
    }
  }
  return undefined;
}

function isForwardCombatTurnProgression(before: Combat, after: Combat): boolean {
  if (!before.active || !after.active) return false;
  return after.round > before.round || (after.round === before.round && after.turnIndex > before.turnIndex);
}

function previewDndCombatTurnProgression(store: StateStore, before: Combat, after: Combat, now: string, saveOutcomes?: Record<string, "success" | "failure">): DndCombatTurnProgression {
  const actorIds = new Set([...before.combatants, ...after.combatants].map((combatant) => combatant.actorId).filter((actorId): actorId is string => Boolean(actorId)));
  let actors = structuredClone(store.state.actors.filter((actor) => actor.campaignId === before.campaignId && actor.systemId === DND_5E_SRD_SYSTEM_ID && actorIds.has(actor.id)));
  const items = structuredClone(store.state.items.filter((item) => item.campaignId === before.campaignId && item.systemId === DND_5E_SRD_SYSTEM_ID && Boolean(item.actorId && actorIds.has(item.actorId))));
  let combat = structuredClone(after);
  const results: Dnd5eSrdCombatRulesProgressionResult[] = [];
  const phases: Array<{ phase: "end_turn" | "end_round" | "start_round" | "start_turn"; round: number; turnIndex: number }> = [
    { phase: "end_turn", round: before.round, turnIndex: before.turnIndex },
    ...(after.round > before.round
      ? [
          { phase: "end_round" as const, round: before.round, turnIndex: before.turnIndex },
          { phase: "start_round" as const, round: after.round, turnIndex: after.turnIndex },
        ]
      : []),
    { phase: "start_turn", round: after.round, turnIndex: after.turnIndex },
  ];

  for (const timing of phases) {
    const result = advanceDnd5eSrdCombatRules({ actors, items, combat: { id: combat.id, round: timing.round, turnIndex: timing.turnIndex, combatants: combat.combatants }, phase: timing.phase, now, ...(saveOutcomes ? { saveOutcomes } : {}) });
    results.push(result);
    if (!result.canApply) return { canApply: false, combat, actors, results };

    const actorDataPatches = new Map(result.actorDataPatches.map((patch) => [patch.actorId, patch.data]));
    actors = actors.map((actor) => {
      const data = actorDataPatches.get(actor.id);
      return data ? { ...actor, data: structuredClone(data) } : actor;
    });
    const combatantUpdates = new Map(result.combatantUpdates.map((update) => [update.combatantId, update.after]));
    const removedConditionsByActor = new Map(
      result.actorUpdates.map((update) => {
        const beforeConditions = actorConditionIdSet(update.before);
        const afterConditions = actorConditionIdSet(update.after);
        return [update.actorId, [...beforeConditions].filter((conditionId) => !afterConditions.has(conditionId))] as const;
      }),
    );
    combat.combatants = combat.combatants.map((combatant) => {
      const nextCombatant = structuredClone(combatantUpdates.get(combatant.id) ?? combatant);
      const removedConditions = combatant.actorId ? removedConditionsByActor.get(combatant.actorId) : undefined;
      if (removedConditions?.length) {
        nextCombatant.conditions = (nextCombatant.conditions ?? []).filter((condition) => !removedConditions.includes(normalizeConditionId(condition.split(":")[0] ?? "")));
      }
      return nextCombatant;
    });
    if (result.events.length > 0) {
      combat.effectScheduleEvents = [...(combat.effectScheduleEvents ?? []), ...result.events.map((event) => ({ ...event, createdAt: now, updatedAt: now }))].slice(-100);
    }
    if (timing.phase === "end_turn") combat.legendaryActionPrompts = result.legendaryActionPrompts.map((prompt) => ({ ...prompt, options: [...prompt.options] }));
    if (timing.phase === "start_turn") {
      const activeActorId = combat.combatants[timing.turnIndex]?.actorId;
      if (activeActorId) combat.legendaryActionPrompts = (combat.legendaryActionPrompts ?? []).filter((prompt) => prompt.actorId !== activeActorId);
    }
  }

  return { canApply: true, combat, actors, results };
}

function effectScheduleEvaluationPayload(evaluation: Dnd5eSrdEffectScheduleEvaluation, combatUpdatedAt: string): Record<string, unknown> {
  return { phase: evaluation.phase, round: evaluation.round, turnIndex: evaluation.turnIndex, events: evaluation.events, actorChanges: evaluation.actorUpdates.map((update) => ({ actorId: update.actorId, reason: update.reason })), unresolvedEventIds: evaluation.unresolvedEventIds, canApply: evaluation.canApply, combatUpdatedAt };
}

function actorConditionIdSet(data: Record<string, unknown>): Set<string> {
  const conditions = Array.isArray(data.conditions) ? data.conditions : [];
  return new Set(conditions.map((condition) => normalizeConditionId(typeof condition === "string" ? condition : (stringFromRecord(recordFromUnknown(condition), "id") ?? ""))).filter(Boolean));
}

function normalizeConditionId(value: string): string {
  return value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function normalizeSpellHelperOptions(options: Record<string, unknown>): NonNullable<Parameters<typeof previewDnd5eSrdSpellHelper>[0]["options"]> {
  const normalized: NonNullable<Parameters<typeof previewDnd5eSrdSpellHelper>[0]["options"]> = {};
  if (typeof options.roundsHeld === "number" && Number.isFinite(options.roundsHeld)) normalized.roundsHeld = Math.max(0, Math.min(10, Math.floor(options.roundsHeld)));
  if (isRecord(options.dartAssignments)) {
    const assignments: Record<string, number> = {};
    for (const [actorId, count] of Object.entries(options.dartAssignments).slice(0, 100)) {
      if (actorId.trim() && typeof count === "number" && Number.isInteger(count) && count >= 0 && count <= 100) assignments[actorId] = count;
    }
    normalized.dartAssignments = assignments;
  }
  return normalized;
}

function requireSceneTacticalMutationGuard(request: FastifyRequest, reply: FastifyReply, scene: Scene, expectedUpdatedAtValue: unknown, operation: string): true | FastifyReply {
  const idempotencyKey = opaqueHeaderText(request.headers["idempotency-key"]);
  if (!idempotencyKey) return badRequest(reply, `${operation} requires an Idempotency-Key header`);
  const expectedUpdatedAt = normalizeNonEmptyString(expectedUpdatedAtValue);
  if (!expectedUpdatedAt) return badRequest(reply, "expectedUpdatedAt must be a non-empty string");
  if (!Number.isFinite(Date.parse(expectedUpdatedAt))) return badRequest(reply, "expectedUpdatedAt must be a valid date-time");
  if (expectedUpdatedAt !== scene.updatedAt) {
    return staleWriteConflict(reply, { resourceType: "scene", resourceId: scene.id, expectedUpdatedAt, currentUpdatedAt: scene.updatedAt, current: withoutSceneEditHistory(scene) });
  }
  return true;
}

function requireExpectedRevision(reply: FastifyReply, input: { resourceType: RevisionResourceType; resourceId: string; currentUpdatedAt: string; expectedUpdatedAt: unknown; current: unknown; label: string }): true | FastifyReply {
  const expectedUpdatedAt = normalizeNonEmptyString(input.expectedUpdatedAt);
  if (!expectedUpdatedAt || !Number.isFinite(Date.parse(expectedUpdatedAt))) return badRequest(reply, `${input.label} expectedUpdatedAt must be a valid date-time`);
  if (expectedUpdatedAt !== input.currentUpdatedAt) {
    return staleWriteConflict(reply, { resourceType: input.resourceType, resourceId: input.resourceId, expectedUpdatedAt, currentUpdatedAt: input.currentUpdatedAt, current: input.current });
  }
  return true;
}

function actorForCombatant(store: StateStore, campaignId: string, combatant: Pick<Combat["combatants"][number], "actorId" | "tokenId">): Actor | undefined {
  const actorId = combatant.actorId ?? store.state.tokens.find((token) => token.id === combatant.tokenId)?.actorId;
  return actorId ? store.state.actors.find((actor) => actor.id === actorId && actor.campaignId === campaignId) : undefined;
}

function dndCharacterApprovalConflict(campaign: Campaign, actor: Actor, items: Item[], action: string): { error: "conflict"; code: "character_approval_required"; message: string; actorId: string } | undefined {
  if (dndCharacterIsApproved(campaign, actor, items)) return undefined;
  return { error: "conflict", code: "character_approval_required", message: `${actor.name} must have a current DM approval before ${action} while character approval is required.`, actorId: actor.id };
}

function characterReviewEntryPayload(store: StateStore, userId: string, entry: DndCharacterReviewEntry): DndCharacterReviewEntry {
  return { ...entry, actor: actorPayloadForUser(store, userId, entry.actor) };
}

function characterReviewItemRevisionMismatch(items: Item[], expected: Record<string, string>): { id: string; name: string; updatedAt?: string } | undefined {
  for (const item of items) {
    if (expected[item.id] !== item.updatedAt) return { id: item.id, name: item.name, updatedAt: item.updatedAt };
  }
  const currentIds = new Set(items.map((item) => item.id));
  const removedId = Object.keys(expected).find((id) => !currentIds.has(id));
  return removedId ? { id: removedId, name: "An attached item" } : undefined;
}

function isStringRecord(value: unknown): value is Record<string, string> {
  return Boolean(value && typeof value === "object" && !Array.isArray(value) && Object.values(value).every((entry) => typeof entry === "string"));
}

function dnd5eSrdSpellAdvancementPlanFromValue(value: unknown): Dnd5eSrdSpellAdvancementPlan | undefined {
  if (!isRecord(value) || typeof value.className !== "string") return undefined;
  const integer = (entry: unknown): entry is number => typeof entry === "number" && Number.isInteger(entry) && entry > 0;
  const stringArray = (entry: unknown): entry is string[] => Array.isArray(entry) && entry.every((item) => typeof item === "string" && item.trim().length > 0);
  if (!integer(value.classLevel) || !integer(value.maxSpellLevel) || !integer(value.preparedSpellCapacity)) return undefined;
  const profile = dnd5eSrdSpellcastingClassProfile(value.className, value.classLevel);
  if (!profile
    || value.className !== profile.className
    || value.spellcastingAbility !== profile.spellcastingAbility
    || value.acquisitionMode !== profile.acquisitionMode
    || value.maxSpellLevel !== profile.maxSpellLevel
    || value.preparedSpellCapacity !== profile.preparedSpellCapacity) return undefined;
  if (!stringArray(value.preparedSpellIds) || !stringArray(value.wizardSpellbookAdditions) || !stringArray(value.resultingSpellbookSpellIds) || !stringArray(value.materializedSpellIds)) return undefined;
  if (value.preparedSpellIds.length !== value.preparedSpellCapacity || new Set(value.preparedSpellIds).size !== value.preparedSpellIds.length) return undefined;
  if (profile.className === "Wizard" && (value.wizardSpellbookAdditions.length !== profile.spellbookAdditions || new Set(value.wizardSpellbookAdditions).size !== profile.spellbookAdditions)) return undefined;
  if (profile.className !== "Wizard" && (value.wizardSpellbookAdditions.length > 0 || value.resultingSpellbookSpellIds.length > 0)) return undefined;
  const materialized = profile.className === "Wizard" ? value.resultingSpellbookSpellIds : value.preparedSpellIds;
  if (hashStableJson(value.materializedSpellIds) !== hashStableJson(materialized)) return undefined;
  if (!Array.isArray(value.spellGrants) || value.spellGrants.length !== materialized.length) return undefined;
  const prepared = new Set(value.preparedSpellIds);
  const expectedGrants = materialized.map((compendiumEntryId) => ({
    compendiumEntryId,
    itemData: dnd5eSrdClassSpellGrantData({
      compendiumEntryId,
      className: profile.className,
      selectedAtLevel: profile.classLevel,
      prepared: prepared.has(compendiumEntryId),
      inSpellbook: profile.className === "Wizard"
    })
  }));
  if (hashStableJson(value.spellGrants) !== hashStableJson(expectedGrants)) return undefined;
  return structuredClone(value) as Dnd5eSrdSpellAdvancementPlan;
}

function applyPreparedControlledCreatureAction(
  state: EngineState,
  campaignId: string,
  userId: string,
  prepared: PreparedControlledCreatureAction,
): AppliedPreparedControlledCreatureAction {
  const workingStore: StateStore = {
    state,
    save() {},
    replace(nextState) { this.state = nextState; },
  };
  const actionBody = prepared.request;
  const actor = workingStore.state.actors.find((candidate) => candidate.id === prepared.handoff.action.actorId && candidate.campaignId === campaignId && candidate.systemId === DND_5E_SRD_SYSTEM_ID);
  if (!actor) throw new Error("Prepared D&D action source actor no longer exists");
  const items = actorItems(workingStore, actor);
  const calculationContext = calculationOverrideContextForActor(workingStore, actor, items);
  const rollDefinition = systemQuickRolls(actor, items, calculationContext).find((roll) => roll.id === prepared.handoff.action.rollId);
  if (!rollDefinition) throw new Error("Prepared D&D action is no longer available for this actor");
  const spellSlotLevel = numberFromRecord(actionBody, "spellSlotLevel", 1, 9);
  const actionOptions = systemActionOptions(spellSlotLevel, actionBody.resourceAmount, actionBody.useFreeResource);
  const formula = systemActionFormula(actor, items, rollDefinition.id, actionOptions, calculationContext) ?? rollDefinition.formula;
  const resolvedRollDefinition = { ...rollDefinition, formula };
  const masteryInput = normalizeSystemRollWeaponMasteryUse(actionBody.weaponMastery);
  if (masteryInput.error) throw new Error(masteryInput.error);
  const masteryEffectRequested = masteryInput.value?.use === true;
  const effectRequested = Boolean(actionBody.applyEffect || masteryEffectRequested);
  const masteryTargetIds = masteryEffectRequested
    ? [actionBody.targetActorId, ...(actionBody.targetActorIds ?? []), masteryInput.value?.secondaryTargetActorId].filter((value): value is string => typeof value === "string" && value.trim().length > 0)
    : undefined;
  const targetActorIds = masteryTargetIds
    ? systemRollTargetActorIds(masteryTargetIds)
    : systemRollTargetActorIds(actionBody.targetActorIds, actionBody.targetActorId, actionBody.applyEffect ? actor.id : undefined);
  const targets = targetActorIds.map((actorId) => {
    const target = workingStore.state.actors.find((candidate) => candidate.id === actorId && candidate.campaignId === campaignId);
    if (!target) throw new Error("Prepared D&D action target actor no longer exists");
    return target;
  });
  const combat = workingStore.state.combats.find((candidate) => candidate.campaignId === campaignId && candidate.active);
  const resolutionOptions = {
    ...actionOptions,
    consumeResources: Boolean(actionBody.consumeResources),
    applyEffect: Boolean(actionBody.applyEffect),
    commit: true,
    effectChoice: actionBody.effectChoice,
    saveOutcomes: actionBody.saveOutcomes,
    reactionUse: actionBody.reactionUse,
    sneakAttackEligible: actionBody.sneakAttackEligible,
    rechargeCheck: actionBody.rechargeCheck,
    weaponMastery: masteryInput.value,
  };
  let resolution = resolveDnd5eSrdAction({
    actor,
    items,
    roll: resolvedRollDefinition,
    targets: targets.map((target) => ({ actor: target, items: actorItems(workingStore, target), saveOutcome: actionBody.saveOutcomes?.[target.id] })),
    combat,
    options: resolutionOptions,
    now: prepared.preparedAt,
  });
  if (resolution.blocked) throw new Error(resolution.blocked.reason);
  const pending = dnd5eSrdCommitInputMessage(resolution, effectRequested);
  if (pending) throw new Error(pending);
  const reviewedRolls = prepared.rolledResults.map(({ resolutionRoll }) => ({ formula: resolutionRoll.formula, targetActorId: resolutionRoll.targetActorId }));
  const currentRolls = resolution.rolls.map((roll) => ({ formula: roll.formula, targetActorId: roll.targetActorId }));
  if (hashStableJson(reviewedRolls) !== hashStableJson(currentRolls)) throw new Error("D&D action rolls changed after review; review the action again");
  const defaultRollTotal = prepared.rolledResults[0]?.rolled.total;
  const rollTotalByTarget = new Map<string, number>();
  const naturalD20ByTarget = new Map<string, number>();
  for (const result of prepared.rolledResults) {
    if (!result.resolutionRoll.targetActorId) continue;
    rollTotalByTarget.set(result.resolutionRoll.targetActorId, result.rolled.total);
    const naturalD20 = dnd5eSrdNaturalD20FromRollTerms(result.rolled.terms);
    if (naturalD20 !== undefined) naturalD20ByTarget.set(result.resolutionRoll.targetActorId, naturalD20);
  }
  const selfRoll = prepared.rolledResults.find(({ resolutionRoll }) => !resolutionRoll.targetActorId);
  const selfNaturalD20 = selfRoll ? dnd5eSrdNaturalD20FromRollTerms(selfRoll.rolled.terms) : undefined;
  const selfRollResult = selfRoll ? { total: selfRoll.rolled.total, ...(selfNaturalD20 !== undefined ? { naturalD20: selfNaturalD20 } : {}) } : undefined;
  resolution = resolveDnd5eSrdAction({
    actor,
    items,
    roll: resolvedRollDefinition,
    targets: targets.map((target) => ({ actor: target, items: actorItems(workingStore, target), saveOutcome: actionBody.saveOutcomes?.[target.id], rollTotal: rollTotalByTarget.get(target.id) ?? defaultRollTotal, naturalD20: naturalD20ByTarget.get(target.id) })),
    combat,
    options: selfRollResult ? { ...resolutionOptions, selfRollResult } : resolutionOptions,
    now: prepared.preparedAt,
  });
  if (resolution.blocked) throw new Error(resolution.blocked.reason);
  const finalPending = dnd5eSrdCommitInputMessage(resolution, effectRequested);
  if (finalPending) throw new Error(finalPending);
  resolution = dnd5eSrdResolutionWithConcentrationCleanups(workingStore, campaignId, resolution);
  const resolutionHash = hashStableJson({ actorUpdates: resolution.actorUpdates, itemUpdates: resolution.itemUpdates.map((item) => ({ id: item.id, data: item.data })), effects: resolution.effects, conditions: resolution.conditions, resourceConsumption: resolution.resourceConsumption, usage: resolution.usage, weaponMastery: resolution.weaponMastery, concentrationCleanups: resolution.concentrationCleanups, auditEvents: resolution.auditEvents });
  if (resolutionHash !== prepared.resolutionHash) throw new Error("D&D action consequences changed after review; review the action again");

  const updatedActorIds: string[] = [];
  for (const update of resolution.actorUpdates) {
    const storedActor = workingStore.state.actors.find((candidate) => candidate.id === update.actorId && candidate.campaignId === campaignId);
    if (!storedActor) throw new Error("Prepared D&D action update actor no longer exists");
    storedActor.data = structuredClone(update.after);
    storedActor.updatedAt = nextRevisionTimestamp(storedActor.updatedAt);
    updatedActorIds.push(storedActor.id);
  }
  const itemRevision = nowIso();
  for (const update of resolution.itemUpdates) {
    const storedItem = workingStore.state.items.find((candidate) => candidate.id === update.id && candidate.campaignId === campaignId);
    if (!storedItem) throw new Error("Prepared D&D action update item no longer exists");
    storedItem.data = structuredClone(update.data);
    storedItem.updatedAt = nextRevisionTimestamp(storedItem.updatedAt || itemRevision);
  }
  let combatUpdated = false;
  if (effectRequested && combat) {
    for (const condition of resolution.conditions) combatUpdated = syncDnd5eSrdResolvedConditionToCombat(combat, condition) || combatUpdated;
  }
  if (combat && resolution.actorUpdates.length > 0) combatUpdated = syncCombatDefeatedFromActorIds(combat, workingStore.state.actors, updatedActorIds) || combatUpdated;
  if (combatUpdated && combat) combat.updatedAt = nextRevisionTimestamp(combat.updatedAt);

  const deathSaveSuffix = resolution.deathSave ? ` — ${dnd5eSrdDeathSaveChatSuffix(resolution.deathSave)}` : "";
  const rolls = prepared.rolledResults.map(({ resolutionRoll, rolled, fairness }) => createTimestamped("roll", {
    campaignId,
    userId,
    actorId: actor.id,
    formula: resolutionRoll.formula,
    label: `${resolutionRoll.targetActorId && prepared.rolledResults.length > 1 ? `${rollDefinition.label} (${targets.find((target) => target.id === resolutionRoll.targetActorId)?.name ?? resolutionRoll.targetActorId})` : rollDefinition.label}${dnd5eSrdRollModeLabelSuffix(resolutionRoll)}${deathSaveSuffix}`,
    visibility: actionBody.visibility ?? "public",
    terms: structuredClone(rolled.terms),
    total: rolled.total,
    fairness: structuredClone(fairness),
  }) satisfies DiceRoll);
  const chatMessages = rolls.map((roll) => createTimestamped("msg", { campaignId, userId, type: "roll" as const, body: `${actor.name} ${roll.label}: ${roll.formula} = ${roll.total}`, visibility: roll.visibility, recipientUserIds: [], rollId: roll.id }) satisfies ChatMessage);
  workingStore.state.rolls.push(...rolls);
  workingStore.state.chat.push(...chatMessages);
  workingStore.state.auditLogs.push(createTimestamped("audit", { campaignId, actorUserId: userId, actorType: "user" as const, action: "system.actor.roll", targetType: "actor", targetId: actor.id, after: { systemId: actor.systemId, actorId: actor.id, rollId: rollDefinition.id, label: rollDefinition.label, consumeResources: Boolean(actionBody.consumeResources), applyEffect: effectRequested, hasResolution: true, preparedPreviewKey: prepared.handoff.action.preparedPreviewKey, controlledCreatureHandoff: true } }));
  return { state: workingStore.state, resolution, sourceActorId: actor.id, updatedActorIds: [...new Set(updatedActorIds)], rolls, chatMessages };
}

function controlledCreatureCreateRequest(value: unknown): DndControlledCreatureCreateRequest | undefined {
  if (!isRecord(value) || !isRecord(value.source) || !isRecord(value.actor) || !isRecord(value.actor.data) || !isRecord(value.duration) || !isRecord(value.initiative) || !isRecord(value.command)) return undefined;
  return value as unknown as DndControlledCreatureCreateRequest;
}

function controlledCreatureConfirmRequest(value: unknown): DndControlledCreatureConfirmRequest | undefined {
  if (!isRecord(value) || typeof value.previewToken !== "string") return undefined;
  const request = controlledCreatureCreateRequest(value.request);
  if (!request || !controlledCreatureRevisionSet(value.expectedUpdatedAt)) return undefined;
  return { request, previewToken: value.previewToken, expectedUpdatedAt: value.expectedUpdatedAt };
}

function preparedControlledCreatureAction(
  store: StateStore,
  headers: Record<string, string | string[] | undefined>,
  userId: string,
  campaignId: string,
  request: DndControlledCreatureCreateRequest,
): { value: PreparedControlledCreatureAction } | { error: string } {
  const origin = request.originatingAction;
  if (!origin) return { error: "Controlled-creature request is not linked to a prepared action" };
  const path = `/api/v1/campaigns/${campaignId}/systems/${DND_5E_SRD_SYSTEM_ID}/actors/${origin.actorId}/roll`;
  const record = store.state.idempotencyRecords.find((candidate) => candidate.key === origin.preparedPreviewKey && candidate.method === "POST" && candidate.userId === userId && candidate.path === path);
  const authorizationHash = idempotencyAuthorizationHash(store, headers, userId);
  if (!record || !authorizationHash || record.authorizationHash !== authorizationHash) return { error: "Prepared D&D action is unavailable or expired; review the action again" };
  let stored: unknown;
  try {
    stored = JSON.parse(record.responseBody);
  } catch {
    return { error: "Prepared D&D action is invalid; review the action again" };
  }
  if (!isRecord(stored) || stored.status !== "ready" || !isControlledCreatureActionHandoff(stored.controlledCreatureHandoff) || !isRecord(stored.preparation)) return { error: "Prepared D&D action does not contain a controlled-creature handoff" };
  const preparation = stored.preparation;
  if (preparation.preparedPreviewKey !== origin.preparedPreviewKey
    || preparation.sourceActorId !== origin.actorId
    || typeof preparation.preparedAt !== "string"
    || !isRecord(preparation.request)
    || !isRecord(preparation.revisions)
    || !isStringRecord(preparation.revisions.actorUpdatedAt)
    || !isStringRecord(preparation.revisions.itemUpdatedAt)
    || (preparation.revisions.combatUpdatedAt !== undefined && typeof preparation.revisions.combatUpdatedAt !== "string")
    || !Array.isArray(preparation.rolledResults)
    || !preparation.rolledResults.every(isFairActionRollResult)
    || typeof preparation.resolutionHash !== "string") return { error: "Prepared D&D action is invalid; review the action again" };
  const handoff = stored.controlledCreatureHandoff;
  if (handoff.action.actorId !== origin.actorId
    || handoff.action.rollId !== origin.rollId
    || handoff.action.label !== origin.label
    || handoff.action.preparedPreviewKey !== origin.preparedPreviewKey
    || handoff.action.resolutionHash !== origin.resolutionHash
    || preparation.resolutionHash !== origin.resolutionHash) return { error: "Controlled-creature handoff does not match its prepared action" };
  const requestErrors = dndControlledCreatureHandoffRequestErrors(handoff, request);
  if (requestErrors.length > 0) return { error: requestErrors.join(" ") };
  return {
    value: {
      handoff,
      request: structuredClone(preparation.request) as SystemActorRollBody,
      preparedAt: preparation.preparedAt,
      actorUpdatedAt: structuredClone(preparation.revisions.actorUpdatedAt),
      itemUpdatedAt: structuredClone(preparation.revisions.itemUpdatedAt),
      ...(typeof preparation.revisions.combatUpdatedAt === "string" ? { combatUpdatedAt: preparation.revisions.combatUpdatedAt } : {}),
      rolledResults: structuredClone(preparation.rolledResults),
      resolutionHash: preparation.resolutionHash,
    },
  };
}

function isControlledCreatureActionHandoff(value: unknown): value is DndControlledCreatureActionHandoff {
  return isRecord(value)
    && value.version === 1
    && (value.status === "supported" || value.status === "manual_required")
    && isRecord(value.action)
    && typeof value.action.actorId === "string"
    && typeof value.action.rollId === "string"
    && typeof value.action.label === "string"
    && isRecord(value.prefill)
    && Array.isArray(value.sourcedFields)
    && value.sourcedFields.every((field) => typeof field === "string")
    && Array.isArray(value.manualChoices);
}

function controlledCreatureRevisionSet(value: unknown): value is DndControlledCreatureRevisionSet {
  if (!isRecord(value)) return false;
  for (const collection of ["actors", "items", "tokens", "combats", "scenes", "encounters"] as const) {
    const revisions = value[collection];
    if (!isRecord(revisions) || Object.values(revisions).some((revision) => typeof revision !== "string" || !Number.isFinite(Date.parse(revision)))) return false;
  }
  return true;
}

function authorizeControlledCreaturePreparation(store: StateStore, userId: string, campaignId: string, request: DndControlledCreatureCreateRequest): true | string {
  const sourceActor = store.state.actors.find((actor) => actor.id === request.source.actorId && actor.campaignId === campaignId);
  const controllerActor = store.state.actors.find((actor) => actor.id === request.controllerActorId && actor.campaignId === campaignId);
  if (!sourceActor || !controllerActor) return "Source and controller actors must belong to this campaign";
  if (!canReadActorPrivateData(store, userId, campaignId, sourceActor) || !canReadActorPrivateData(store, userId, campaignId, controllerActor)) return "Missing permission: actor.readPrivate";
  if (!canUpdateActorForUser(store, userId, sourceActor) || !canUpdateActorForUser(store, userId, controllerActor)) return "Missing permission: actor.update";
  const memberUserIds = new Set(store.state.members.filter((member) => member.campaignId === campaignId).map((member) => member.userId));
  if (!memberUserIds.has(request.controllerUserId) || !memberUserIds.has(request.ownerUserId)) return "Controller and owner must be campaign members";
  if ((request.controllerUserId !== userId || request.ownerUserId !== userId) && !canCampaign(store, userId, campaignId, "campaign.update")) return "Only a campaign editor can assign another controller or owner";
  if (request.kind === "transformation") {
    const target = store.state.actors.find((actor) => actor.id === request.targetActorId && actor.campaignId === campaignId);
    if (!target || !canUpdateActorForUser(store, userId, target)) return "Missing permission to transform the target actor";
  } else {
    if (!canCampaign(store, userId, campaignId, "actor.create")) return "Missing permission: actor.create";
    if (!canCampaign(store, userId, campaignId, "token.create")) return "Missing permission: token.create";
    if (!canCampaign(store, userId, campaignId, "scene.update")) return "Missing permission: scene.update";
  }
  if (request.combatId && !canCampaign(store, userId, campaignId, "combat.manage")) return "Missing permission: combat.manage";
  return true;
}

function requireControlledCreatureLifecycleAccess(store: StateStore, reply: FastifyReply, headers: Record<string, string | string[] | undefined>, userId: string, campaignId: string): true | FastifyReply {
  const activeOrganization = requireCampaignActiveOrganization(store, reply, headers, userId, campaignId);
  if (activeOrganization !== true) return activeOrganization;
  return store.state.members.some((member) => member.campaignId === campaignId && member.userId === userId)
    ? true
    : forbidden(reply, "Current campaign membership is required for controlled-creature lifecycle changes");
}

function controlledCreatureStaleWrite(reply: FastifyReply, mismatch: ControlledCreatureRevisionMismatch): FastifyReply {
  return reply.code(409).send({ error: "conflict", code: "stale_write", message: `${mismatch.collection} record ${mismatch.id} changed after this lifecycle was previewed. Review the latest state and retry.`, resourceType: mismatch.collection, resourceId: mismatch.id, expectedUpdatedAt: mismatch.expectedUpdatedAt, currentUpdatedAt: mismatch.currentUpdatedAt, current: mismatch.current ?? { deleted: true } });
}

function controlledCreatureMutationPayload(store: StateStore, userId: string, result: DndControlledCreatureMutationResult): DndControlledCreatureMutationResult {
  return { ...result, actors: result.actors.map((actor) => actorPayloadForUser(store, userId, actor)) };
}

function mergeControlledCreatureMutationResults(
  primary: DndControlledCreatureMutationResult,
  secondary: DndControlledCreatureMutationResult[],
): DndControlledCreatureMutationResult {
  const unique = <T extends { id: string }>(items: T[]): T[] => [...new Map(items.map((item) => [item.id, item])).values()];
  return {
    ...primary,
    records: unique([...secondary.flatMap((result) => result.records), ...primary.records]),
    actors: unique([...secondary.flatMap((result) => result.actors), ...primary.actors]),
    tokens: unique([...secondary.flatMap((result) => result.tokens), ...primary.tokens]),
    combats: unique([...secondary.flatMap((result) => result.combats), ...primary.combats]),
    removedActorIds: [...new Set([...secondary.flatMap((result) => result.removedActorIds), ...primary.removedActorIds])],
    removedTokenIds: [...new Set([...secondary.flatMap((result) => result.removedTokenIds), ...primary.removedTokenIds])],
  };
}

function broadcastControlledCreatureMutation(broadcast: (event: EngineEvent) => void, userId: string, result: DndControlledCreatureMutationResult): void {
  const campaignId = result.records[0]?.campaignId;
  if (!campaignId) return;
  const createdActorIds = new Set(result.action === "created" ? result.records.filter((record) => record.kind !== "transformation").map((record) => record.linkedActorId) : []);
  for (const actor of result.actors) {
    broadcast(createEvent({ campaignId, type: createdActorIds.has(actor.id) ? "actor.created" : "actor.updated", actorUserId: userId, targetId: actor.id, payload: actor }));
  }
  for (const token of result.tokens) {
    broadcast(createEvent({ campaignId, type: "token.created", actorUserId: userId, targetId: token.id, payload: token }));
  }
  for (const actorId of result.removedActorIds) {
    broadcast(createEvent({ campaignId, type: "actor.deleted", actorUserId: userId, targetId: actorId, payload: { id: actorId } }));
  }
  for (const tokenId of result.removedTokenIds) {
    broadcast(createEvent({ campaignId, type: "token.deleted", actorUserId: userId, targetId: tokenId, payload: { id: tokenId } }));
  }
  for (const combat of result.combats) {
    broadcast(createEvent({ campaignId, type: "combat.turnChanged", actorUserId: userId, targetId: combat.id, payload: combat }));
  }
}

function staleWriteConflict(reply: FastifyReply, input: { resourceType: RevisionResourceType; resourceId: string; expectedUpdatedAt: string; currentUpdatedAt: string; current: unknown }): FastifyReply {
  return reply.code(409).send({ error: "conflict", code: "stale_write", message: `${input.resourceType === "actor" ? "Actor" : input.resourceType === "campaign" ? "Campaign" : input.resourceType === "combat" ? "Combat" : input.resourceType === "item" ? "Item" : input.resourceType === "scene" ? "Scene" : input.resourceType === "token" ? "Token" : input.resourceType === "user" ? "Profile" : "Journal entry"} changed after this action was prepared. Review the latest state and retry.`, resourceType: input.resourceType, resourceId: input.resourceId, expectedUpdatedAt: input.expectedUpdatedAt, currentUpdatedAt: input.currentUpdatedAt, current: input.current });
}

type RevisionResourceType = "actor" | "calculation_override" | "campaign" | "campaign_invite" | "campaign_member" | "campaign_session" | "character_transfer" | "combat" | "content_import" | "item" | "journal" | "organization" | "organization_member" | "plugin_storage" | "scene" | "token" | "user" | "world_record" | "world_relation";

function nextRevisionTimestamp(current: string): string {
  const now = Date.now();
  const currentTime = Date.parse(current);
  return new Date(Number.isFinite(currentTime) && currentTime >= now ? currentTime + 1 : now).toISOString();
}

function advanceCampaignAggregateRevision(store: StateStore, campaignId: string): Campaign | undefined {
  const campaign = store.state.campaigns.find((candidate) => candidate.id === campaignId);
  if (campaign) campaign.updatedAt = nextRevisionTimestamp(campaign.updatedAt);
  return campaign;
}

function recoverInterruptedCampaignWebhookDeliveries(store: StateStore): number {
  const queued = store.state.campaignWebhookDeliveries.filter((delivery) => delivery.status === "queued");
  for (const delivery of queued) failCampaignWebhookDelivery(delivery, { errorCode: "interrupted" });
  for (const webhookId of new Set(queued.map((delivery) => delivery.webhookId))) {
    pruneCampaignWebhookDeliveryLedger(store, webhookId);
  }
  for (const campaignId of new Set(queued.map((delivery) => delivery.campaignId))) {
    pruneCampaignWebhookCampaignLedger(store, campaignId);
  }
  return queued.length;
}

interface CampaignWebhookSendOutcome {
  result: CampaignWebhookTransportResult;
  durationMs: number;
}

function currentQueuedCampaignWebhookDelivery(
  store: StateStore,
  revision: Pick<CampaignWebhookDelivery, "id" | "campaignId" | "webhookId" | "updatedAt">,
): CampaignWebhookDelivery | undefined {
  return store.state.campaignWebhookDeliveries.find((delivery) =>
    delivery.id === revision.id
    && delivery.campaignId === revision.campaignId
    && delivery.webhookId === revision.webhookId
    && delivery.status === "queued"
    && delivery.updatedAt === revision.updatedAt
  );
}

async function sendCampaignWebhook(transport: CampaignWebhookTransport, webhook: CampaignWebhookSubscription, envelope: CampaignWebhookEnvelopeV1): Promise<CampaignWebhookSendOutcome> {
  const startedAt = Date.now();
  const request = campaignWebhookSignedRequest(envelope, webhook.signingSecret);
  let result: CampaignWebhookTransportResult;
  try {
    result = await transport.send({ url: webhook.url, ...request });
  } catch {
    result = { ok: false, errorCode: "network_error" };
  }
  const durationMs = Math.max(0, Date.now() - startedAt);
  return { result, durationMs };
}

function completeCampaignWebhookDelivery(delivery: CampaignWebhookDelivery, outcome: CampaignWebhookSendOutcome): CampaignWebhookDelivery {
  if (!outcome.result.ok) return failCampaignWebhookDelivery(delivery, outcome.result, outcome.durationMs);
  const deliveredAt = nowIso();
  Object.assign(delivery, { status: "delivered" as const, responseStatus: outcome.result.responseStatus, responseBytes: outcome.result.responseBytes, durationMs: outcome.durationMs, deliveredAt, failedAt: undefined, errorCode: undefined, updatedAt: deliveredAt });
  return delivery;
}

function failCampaignWebhookDelivery(delivery: CampaignWebhookDelivery, result: { responseStatus?: number; responseBytes?: number; errorCode?: string }, durationMs = 0): CampaignWebhookDelivery {
  const failedAt = nowIso();
  Object.assign(delivery, { status: "failed" as const, responseStatus: result.responseStatus, responseBytes: result.responseBytes, durationMs, failedAt, deliveredAt: undefined, errorCode: result.errorCode ?? "network_error", updatedAt: failedAt });
  return delivery;
}

function pendingResolution(reply: FastifyReply, message: string, resolution: RulesActionResolutionResult | undefined, actor: Actor, sheet: unknown): FastifyReply {
  return reply.code(409).send({ error: "pending_resolution", message, resolution, actor, sheet });
}
